INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Inspiring Leader', 'General Feat', 'Level 4+, Wisdom or Charisma 13+', 'Ability Score Increase: Increase your Wisdom or Charisma score by 1, to a maximum of 20.

Bolstering Performance: When you finish a Short or Long Rest, you can give an inspiring performance: a speech, song, or dance. When you do so, choose up to six allies (which can include yourself) within 30 feet of yourself who witness the performance. The chosen creatures each gain Temporary Hit Points equal to your character level plus the modifier of the ability you increased with this feat.', '[{"name":"Ability Score Increase","description":"Increase your Wisdom or Charisma score by 1, to a maximum of 20."},{"name":"Bolstering Performance","description":"When you finish a Short or Long Rest, you can give an inspiring performance: a speech, song, or dance. When you do so, choose up to six allies (which can include yourself) within 30 feet of yourself who witness the performance. The chosen creatures each gain Temporary Hit Points equal to your character level plus the modifier of the ability you increased with this feat."}]'::jsonb, FALSE, ARRAY['common', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
