Guarded Mind: If you fail an Intelligence, a Wisdom, or a Charisma saving throw, you can cause yourself to succeed instead. Once you use this benefit, you can''t use it again until you finish a Short or Long Rest.', '[{"name":"Ability Score Increase","description":"Increase your Strength or Dexterity score by 1, to a maximum of 20."},{"name":"Concentration Breaker","description":"When you damage a creature that is concentrating, it has Disadvantage on the saving throw it makes to maintain Concentration."},{"name":"Guarded Mind","description":"If you fail an Intelligence, a Wisdom, or a Charisma saving throw, you can cause yourself to succeed instead. Once you use this benefit, you can''t use it again until you finish a Short or Long Rest."}]'::jsonb, FALSE, ARRAY['common', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
