INSERT INTO official.equipment (name, category, sub_category, cost, weight, damage, properties, mastery, description, legacy, tags) VALUES ('Viol', 'Tool', 'Tool', 'Charisma', '1 lb.', NULL, ARRAY[]::TEXT[], NULL, 'A tool set/kit used for crafting or checks.', FALSE, ARRAY['tool']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, sub_category = EXCLUDED.sub_category, cost = EXCLUDED.cost, weight = EXCLUDED.weight, damage = EXCLUDED.damage, properties = EXCLUDED.properties, mastery = EXCLUDED.mastery, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Adventurer''s Ring', 'Ring', 'Common', 'No', 'Varies', '"Lamps are a liability on adventures. Delicate and prone to oil spillage, lamps fill a hand that should otherwise be wielding a weapon or casting a spell. Once you try one of our elegant and practical rings, you’ll never go back to cumbersome flint and fire."

While the cover on this ring is open, the ring produces a flame that creates no heat and consumes no fuel. It sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. As a Bonus Action, you can close the cover, smothering the flame, or open it again.', FALSE, ARRAY['common', 'frhof', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bead of Nourishment', 'Wondrous Item', 'Common', 'No', 'Varies', 'This flavorless, gelatinous bead dissolves on your tongue and provides as much nourishment as 1 day of Rations.', FALSE, ARRAY['common', 'consumable', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bead of Refreshment', 'Wondrous Item', 'Common', 'No', 'Varies', 'This flavorless, gelatinous bead dissolves in liquid, transforming up to a pint of the liquid into fresh, cold drinking water. The bead has no effect on magical liquids or harmful substances such as poison.', FALSE, ARRAY['common', 'consumable', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Armor of Gleaming', 'Armor (Any Light', 'Common', 'No', 'Varies', 'This armor never gets dirty.', FALSE, ARRAY['armor', 'common']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Boots of False Tracks', 'Wondrous Item', 'Common', 'No', 'Varies', 'While wearing these boots, you can have them leave tracks like those of any kind of Humanoid of your size.', FALSE, ARRAY['attuned', 'common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Candle of the Deep', 'Wondrous Item', 'Common', 'No', 'Varies', 'The flame of this candle isn’t extinguished when immersed in water. It gives off light and heat like a normal candle.', FALSE, ARRAY['common', 'consumable', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Charlatan''s Die', 'Wondrous Item', 'Common', 'No', 'Varies', 'Whenever you roll this six-sided die, you can control which number it rolls.', FALSE, ARRAY['attuned', 'common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of Billowing', 'Wondrous Item', 'Common', 'No', 'Varies', 'While wearing this cloak, you can take a Bonus Action to make it billow dramatically for 1 minute.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cast-Off Armor', 'Armor (Any Light', 'Common', 'No', 'Varies', 'You can doff this armor as a Magic action.', FALSE, ARRAY['armor', 'common']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of Many Fashions', 'Wondrous Item', 'Common', 'No', 'Varies', 'While wearing this cloak, you can take a Bonus Action to change the style, color, and apparent quality of the garment. The cloak’s weight doesn’t change. Regardless of its appearance, the cloak can’t be anything but a cloak. Although it can duplicate the appearance of other magic cloaks, it doesn’t gain their magical properties.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Clockwork Amulet', 'Wondrous Item', 'Common', 'No', 'Varies', 'This copper amulet contains tiny interlocking gears and is powered by magic from Mechanus, a plane of clockwork predictability. Faint ticking and whirring noises emanate from within.

When you make an attack roll while wearing the amulet, you can forgo rolling the d20 to get a 10 on the die. Once used, this property can’t be used again until the next dawn.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dark Shard Amulet', 'Wondrous Item', 'Common', 'No', 'Varies', 'This amulet is fashioned from a shard of resilient material originating from an otherworldly realm. While you are wearing it, you gain the following benefits.

Spellcasting Focus. You can use the amulet as a Spellcasting Focus for your Warlock spells.

Unknown Spell. As a Magic action, you can try to cast a cantrip that you don’t know. The cantrip must be on the Warlock spell list and have a casting time of an action, and you make a DC 10 Intelligence (Arcana) check. On a successful check, you cast the spell. On a failed check, the spell fails, and the action used to cast it is wasted. In either case, you can’t use this property again until you finish a Long Rest.', FALSE, ARRAY['attuned', 'common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Clothes of Mending', 'Wondrous Item', 'Common', 'No', 'Varies', 'This elegant outfit magically mends itself to counteract daily wear and tear. Pieces of the outfit that are destroyed can’t be repaired in this way.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dread Helm', 'Wondrous Item', 'Common', 'No', 'Varies', 'While you’re wearing this fearsome steel helm, your eyes glow red and the rest of your face is hidden in shadow.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ear Horn of Hearing', 'Wondrous Item', 'Common', 'No', 'Varies', 'While held up to your ear, this horn suppresses the effects of the Deafened condition on you.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Enduring Spellbook', 'Wondrous Item', 'Common', 'No', 'Varies', 'This spellbook, along with anything written on its pages, can’t be damaged by fire or water. In addition, the spellbook doesn’t deteriorate with age.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ersatz Eye', 'Wondrous Item', 'Common', 'No', 'Varies', 'This magical eye replaces a real one that was lost or removed. While the Ersatz Eye is embedded in your eye socket, you can see through the tiny orb as though it were your natural eye. You can insert or remove the Ersatz Eye as a Magic action, and it can’t be removed against your will while you are alive.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Hat of Wizardry', 'Wondrous Item', 'Common', 'No', 'Varies', 'This cone-shaped hat is adorned with moons and stars. While you are wearing it, you gain the following benefits.

Spellcasting Focus. You can use the hat as a Spellcasting Focus for your Wizard spells.

Unknown Spell. As a Magic action, you can try to cast a cantrip that you don’t know. The cantrip must be on the Wizard spell list and have a casting time of an action, and you make a DC 10 Intelligence (Arcana) check. On a successful check, you cast the spell. On a failed check, the spell fails, and the action used to cast the spell is wasted. In either case, you can’t use this property again until you finish a Long Rest.', FALSE, ARRAY['attuned', 'common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Hat of Vermin', 'Wondrous Item', 'Common', 'No', 'Varies', 'This hat has 3 charges. While holding the hat, you can take a Magic action to expend 1 charge and summon your choice of a Bat, a Frog, or a Rat. The summoned creature magically appears in the hat and tries to get away from you as quickly as possible. The creature is Indifferent toward you and other creatures, and it isn’t under your control. It behaves as an ordinary creature of its kind and disappears after 1 hour or when it drops to 0 Hit Points. The hat regains all expended charges daily at dawn.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Eternal Chalk', 'Wondrous Item', 'Common', 'No', 'Varies', 'A stick of Eternal Chalk never breaks or wears down with normal use. When using this chalk you can choose the color of its marks and whether they emit a faint glow. Any marks you make with this chalk can''t be erased for 7 days by anyone except you.', FALSE, ARRAY['common', 'drops', 'drops0626', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Heward''s Handy Spice Pouch', 'Wondrous Item', 'Common', 'No', 'Varies', 'This belt pouch appears empty and has 10 charges. While holding the pouch, you can take a Magic action to expend 1 charge, name any nonmagical food seasoning (such as salt, pepper, saffron, or cilantro), and remove a pinch of the desired seasoning from the pouch. A pinch is enough to season a single meal. The pouch regains 1d6 + 4 expended charges daily at dawn.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Horn of Silent Alarm', 'Wondrous Item', 'Common', 'No', 'Varies', 'This horn has 4 charges and regains 1d4 expended charges daily at dawn. As a Magic action, you can blow the horn while expending 1 charge. One creature of your choice hears the horn’s blare, provided that creature is within 600 feet of the horn. No other creature hears the horn.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Instrument of Illusions', 'Wondrous Item', 'Common', 'No', 'Varies', 'While you are playing this musical instrument, you can take a Magic action to create harmless, illusory visual effects within a 5-foot Emanation originating from the instrument. If you are a Bard, the size of the Emanation increases to 15 feet. Sample visual effects include luminous musical notes, a spectral dancer, butterflies, and gently falling snow. The magical effects have neither substance nor sound, and they are obviously illusory. The effects end when you stop playing.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Instrument of Scribing', 'Wondrous Item', 'Common', 'No', 'Varies', 'This musical instrument has 3 charges and regains all expended charges daily at dawn. While you are playing it, you can take a Magic action to expend 1 charge and write a magical message on a nonmagical object or surface that you can see within 30 feet of yourself. The message can be up to six words long and is written in a language you know. If you are a Bard, you can scribe an additional seven words and make the message glow faintly, allowing it to be seen in nonmagical Darkness. Casting the Dispel Magic spell on the message erases it. Otherwise, the message fades away after 24 hours.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Lock of Trickery', 'Wondrous Item', 'Common', 'No', 'Varies', 'This lock appears to be an ordinary Lock (of the type described in chapter 6 of the Player’s Handbook) and comes with a single key. The tumblers in this lock magically adjust to thwart burglars. Dexterity checks made to pick the lock have Disadvantage.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Manifold Tool', 'Wondrous Item', 'Common', 'No', 'Varies', 'This tool takes the form of a wrench, a screwdriver, or another basic tool. As a Magic action, you can touch the item and transform it into a type of Artisan’s Tools of your choice. Whatever form the tool takes, you have proficiency with it when you use it.', FALSE, ARRAY['attuned', 'common', 'efota', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mask of Changed Appearance', 'Wondrous Item', 'Common', 'No', 'Varies', 'This jeweled mask has 3 charges. As a Magic action, you can expend 1 charge and change your face’s appearance. You can’t make yourself look like a different person, but you can smooth or deepen your wrinkles, whiten your teeth, hide or accentuate bags under your eyes, or perform other minor cosmetic changes. While your appearance is changed, the mask has the Invisible condition. Your changed appearance lasts 1 hour.

Regaining Charges. The mask regains 1d3 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the mask explodes in a harmless cloud of sweet-swelling powder and is destroyed.', FALSE, ARRAY['common', 'nf', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Moon-Touched Sword', 'Weapon (Glaive', 'Common', 'No', 'Varies', 'In Darkness, the unsheathed blade of this weapon sheds moonlight, creating Bright Light in a 15-foot radius and Dim Light for an additional 15 feet.', FALSE, ARRAY['common', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mystery Key', 'Wondrous Item', 'Common', 'No', 'Varies', 'A question mark is worked into the head of this key. The key has a 5 percent chance of unlocking any lock into which it’s inserted. Once it unlocks something, the key disappears.', FALSE, ARRAY['common', 'consumable', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mechanical Wonder', 'Wondrous Item', 'Common', 'No', 'Varies', 'A Mechanical Wonder is a semi-autonomous object imbued with magical power. Mechanical Wonders vary greatly in size and form depending on their function.

A Mechanical Wonder is a dormant object until activated. To activate a Mechanical Wonder, you must wind the wonder with a handheld key unique to that wonder. It takes 1 minute to wind a Mechanical Wonder. While you wind it, you must take the Utilize action each turn.

Once wound, a Mechanical Wonder remains activated for the duration specified in the wonder''s description below.

Domestic Wonder (Uncommon). This bipedal wonder is designed to assist with household duties. It vaguely resembles whatever species its creator used as inspiration. An activated domestic wonder uses the Domestic Wonder stat block. The wonder is an ally to you and your allies. In combat, the wonder shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don''t issue any, it takes the Dodge action and uses its movement to avoid danger. The domestic wonder is destroyed if it drops to 0 Hit Points.

Flying Wonder (Common). An activated flying wonder uses the Flying Wonder stat block. The wonder is an ally to you and your allies. In combat, the wonder shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don''t issue any, it takes the Dodge action and uses its movement to avoid danger. The flying wonder is destroyed if it drops to 0 Hit Points.

Gyrocopter Wonder (Rare). This wagon-sized vehicle is made of brassy metal and has a spiral-shaped propeller atop it. Its midsection is open on two sides. Once wound, the gyrocopter wonder remains active for 8 hours. While active, the gyrocopter can be used as a vehicle; it requires one pilot.

The gyrocopter wonder is a Huge object that weighs 500 pounds and has the following statistics: AC 14, HP 50, Speed 5 ft., and Fly Speed 20 ft. The gyrocopter can bear up to 2,000 pounds of cargo; if it bears any more than this, it deactivates.

Eight spectral cords are mounted to the inside of the cargo bay. A creature riding in the gyrocopter wonder can take a Utilize action to attach itself to or detach itself from one of these cords. A creature attached to a cord can leap from the gyrocopter wonder and glide, moving up to 5 feet horizontally for every 1 foot it descends in the air. If a creature attached to a cord is ever more than 500 feet away from the gyrocopter, the cord immediately disappears and returns to the wonder.

Mobility Wonder (Common). While inactive, the mobility wonder resembles a metal turtle shell with straps. It is designed to be worn on your back or flank, depending on your anatomy. Once wound, the mobility wonder transforms into a personal transport device and remains active for 24 hours. While active, the mobility wonder increases your Speed to 30 feet. Other creatures can’t remove your mobility wonder from you unless you allow it.', FALSE, ARRAY['common', 'frhof', 'rare', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Orb of Direction', 'Wondrous Item', 'Common', 'No', 'Varies', 'This orb can be used as an Arcane Focus.

While holding this orb, you can take a Magic action to determine which way is magnetic north. Nothing happens if the orb is used in a location that has no magnetic north.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Pipe of Smoke Monsters', 'Wondrous Item', 'Common', 'No', 'Varies', 'While smoking this pipe, you can take a Magic action to exhale a puff of smoke that takes the form of a creature, such as a dragon, a flumph, or a slaad. The form must be small enough to fit in a 1-foot cube and loses its shape after a few seconds, becoming an ordinary puff of smoke.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Orb of Time', 'Wondrous Item', 'Common', 'No', 'Varies', 'This orb can be used as an Arcane Focus.

While holding the orb, you can take a Magic action to determine whether it is morning, afternoon, evening, or nighttime. This property functions only on the Material Plane.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Perfume of Bewitching', 'Wondrous Item', 'Common', 'No', 'Varies', 'This tiny vial contains magic perfume, enough for one use. You can take a Magic action to apply the perfume to yourself, and its effect lasts 1 hour. For the duration, you have Advantage on all Charisma (Deception and Persuasion) checks made to influence a creature within 5 feet of yourself.', FALSE, ARRAY['common', 'consumable', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Pole of Angling', 'Wondrous Item', 'Common', 'No', 'Varies', 'This item functions as a Pole. While holding it, you can take a Magic action to cause it to transform into a fishing pole with a hook, a line, and a reel, or have the fishing pole revert to a Pole.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Pole of Collapsing', 'Wondrous Item', 'Common', 'No', 'Varies', 'This item functions as a Pole. While holding it, you can take a Magic action to collapse it into a 1-foot-long rod for ease of storage (the pole’s weight doesn’t change) or cause the 1-foot-long rod to revert to a Pole. The rod elongates only as far as the surrounding space allows.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Pot of Awakening', 'Wondrous Item', 'Common', 'No', 'Varies', 'If you plant an ordinary shrub in this 10-pound clay pot and let it grow for 30 days, the shrub magically transforms into an Awakened Shrub at the end of that time. When the shrub awakens, its roots break the pot, destroying it.

The awakened shrub is Friendly toward you and obeys your commands. Absent commands from you, it does nothing.', FALSE, ARRAY['common', 'consumable', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Climbing', 'Potion', 'Common', 'No', 'Varies', 'When you drink this potion, you gain a Climb Speed equal to your Speed for 1 hour. During this time, you have Advantage on Strength (Athletics) checks to climb.

This potion is separated into brown, silver, and gray layers resembling bands of stone. Shaking the bottle fails to mix the colors.', FALSE, ARRAY['common', 'consumable', 'potion']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Comprehension', 'Potion', 'Common', 'No', 'Varies', 'When you drink this potion, you gain the effect of the Comprehend Languages spell for 1 hour.

This potion’s liquid is a clear concoction with bits of salt and soot swirling in it.', FALSE, ARRAY['common', 'consumable', 'potion']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Healing', 'Potion', 'Common', 'No', 'Varies', 'This potion is a magic item. As a Bonus Action, you can drink it or administer it to another creature within 5 feet of yourself. The creature that drinks the magical red fluid in this vial regains 2d4 + 2 Hit Points.

Potion, Rarity Varies

You regain Hit Points when you drink this potion. The number of Hit Points depends on the potion’s rarity, as shown in the table below.

Whatever its potency, the potion’s red liquid glimmers when agitated.', FALSE, ARRAY['common', 'consumable', 'potion', 'rare', 'uncommon', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Prosthetic Limb', 'Wondrous Item', 'Common', 'No', 'Varies', 'This magic item replaces a lost limb - a hand, an arm, a foot, a leg, or a similar body part. While the prosthetic is attached, it functions identically to the part it replaces. You can detach or reattach it as a Magic action, and it can’t be removed against your will while you are alive.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rival Coin', 'Wondrous Item', 'Common', 'No', 'Varies', 'This gold coin has a creature embossed on each side. The two depicted creatures must be famous rivals or enemies of each other. For example, a Rival Coin might show Iggwilv on one side and Mordenkainen on the other, or Venger on one side and Tiamat on the other. One of these figures is on the “heads” side of the coin, the other on the “tails” side.

The coin has 1 charge and regains its expended charge daily at dawn. You can take a Magic action to toss the coin, expending its charge. Roll any die to determine whether the coin comes up heads (on an even number) or tails (on an odd number). The roll also determines the effect:

Heads. Target one creature you can see within 60 feet of yourself. The target makes a DC 13 Wisdom saving throw. On a failed save, the target takes 2d4 Psychic damage and has Disadvantage on the next attack roll it makes before the end of its next turn. On a successful save, the target takes half as much damage only.

Tails. You take 1d4 Psychic damage.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rope of Mending', 'Wondrous Item', 'Common', 'No', 'Varies', 'This 50-foot coil of rope can repair itself when cut into any number of smaller pieces. As a Magic action, you can cause all pieces of the rope that are in contact with each other and not otherwise in use to knit back together. A Rope of Mending is forever shortened if a section of it is lost or destroyed.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ruby of the War Mage', 'Wondrous Item', 'Common', 'No', 'Varies', 'Etched with eldritch runes, this 1-inch-diameter ruby allows you to use a Simple or Martial weapon as a Spellcasting Focus for your spells. For this property to work, you must attach the ruby to the weapon by pressing the ruby against it for at least 10 minutes. Thereafter, the ruby can’t be removed unless you detach it as a Magic action, the weapon is destroyed, or your Attunement to the ruby ends.', FALSE, ARRAY['attuned', 'common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Shield of Expression', 'Armor (Shield)', 'Common', 'No', 'Varies', 'The front of this Shield is shaped in the likeness of a face. While bearing the Shield, you can take a Bonus Action to alter the face’s expression.', FALSE, ARRAY['armor', 'common']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Silvered Weapon', 'Weapon (Any Simple or Martial)', 'Common', 'No', 'Varies', 'An alchemical process has bonded silver to this magic weapon. When you score a Critical Hit with it against a creature that is shape-shifted, the weapon deals one additional die of damage.', FALSE, ARRAY['common', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Spell Scroll', 'A Spell Scroll bears the words of a single spell', 'Common', 'No', 'Varies', 'If the spell is on your spell list but of a higher level than you can normally cast, you make an ability check using your spellcasting ability to determine whether you cast the spell. The DC equals 10 plus the spell’s level. On a failed check, the spell disappears from the scroll with no other effect.

The level of the spell on the scroll determines the spell’s saving throw DC and attack bonus, as well as the scroll’s rarity, as shown in the following table.

Copying a Scroll into a Spellbook. A Wizard spell on a Spell Scroll can be copied into a spellbook. When a spell is copied in this way, the copier must succeed on an Intelligence (Arcana) check with a DC equal to 10 plus the spell’s level. On a successful check, the spell is copied. Whether the check succeeds or fails, the Spell Scroll is destroyed.', FALSE, ARRAY['common', 'consumable', 'legendary', 'rare', 'scroll', 'uncommon', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Smoldering Armor', 'Armor (Any Heavy', 'Common', 'No', 'Varies', 'Wisps of harmless, odorless smoke rise from this armor while it is worn.', FALSE, ARRAY['armor', 'common']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Adornment', 'Staff', 'Common', 'No', 'Varies', 'If you place a Tiny object weighing no more than 1 pound (such as a shard of crystal, an egg, or a stone) above the tip of this staff while holding it, the object floats an inch from the staff’s tip and remains there until it is removed or until the staff is no longer in your possession. The staff can have up to three such objects floating over its tip at any given time. While holding the staff, you can make one or more of the objects slowly spin or turn in place.', FALSE, ARRAY['common', 'staff']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Flowers', 'Staff', 'Common', 'No', 'Varies', 'This wooden staff has 10 charges. While holding it, you can take a Magic action to expend 1 charge from the staff and cause a flower to sprout from a patch of earth or soil within 5 feet of yourself, or from the staff itself. Unless you choose a specific kind of flower, the staff creates a mild-scented daisy. The flower is harmless and nonmagical, and it grows or withers as a normal flower would.

Regaining Charges. The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff turns into flower petals and is lost forever.', FALSE, ARRAY['common', 'staff']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sylvan Talon', 'Weapon (Dagger', 'Common', 'No', 'Varies', 'While this weapon is on your person, you understand the nonwritten communication of all Fey, and they understand yours.

Secret Message. As a Magic action, you can use the weapon to cast Message. Once this property is used, it can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'common', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Talking Doll', 'Wondrous Item', 'Common', 'No', 'Varies', 'While this doll is within 5 feet of you, you can spend a Short Rest telling it to say up to six phrases, none of which can be more than six words long, and set a condition under which the doll speaks each phrase. You can also replace old phrases with new ones. Whatever the condition, it must occur within 5 feet of the doll to make it speak. For example, whenever someone picks up the doll, it might say, “I want a piece of candy.” The doll’s phrases are lost when your Attunement to the doll ends.', FALSE, ARRAY['attuned', 'common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Tankard of Sobriety', 'Wondrous Item', 'Common', 'No', 'Varies', 'This tankard has a stern face sculpted into one side. You can drink ale, wine, or any other nonmagical alcoholic beverage poured into it without becoming inebriated. The tankard has no effect on magical liquids or harmful substances such as poison.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Veteran''s Cane', 'Wondrous Item', 'Common', 'No', 'Varies', 'As a Bonus Action, you can transform this walking cane into an ordinary Longsword or change the Longsword back into a walking cane. In either case, you must be holding the item.', FALSE, ARRAY['common', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Conducting', 'Wand', 'Common', 'No', 'Varies', 'This wand has 3 charges. While holding it, you can take a Magic action to expend 1 charge and create orchestral music by waving it around. The music can be heard out to 120 feet and ends when you stop waving the wand.

Regaining Charges. The wand regains all expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, a sad tuba sound plays as the wand crumbles into dust and is destroyed.', FALSE, ARRAY['common', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Pyrotechnics', 'Wand', 'Common', 'No', 'Varies', 'This wand has 7 charges. While holding it, you can take a Magic action to expend 1 charge and create a harmless burst of multicolored light at a point you can see up to 120 feet away. The burst of light is accompanied by a crackling noise that can be heard up to 300 feet away. The light is as bright as a torch flame but lasts only a second.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand erupts in a harmless pyrotechnic display and is destroyed.', FALSE, ARRAY['common', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Adamantine Armor', 'Armor (Any Medium or Heavy', 'Uncommon', 'No', 'Varies', 'This suit of armor is reinforced with adamantine, one of the hardest substances in existence. While you’re wearing it, any Critical Hit against you becomes a normal hit.', FALSE, ARRAY['armor', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Alchemy Jug', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This ceramic jug appears to be able to hold a gallon of liquid and weighs 12 pounds whether full or empty. The jug sloshes when it is shaken, even if the jug is empty.

You can take a Magic action and name one liquid from the Alchemy Jug Liquids table to cause the jug to produce the chosen liquid. Afterward, you can uncork the jug as a Utilize action and pour that liquid out, up to 2 gallons per minute. The maximum amount of liquid the jug can produce depends on the liquid you named.

Once the jug starts producing a liquid, it can’t produce a different one, or more of one that has reached its maximum, until the next dawn.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Adamantine Weapon', 'Weapon (Any Ammunition or Melee Weapon)', 'Uncommon', 'No', 'Varies', 'This weapon or piece of ammunition is made of adamantine, one of the hardest substances in existence. Whenever this weapon or piece of ammunition hits an object, the hit is a Critical Hit.', FALSE, ARRAY['uncommon', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ammunition, +1, +2, or +3', 'Weapon (Any Ammunition)', 'Uncommon', 'No', 'Varies', 'You have a bonus to attack rolls and damage rolls made with this piece of magic ammunition. The bonus is determined by the rarity of the ammunition. Once it hits a target, the ammunition is no longer magical.

This ammunition is typically found or sold in quantities of ten or twenty pieces. Ten pieces of this ammunition are equivalent in value to a potion of the same rarity.', FALSE, ARRAY['consumable', 'rare', 'uncommon', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Amulet of Proof against Detection and Location', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this amulet, you can’t be targeted by Divination spells or perceived through magical scrying sensors unless you allow it.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Arcane Battery', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This smooth, oval stone is etched with faintly glowing, magical symbols. While holding the battery, you can take a Magic action to touch the battery to one magic item. If that magic item normally regains expended charges daily, it immediately regains 1d4 + 1 expended charges, and the battery loses its magic.', FALSE, ARRAY['consumable', 'nf', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Baba Yaga''s Dancing Broom', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'The archfey Baba Yaga crafted many of these magic brooms. No two appear exactly alike. While holding the broom, you can take a Magic action to transform it into an Animated Broom under your control. The broom then moves into an unoccupied space as close to you as possible. The broom acts immediately after you on your Initiative count and remains animate until you take a Bonus Action and use a command word to render it inanimate.

On your turn, you can mentally command the animated broom if it is within 30 feet of you and you don’t have the Incapacitated condition (no action required). You decide what action the broom takes and where it moves during its next turn, or you can issue it a general command, such as to attack your enemies or guard a location.

If the broom is reduced to 0 Hit Points, it shatters and is destroyed. If the broom reverts to its inanimate form before losing all its Hit Points, it regains all of them.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bag of Holding', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This bag has an interior space considerably larger than its outside dimensions—roughly 2 feet square and 4 feet deep on the inside. The bag can hold up to 500 pounds, not exceeding a volume of 64 cubic feet. The bag weighs 5 pounds, regardless of its contents. Retrieving an item from the bag requires a Utilize action.

If the bag is overloaded, pierced, or torn, it is destroyed, and its contents are scattered in the Astral Plane. If the bag is turned inside out, its contents spill forth unharmed, but the bag must be put right before it can be used again. The bag holds enough air for 10 minutes of breathing, divided by the number of breathing creatures inside.

Placing a Bag of Holding inside an extradimensional space created by a Heward’s Handy Haversack, Portable Hole, or similar item instantly destroys both items and opens a gate to the Astral Plane. The gate originates where the one item was placed inside the other. Any creature within a 10-foot-radius Sphere centered on the gate is sucked through it to a random location on the Astral Plane. The gate then closes. The gate is one-way and can’t be reopened.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bag of Tricks', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This bag made from gray, rust, or tan cloth appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object.

You can take a Magic action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling on the table that corresponds to the bag’s color. See the Monster Manual for the creature’s stat block. The creature vanishes at the next dawn or when it is reduced to 0 Hit Points.

The creature is Friendly to you and your allies, and it acts immediately after you on your Initiative count. You can take a Bonus Action to command how the creature moves and what action it takes on its next turn, such as attacking an enemy. In the absence of such orders, the creature acts in a fashion appropriate to its nature.

Once three fuzzy objects have been pulled from the bag, the bag can’t be used again until the next dawn.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Boots of Elvenkind', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While you wear these boots, your steps make no sound, regardless of the surface you are moving across. You also have Advantage on Dexterity (Stealth) checks.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Boots of Striding and Springing', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While you wear these boots, your Speed becomes 30 feet unless your Speed is higher, and your Speed isn’t reduced by you carrying weight in excess of your carrying capacity or wearing Heavy Armor.

Once on each of your turns, you can jump up to 30 feet by spending only 10 feet of movement.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Boots of the Winding Path', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing these boots, you can take a Bonus Action to teleport up to 15 feet to an unoccupied space you can see. You must have occupied that space at some point during the current turn.', FALSE, ARRAY['attuned', 'efota', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Boots of the Winterlands', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'These furred boots are snug and feel warm. While wearing them, you gain the following benefits.

Cold Resistance. You have Resistance to Cold damage and can tolerate temperatures of 0 degrees Fahrenheit or lower without any additional protection.

Winter Strider. You ignore Difficult Terrain created by ice or snow.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bracers of Archery', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing these bracers, you have proficiency with the Longbow and Shortbow, and you gain a +2 bonus to damage rolls made with such weapons.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Brooch of Shielding', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this brooch, you have Resistance to Force damage, and you have Immunity to damage from the Magic Missile spell.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Circlet of Blasting', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this circlet, you can cast Scorching Ray with it (+5 to hit). The circlet can’t cast this spell again until the next dawn.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Broom of Flying', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This wooden broom functions like a mundane broom until you stand astride it and take a Magic action to make it hover beneath you, at which time it can be ridden in the air. It has a Fly Speed of 50 feet. It can carry up to 400 pounds, but its Fly Speed becomes 30 feet while carrying over 200 pounds. The broom stops hovering when you land or when you’re no longer riding it.

As a Magic action, you can send the broom to travel alone to a destination within 1 mile of you if you name the location and are familiar with it. The broom comes back to you when you take a Magic action and use a command word if the broom is still within 1 mile of you.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cap of Water Breathing', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this cap underwater, you can take a Magic action to create a bubble of air around your head. This bubble allows you to breathe normally underwater. This bubble stays with you until the cap is removed or you are no longer underwater.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cap of Vanishing', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Wondrous item, uncommon (requires attunement)

This cap has 3 charges and regains all expended charges daily at dawn. While wearing the cap, you can take a Magic action and expend 1 charge to give yourself the Invisible condition for 10 minutes. The effect ends early if the hat is removed, or immediately after you make an attack roll, deal damage, or cast a spell.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item', 'wtthc']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of Elvenkind', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While you wear this cloak, Wisdom (Perception) checks made to perceive you have Disadvantage, and you have Advantage on Dexterity (Stealth) checks.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of Protection', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'You gain a +1 bonus to Armor Class and saving throws while you wear this cloak.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of the Manta Ray', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this cloak, you can breathe underwater, and you have a Swim Speed of 60 feet.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Deck of Illusions', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This box contains a set of cards. A full deck has 34 cards: 32 depicting specific creatures and two with a mirrored surface. A deck found as treasure is usually missing 1d20 − 1 cards.

The magic of the deck functions only if its cards are drawn at random. You can take a Magic action to draw a card at random from the deck and throw it to the ground at a point within 30 feet of yourself. An illusion of a creature, determined by rolling on the Deck of Illusions table, forms over the thrown card and remains until dispelled. The illusory creature created by the card looks and behaves like a real creature of its kind, except that it can do no harm. While you are within 120 feet of the illusory creature and can see it, you can take a Magic action to move it anywhere within 30 feet of its card.

Any physical interaction with the illusory creature reveals it to be false, because objects pass through it. A creature that takes a Study action to visually inspect the illusory creature identifies it as an illusion with a successful DC 15 Intelligence (Investigation) check. The illusion lasts until its card is moved or the illusion is dispelled (using a Dispel Magic spell or a similar effect). When the illusion ends, the image on its card disappears, and that card can’t be used again.

*Stat blocks for these creatures (except the card drawer) appear in the Monster Manual.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Decanter of Endless Water', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This stoppered flask sloshes when shaken, as if it contains water. The decanter weighs 2 pounds.

You can take a Magic action to remove the stopper and issue one of three command words, whereupon an amount of fresh water or salt water (your choice) pours out of the flask. The water stops pouring out at the start of your next turn. Choose from the following command words:

Splash. The decanter produces 1 gallon of water.

Fountain. The decanter produces 5 gallons of water.

Geyser. The decanter produces 30 gallons of water that gushes forth in a Line 30 feet long and 1 foot wide. If you’re holding the decanter, you can aim the geyser in one direction (no action required). One creature of your choice in the Line must succeed on a DC 13 Strength saving throw or take 1d4 Bludgeoning damage and have the Prone condition. Instead of a creature, you can target one object in the Line that isn’t being worn or carried and that weighs no more than 200 pounds. The object is knocked over by the geyser.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Driftglobe', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This small sphere of thick glass weighs 1 pound. If you are within 60 feet of it, you can command it to emanate light equivalent to that of the Light or Daylight spell (your choice). Once used, the Daylight effect can’t be used again until the next dawn.

You can issue another command as a Magic action to make the illuminated globe rise into the air and float no more than 5 feet off the ground. The globe hovers in this way until you or another creature grasps it. If you move more than 60 feet from the hovering globe, it follows you until it is within 60 feet of you. It takes the shortest route to do so. If prevented from moving, the globe sinks gently to the ground and becomes inactive, and its light winks out.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dust of Disappearance', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This powder resembles fine sand. There is enough of it for one use. When you take a Utilize action to throw the dust into the air, you and each creature and object within a 10-foot Emanation originating from you have the Invisible condition for 2d4 minutes. The duration is the same for all subjects, and the dust is consumed when its magic takes effect. Immediately after an affected creature makes an attack roll, deals damage, or casts a spell, the Invisible condition ends for that creature.', FALSE, ARRAY['consumable', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dust of Dryness', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This small packet contains 1d6 + 4 pinches of dust. As a Utilize action, you can sprinkle a pinch of the dust over water, turning up to a 15-foot Cube of water into one marble-sized pellet, which floats or rests near where the dust was sprinkled. The pellet’s weight is negligible. A creature can take a Utilize action to smash the pellet against a hard surface, causing the pellet to shatter and release the water the dust absorbed. Doing so destroys the pellet and ends its magic.

As a Utilize action, you can sprinkle a pinch of the dust on an Elemental within 5 feet of yourself that is composed mostly of water (such as a Water Elemental or a Water Weird). Such a creature exposed to a pinch of the dust makes a DC 13 Constitution saving throw, taking 10d6 Necrotic damage on a failed save or half as much damage on a successful one.', FALSE, ARRAY['consumable', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dust of Sneezing and Choking', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Found in a small container, this powder resembles Dust of Disappearance, and Identify reveals it to be such. There is enough of it for one use.

As a Utilize action, you can throw the dust into the air, forcing yourself and every creature in a 30-foot Emanation originating from you to make a DC 15 Constitution saving throw. Constructs, Elementals, Oozes, Plants, and Undead succeed on the save automatically.

On a failed save, a creature begins sneezing uncontrollably; it has the Incapacitated condition and is suffocating. The creature repeats the save at the end of each of its turns, ending the effect on itself on a success. The effect also ends on any creature targeted by a Lesser Restoration spell.', FALSE, ARRAY['consumable', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Elemental Gem', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This gem contains a mote of elemental energy. When you take a Utilize action to break the gem, an elemental is summoned (see the Monster Manual for its stat block), and the gem ceases to be magical. The elemental appears in an unoccupied space as close to the broken gem as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The type of gem determines the elemental, as shown in the following table.', FALSE, ARRAY['consumable', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Enspelled Armor', 'Armor (Any Light', 'Uncommon', 'No', 'Varies', 'Bound into this armor is a spell of level 8 or lower. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell.

The level of the spell bound into the armor determines the spell’s saving throw DC and attack bonus, as well as the armor’s rarity, as shown in the following table.', FALSE, ARRAY['armor', 'attuned', 'legendary', 'rare', 'uncommon', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Enspelled Staff', 'Staff', 'Uncommon', 'No', 'Varies', 'Bound into this staff is a spell of level 8 or lower. The spell is determined when the staff is created and can be of any school of magic. The staff has 6 charges and regains 1d6 expended charges daily at dawn. While holding the staff, you can expend 1 charge to cast its spell. If you expend the staff’s last charge, roll 1d20. On a 1, the staff loses its properties and becomes a nonmagical Quarterstaff.

The level of the spell bound into the staff determines the spell’s saving throw DC and attack bonus, as well as the staff’s rarity, as shown in the following table.', FALSE, ARRAY['attuned', 'legendary', 'rare', 'staff', 'uncommon', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Enspelled Weapon', 'Weapon (Any Simple or Martial)', 'Uncommon', 'No', 'Varies', 'Bound into this weapon is a spell of level 8 or lower. The spell is determined when the weapon is created and must belong to the Conjuration, Divination, Evocation, Necromancy, or Transmutation school of magic. The weapon has 6 charges and regains 1d6 expended charges daily at dawn. While holding the weapon, you can expend 1 charge to cast its spell.

The level of the spell bound into the weapon determines the spell’s saving throw DC and attack bonus, as well as the weapon’s rarity, as shown in the following table.', FALSE, ARRAY['attuned', 'legendary', 'rare', 'uncommon', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Eversmoking Bottle', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'As a Magic action, you can open or close this bottle.

Opening the bottle causes thick smoke to billow out, forming a cloud that fills a 60-foot Emanation originating from the bottle. The area within the smoke is Heavily Obscured.

Each minute the bottle remains open, the size of the Emanation increases by 10 feet until it reaches its maximum size of 120 feet.

Closing the bottle causes the cloud to become fixed in place until it disperses after 10 minutes. A strong wind (such as that created by the Gust of Wind spell) disperses the cloud after 1 minute.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Eyes of Charming', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'These crystal lenses fit over the eyes. They have 3 charges. While wearing them, you can expend 1 or more charges to cast Charm Person (save DC 13). For 1 charge, you cast the level 1 version of the spell. You increase the spell’s level by one for each additional charge you expend. The lenses regain all expended charges daily at dawn.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Eyes of Minute Seeing', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'These crystal lenses fit over the eyes. While wearing them, your vision improves significantly out to a range of 1 foot, granting you Darkvision within that range and Advantage on Intelligence (Investigation) checks made to examine something within that range.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Eyes of the Eagle', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'These crystal lenses fit over the eyes. While wearing them, you have Advantage on Wisdom (Perception) checks that rely on sight. In conditions of clear visibility, you can make out details of even extremely distant creatures and objects as small as 2 feet across.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Figurine of Wondrous Power', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'A Figurine of Wondrous Power is a statuette small enough to fit in a pocket. If you take a Magic action to throw the figurine to a point on the ground within 60 feet of yourself, the figurine becomes a living creature specified in the figurine’s description below. If the space where the creature would appear is occupied by other creatures or objects, or if there isn’t enough space for the creature, the figurine doesn’t become a creature.

The creature is Friendly to you and your allies. It understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. If you issue no commands, the creature defends itself but takes no other actions.

The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if its creature form drops to 0 Hit Points or if you take a Magic action while touching the creature to make it revert to figurine form. When the creature becomes a figurine again, its property can’t be used again until a certain amount of time has passed, as specified in the figurine’s description.

This bronze statuette is of a griffon rampant. It can become a Griffon for up to 6 hours. Once it has been used, it can’t be used again until 5 days have passed.

This ebony statuette, carved in the likeness of a horsefly, can become a Giant Fly (see the accompanying stat block) for up to 12 hours and can be ridden as a mount. Once it has been used, it can’t be used again until 2 days have passed.

These gold statuettes of lions are always created in pairs. You can use one figurine or both simultaneously. Each can become a Lion for up to 1 hour. Once a lion has been used, it can’t be used again until 7 days have passed.

These ivory statuettes of goats are always created in sets of three. Each goat looks unique and functions differently from the others. Their properties are as follows:

Goat of Terror. This figurine can become a Giant Goat for up to 3 hours. The goat can’t attack, but you can (harmlessly) remove its horns and use them as weapons. One horn becomes a +1 Lance, and the other becomes a +2 Longsword. Removing a horn requires a Magic action, and the weapons disappear and the horns return when the goat reverts to figurine form. While you ride the goat, any Hostile creature that starts its turn within a 30-foot Emanation originating from the goat must succeed on a DC 15 Wisdom saving throw or have the Frightened condition for 1 minute, until you are no longer riding the goat, or until the goat reverts to figurine form. The Frightened creature repeats the save at the end of each of its turns, ending the effect on itself on a success. Once it succeeds on the save, a creature is immune to this effect for the next 24 hours. Once the figurine has been used, it can’t be used again until 15 days have passed.

Goat of Traveling. This figurine can become a Large goat with the same statistics as a Riding Horse. It has 24 charges, and each hour or portion thereof it spends in goat form costs 1 charge. While it has charges, you can use it as often as you wish. When it runs out of charges, it reverts to a figurine and can’t be used again until 7 days have passed, when it regains all expended charges.

Goat of Travail. This figurine can become a Giant Goat for up to 3 hours. Once it has been used, it can’t be used again until 30 days have passed.

This marble statuette resembles a trumpeting elephant. It can become an Elephant for up to 24 hours. Once it has been used, it can’t be used again until 7 days have passed.

This polished obsidian horse can become a Nightmare for up to 24 hours. The nightmare fights only to defend itself. Once it has been used, it can’t be used again until 5 days have passed.

The figurine has a 10 percent chance each time you use it to ignore your orders, including a command to revert to figurine form. If you mount the nightmare while it is ignoring your orders, you and the nightmare are instantly transported to a random location on the plane of Hades, where the nightmare reverts to figurine form.

This onyx statuette of a dog can become a Mastiff for up to 6 hours. The mastiff has an Intelligence of 8 and can speak Common. It also has Blindsight with a range of 60 feet. Once it has been used, it can’t be used again until 7 days have passed.

This serpentine statuette of an owl can become a Giant Owl for up to 8 hours. The owl can communicate telepathically with you at any range if you and it are on the same plane of existence. Once it has been used, it can’t be used again until 2 days have passed.

This silver statuette of a raven can become a Raven for up to 12 hours. Once it has been used, it can’t be used again until 2 days have passed. While in raven form, the figurine grants you the ability to cast Animal Messenger on it.', FALSE, ARRAY['rare', 'uncommon', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Gauntlets of Ogre Power', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Your Strength is 19 while you wear these gauntlets. They have no effect on you if your Strength is 19 or higher without them.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Gem of Brightness', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This prism has 50 charges. While you are holding it, you can take a Magic action and use one of three command words to cause one of the following effects:

First Command Word. The gem sheds Bright Light in a 30-foot radius and Dim Light for an additional 30 feet. This effect doesn’t expend a charge. It lasts until you take a Bonus Action to repeat the command word or until you use another function of the gem.

Second Command Word. You expend 1 charge and cause the gem to fire a brilliant beam of light at one creature you can see within 60 feet of yourself. The creature must succeed on a DC 15 Constitution saving throw or have the Blinded condition for 1 minute. The creature repeats the save at the end of each of its turns, ending the effect on itself on a success.

Third Command Word. You expend 5 charges and cause the gem to flare with intense light in a 30-foot Cone. Each creature in the Cone makes a saving throw as if struck by the beam created with the second command word.

When all of the gem’s charges are expended, the gem becomes a nonmagical jewel worth 50 GP.', FALSE, ARRAY['consumable', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Gloves of Missile Snaring', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'If you’re hit by an attack roll made with a Ranged or Thrown weapon while wearing these gloves, you can take a Reaction to reduce the damage by 1d10 plus your Dexterity modifier if you have a free hand. If you reduce the damage to 0, you can catch the ammunition or weapon if it is small enough for you to hold in that hand.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Gloves of Thievery', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'These gloves are imperceptible while worn. While wearing them, you gain a +5 bonus to Dexterity (Sleight of Hand) checks.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Gloves of Swimming and Climbing', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing these gloves, you have a Climb Speed and a Swim Speed equal to your Speed, and you gain a +5 bonus to Strength (Athletics) checks made to climb or swim.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Goggles of Night', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing these dark lenses, you have Darkvision out to 60 feet. If you already have Darkvision, wearing the goggles increases its range by 60 feet.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Hag Eye', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'A Hag Eye has 3 charges. While wearing or holding this item, you can expend 1 charge to cast Darkvision (targeting yourself only) or See Invisibility. The Hag Eye regains all expended charges daily at dawn.

Coven Sensor. The Hag Eye is usually entrusted to a hag’s minion for safekeeping and transport. As a Magic action, a hag who belongs to the coven that created the Hag Eye can see what the Hag Eye sees if the hag and the Hag Eye are on the same plane of existence. This effect lasts as long as the hag maintains Concentration. Multiple hags in the coven can see through the Hag Eye simultaneously.

Creating a Hag Eye. Only a hag coven can craft this item, which is made from a real eye coated in varnish and often fitted to a pendant or another wearable item. A hag coven can have only one Hag Eye at a time, and creating a new one requires all three members of the coven to perform a special rite. This rite takes 1 hour, and the hags can’t perform it if one or more of them has the Incapacitated condition. If the hags take any other actions during this rite, the rite fails and ends.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Harkon''s Bite', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'A dire wolf’s tooth dangles from this simple cord necklace. You gain a +1 bonus to ability checks and saving throws while you wear this necklace.

Curse. This necklace is cursed. Attuning to the necklace curses you; this curse can’t be removed until Harkon Lukas dies. As long as you remain cursed, you become a Werewolf serving Harkon Lukas under the DM’s control during the night of a full moon.', FALSE, ARRAY['attuned', 'rthw', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Hat of Vortexes', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This hat has 3 charges and regains all expended charges daily at dawn. You can take a Magic action and expend 1 charge while holding the hat to release a magical vortex from it. The vortex fills a 10-foot Cube originating from you and lasts for 1 hour. While the vortex is present, its area is Difficult Terrain.

You decide a vortex’s visual details when you create it. For instance, the vortex might be multicolored or glittery.', FALSE, ARRAY['attuned', 'nf', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Harper Pin', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'When you attune to this pin, choose a Harper persona (see the Forgotten Realms: Heroes of Faerûn for examples), including an alignment and a creature type. While wearing this pin, you register as that persona when targeted by magic to determine your creature type, alignment, or location.

The type of pin determines its rarity and effects.

Silver Harper Pin. When you attune to this pin, you can devise a general line of thought of 25 words or fewer. While you wear this pin, a creature that reads your thoughts detects your preprogrammed line of thought instead. A creature that takes the Study action while reading your thoughts makes a DC 13 Intelligence (Investigation) check. On a successful check, it becomes aware that the detected thoughts are preprogrammed.

Golden Harper Pin. While wearing this pin, you can cast the Nondetection spell on yourself. The duration of this spell is permanent until you disable the effect (no action required), you remove the pin, or you are no longer attuned to the pin.', FALSE, ARRAY['attuned', 'fraif', 'rare', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Headband of Intellect', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Your Intelligence is 19 while you wear this headband. It has no effect on you if your Intelligence is 19 or higher without it.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Hat of Disguise', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this hat, you can cast the Disguise Self spell. The spell ends if the hat is removed.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Helm of Awareness', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this helmet, you have Advantage on Initiative rolls.', FALSE, ARRAY['efota', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Helm of Comprehending Languages', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this helm, you can cast Comprehend Languages from it.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Immovable Rod', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Rod, Uncommon

This iron rod has a button on one end. You can take a Utilize action to press the button, which causes the rod to become magically fixed in place. Until you or another creature takes a Utilize action to push the button again, the rod doesn’t move, even if it defies gravity. The rod can hold up to 8,000 pounds of weight. More weight causes the rod to deactivate and fall. A creature can take a Utilize action to make a DC 30 Strength (Athletics) check, moving the fixed rod up to 10 feet on a successful check.', FALSE, ARRAY['rod', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Instrument of the Bards', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'An Instrument of the Bards is superior to an ordinary instrument in every way. Seven types of these instruments exist, each named after a bard college. The Instruments of the Bards table lists the spells common to all instruments, as well as the spells specific to each one and its rarity. A creature that attempts to play the instrument without being attuned to it must succeed on a DC 15 Wisdom saving throw or take 2d4 Psychic damage.

You can play the instrument to cast one of its spells. Once the instrument has been used to cast a spell, it can’t be used to cast that spell again until the next dawn. The spells use your spellcasting ability and spell save DC.', FALSE, ARRAY['attuned', 'legendary', 'rare', 'uncommon', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Helm of Telepathy', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this helm, you have telepathy with a range of 30 feet, and you can cast Detect Thoughts or Suggestion (save DC 13) from the helm. Once either spell is cast from the helm, that spell can’t be cast from it again until the next dawn.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Javelin of Lightning', 'Weapon (Javelin)', 'Uncommon', 'No', 'Varies', 'Each time you make an attack roll with this magic weapon and hit, you can have it deal Lightning damage instead of Piercing damage.

Lightning Bolt. When you throw this weapon at a target no farther than 120 feet from you, you can forgo making a ranged attack roll and instead turn the weapon into a bolt of lightning. This bolt forms a 5-foot-wide Line between you and the target. The target and each other creature in the Line (excluding you) makes a DC 13 Dexterity saving throw, taking 4d6 Lightning damage on a failed save or half as much damage on a successful one. Immediately after dealing this damage, the weapon reappears in your hand. This property can’t be used again until the next dawn.', FALSE, ARRAY['uncommon', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Keoghtom''s Ointment', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This glass jar, 3 inches in diameter, contains 1d4 + 1 doses of a thick mixture that smells faintly of aloe. The jar and its contents weigh 1/2 pound.

As a Utilize action, you can swallow one dose of the ointment or apply it to a creature within 5 feet of yourself. The creature that receives it regains 2d8 + 2 Hit Points and ceases to have the Poisoned condition.', FALSE, ARRAY['consumable', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Lantern of Revealing', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While lit, this hooded lantern burns for 6 hours on 1 pint of oil, shedding Bright Light in a 30-foot radius and Dim Light for an additional 30 feet. Invisible creatures and objects are visible as long as they are in the lantern’s Bright Light. You can take a Utilize action to lower the hood, reducing the lantern’s light to Dim Light in a 5-foot radius.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mind Sharpener', 'Ring', 'Uncommon', 'No', 'Varies', 'The item has 4 charges. When you fail a Constitution saving throw to maintain Concentration, you can take a Reaction and expend 1 of the item’s charges to succeed instead. The item regains 1d4 expended charges daily at dawn.', FALSE, ARRAY['attuned', 'efota', 'ring', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mariner''s Armor', 'Armor (Any Light', 'Uncommon', 'No', 'Varies', 'While wearing this armor, you have a Swim Speed equal to your Speed. In addition, if you start your turn underwater with 0 Hit Points, you immediately regain 1d4 Hit Points. The armor can’t heal anyone again until the next dawn.

The armor is decorated with fish and shell motifs.', FALSE, ARRAY['armor', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mithral Armor', 'Armor (Any Medium or Heavy', 'Uncommon', 'No', 'Varies', 'Mithral is a light, flexible metal. Armor made of this substance can be worn under normal clothes. If the armor normally imposes Disadvantage on Dexterity (Stealth) checks or has a Strength requirement, the mithral version of the armor doesn’t.', FALSE, ARRAY['armor', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Necklace of Adaptation', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this necklace, you can breathe normally in any environment, and you have Advantage on saving throws made to avoid or end the Poisoned condition.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Oil of Slipperiness', 'Potion', 'Uncommon', 'No', 'Varies', 'One vial of this oil can cover one Medium or smaller creature, along with the equipment it’s wearing and carrying (one additional vial is required for each size category above Medium). Applying the oil takes 10 minutes. The affected creature then gains the effect of the Freedom of Movement spell for 8 hours.

Alternatively, the oil can be poured on the ground as a Magic action, where it covers a 10-foot square, duplicating the effect of the Grease spell in that area for 8 hours.

This sticky, black unguent is thick and heavy, but it flows quickly when poured.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Pearl of Power', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While this pearl is on your person, you can take a Magic action to regain one expended spell slot of level 3 or lower. Once you use the pearl, it can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Nature''s Mantle', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This cloak shifts color and texture to blend with the terrain surrounding you. While wearing the cloak, you can use it as a Spellcasting Focus for your Druid and Ranger spells.

While you are in an area that is Lightly Obscured, you can Hide as a Bonus Action even if you are being directly observed.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Periapt of Health', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this pendant, you can take a Magic action to regain 2d4 + 2 Hit Points. Once used, this property can’t be used again until the next dawn.

In addition, you have Advantage on saving throws to avoid or end the Poisoned condition while you wear this pendant.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Pipes of Haunting', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'These pipes have 3 charges and regain 1d3 expended charges daily at dawn. You can take a Magic action to play them and expend 1 charge to create an eerie, spellbinding tune. Each creature of your choice within 30 feet of you must succeed on a DC 15 Wisdom saving throw or have the Frightened condition for 1 minute. A creature that fails the save repeats it at the end of each of its turns, ending the effect on itself on a success. A creature that succeeds on its save is immune to the effect of these pipes for 24 hours.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Periapt of Wound Closure', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this pendant, you gain the following benefits.

Life Preservation. Whenever you make a Death Saving Throw, you can change a roll of 9 or lower to a 10, turning a failed save into a successful one.

Natural Healing Boost. Whenever you roll a Hit Point Die to regain Hit Points, double the number of Hit Points it restores.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Philter of Love', 'Potion', 'Uncommon', 'No', 'Varies', 'The next time you see a creature within 10 minutes after drinking this philter, you are charmed by that creature and have the Charmed condition for 1 hour.

This rose-hued, effervescent liquid contains one easy-to-miss bubble shaped like a heart.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Pipes Of Pestilence', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Wondrous item, uncommon (requires attunement)

If you play these pipes as a Magic action, you summon one Swarm of Corrupted Rats in an unoccupied space within 60 feet of yourself. The swarm is Friendly to you and your allies for as long as you continue to play the pipes each round as a Magic action. While Friendly, the swarm is under your control, obeys your commands, and takes no action other than to defend itself if you issue it no commands. Once your control ends, the swarm vanishes, and the pipes can''t be used again until the next dawn.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item', 'wtthc']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Pipes of the Sewers', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While these pipes are on your person, ordinary rats and giant rats are Indifferent toward you and won’t attack you unless you threaten or harm them.

The pipes have 3 charges and regain 1d3 expended charges daily at dawn. If you play the pipes as a Magic action, you can take a Bonus Action to expend 1 to 3 charges, calling forth one Swarm of Rats with each expended charge if enough rats are within half a mile of you to be called in this fashion (as determined by the DM). If there aren’t enough rats to form a swarm, the charge is wasted. Called swarms move toward the music by the shortest available route but aren’t under your control otherwise.

Whenever a Swarm of Rats that isn’t under another creature’s control comes within 30 feet of you while you are playing the pipes, the swarm makes a DC 15 Wisdom saving throw. On a successful save, the swarm behaves as it normally would and can’t be swayed by the pipes’ music for the next 24 hours. On a failed save, the swarm is swayed by the pipes’ music and becomes Friendly to you and your allies for as long as you continue to play the pipes each round as a Magic action. A Friendly swarm obeys your commands. If you issue no commands to a Friendly swarm, it defends itself but otherwise takes no actions. If a Friendly swarm starts its turn more than 30 feet away from you, your control over that swarm ends, and the swarm behaves as it normally would and can’t be swayed by the pipes’ music for the next 24 hours.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Poison Soaked Kukri', 'Weapon', 'Uncommon', 'Required', 'Varies', 'You can take a Bonus Action to magically coat the blade of this Dagger with poison. The poison remains for 1 minute or until an attack using this weapon hits a creature. That creature must succeed on a DC 13 Constitution saving throw or take 2d8 Poison damage and have the Poisoned condition for 1 minute. This Bonus Action can''t be used again this way until the next dawn.', FALSE, ARRAY['attuned', 'uncommon', 'weapon', 'wtthc']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Fire Breath', 'Potion', 'Uncommon', 'No', 'Varies', 'After drinking this potion, you can take a Bonus Action to exhale fire at a target within 30 feet of yourself. The target makes a DC 13 Dexterity saving throw, taking 4d6 Fire damage on a failed save or half as much damage on a successful one. The effect ends after you exhale the fire three times or when 1 hour has passed.

This potion’s orange liquid flickers, and smoke fills the top of the container and wafts out whenever it is opened.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Animal Friendship', 'Potion', 'Uncommon', 'No', 'Varies', 'When you drink this potion, you can cast the level 3 version of the Animal Friendship spell (save DC 13).

Agitating this potion’s muddy liquid brings little bits into view: a fish scale, a hummingbird feather, a cat claw, or a squirrel hair.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Giant Strength', 'Potion', 'Uncommon', 'No', 'Varies', 'When you drink this potion, your Strength score changes for 1 hour. The type of giant determines the score (see the table below). The potion has no effect on you if your Strength is equal to or greater than that score.

This potion’s transparent liquid has floating in it a sliver of light resembling a giant’s fingernail.', FALSE, ARRAY['consumable', 'legendary', 'potion', 'rare', 'uncommon', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Pugilism', 'Potion', 'Uncommon', 'No', 'Varies', 'After you drink this potion, each Unarmed Strike you make deals an extra 1d6 Force damage on a hit. This effect lasts 10 minutes.

This potion is a thick green fluid that tastes like spinach.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Growth', 'Potion', 'Uncommon', 'No', 'Varies', 'When you drink this potion, you gain the “enlarge” effect of the Enlarge/Reduce spell for 10 minutes (no Concentration required).

The red in the potion’s liquid continuously expands from a tiny bead to color the clear liquid around it and then contracts. Shaking the bottle fails to interrupt this process.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Resistance', 'Potion', 'Uncommon', 'No', 'Varies', 'When you drink this potion, you have Resistance to one type of damage for 1 hour. The DM chooses the type or determines it randomly by rolling on the following table.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Poison', 'Potion', 'Uncommon', 'No', 'Varies', 'This concoction looks, smells, and tastes like a Potion of Healing or another beneficial potion. However, it is actually poison masked by illusion magic. Identify reveals its true nature.

If you drink this potion, you take 4d6 Poison damage and must succeed on a DC 13 Constitution saving throw or have the Poisoned condition for 1 hour.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Water Breathing', 'Potion', 'Uncommon', 'No', 'Varies', 'You can breathe underwater for 24 hours after drinking this potion.

This potion’s cloudy green fluid smells of the sea and has a jellyfish-like bubble floating in it.', FALSE, ARRAY['consumable', 'potion', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Quaal''s Feather Token', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This object looks like a feather. Different types of feather tokens exist, each with a different single-use effect. The DM chooses the kind of token or determines it randomly by rolling on the Quaal’s Feather Tokens table. The type of token determines its rarity.

Anchor (Uncommon) You can take a Magic action to touch the token to a boat or ship. For the next 24 hours, the vessel can’t be moved by any means. Touching the token to the vessel again ends the effect. When the effect ends, the token disappears.

Bird (Rare) You can take a Magic action to toss the token 5 feet into the air. The token disappears and an enormous, multicolored bird takes its place. The bird has the statistics of a Roc, but it can’t attack. It obeys your simple commands and can carry up to 500 pounds while flying at its maximum speed (16 miles per hour for a maximum of 144 miles per day, with a 1-hour rest for every 3 hours of flying) or 1,000 pounds at half that speed. The bird disappears after flying its maximum distance for a day or if it drops to 0 Hit Points. You can dismiss the bird as a Magic action.

Fan (Uncommon) If you are on a boat or ship, you can take a Magic action to toss the token up to 10 feet in the air. The token disappears, and a giant flapping fan takes its place. The fan floats and creates a strong wind. This wind can fill the sails of one ship, increasing its speed by 5 miles per hour for 8 hours. You can dismiss the fan as a Magic action.

Swan Boat (Rare) You can take a Magic action to touch the token to a body of water at least 60 feet in diameter. The token disappears, and a 50-foot-long, 20-foot-wide boat shaped like a swan takes its place. The boat is self-propelled and moves across water at a speed of 6 miles per hour. You can take a Magic action while on the boat to command it to move or to turn up to 90 degrees. The boat remains for 24 hours and then disappears. You can dismiss the boat as a Magic action.

Tree (Uncommon) You must be outdoors to use this token. You can take a Magic action to touch it to an unoccupied space on the ground. The token disappears, and in its place a nonmagical oak tree springs into existence. The tree is 60 feet tall and has a 5-foot-diameter trunk, and its branches at the top spread out in a 20-foot radius.

Whip (Rare) You can take a Magic action to throw the token to a point within 10 feet of yourself. The token disappears, and a floating whip takes its place. You can then take a Bonus Action to make a melee spell attack against a creature within 10 feet of the whip, with an attack bonus of +9. On a hit, the target takes 1d6 + 5 Force damage.

As a Bonus Action, you can direct the whip to fly up to 20 feet and repeat the attack against a creature within 10 feet of the whip. The whip disappears after 1 hour, when you take a Magic action to dismiss it, or when you die or have the Incapacitated condition.', FALSE, ARRAY['consumable', 'rare', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Reliquary of Dawn', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This talisman contains a discarded claw, scale, or fang from Eirdu, which many believe is the incarnation of the sun in Lorwyn. While you wear a Reliquary of Dawn, you are immune to the effects of Eventide.', FALSE, ARRAY['lfl', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Reliquary of Twilight', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This talisman contains a discarded claw, scale, or fang from Isilu, which many believe is the incarnation of the moon in Shadowmoor. While you wear a Reliquary of Twilight, you are immune to the effects of Morningtide.', FALSE, ARRAY['lfl', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Quiver of Ehlonna', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Each of the quiver’s three compartments connects to an extradimensional space that allows the quiver to hold numerous items while never weighing more than 2 pounds. The shortest compartment can hold up to 60 Arrows, Bolts, or similar objects. The midsize compartment holds up to 18 Javelins or similar objects. The longest compartment holds up to 6 long objects, such as bows, Quarterstaffs, or Spears.

You can draw any item the quiver contains as if doing so from a regular quiver or scabbard.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Repeating Shot', 'Weapon (Any Simple or Martial with the Ammunition Property)', 'Uncommon', 'No', 'Varies', 'This magic weapon grants a +1 bonus to attack and damage rolls made with it when it’s used to make a ranged attack, and it ignores the Loading property if it has that property.

If the weapon lacks ammunition, it produces its own, automatically creating one piece of magic ammunition when the wielder makes a ranged attack roll with it. The ammunition created by the weapon vanishes the instant after it hits or misses a target.', FALSE, ARRAY['attuned', 'efota', 'uncommon', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Returning Weapon', 'Weapon (Any Simple or Martial with the Thrown Property)', 'Uncommon', 'No', 'Varies', 'This magic weapon grants a +1 bonus to attack and damage rolls made with it, and it returns to your hand immediately after you use it to make a ranged attack roll.', FALSE, ARRAY['efota', 'uncommon', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Repulsion Shield', 'Armor (Shield)', 'Uncommon', 'No', 'Varies', 'You gain a +1 bonus to Armor Class while wielding this shield.

The shield has 4 charges. While holding it, when a Large or smaller creature within 5 feet of you hits you with a melee attack roll, you can take a Reaction to expend 1 of the shield’s charges and push the attacker up to 15 feet straight away. The shield regains 1d4 expended charges daily at dawn.', FALSE, ARRAY['armor', 'efota', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Mind Shielding', 'Ring', 'Uncommon', 'No', 'Varies', 'While wearing this ring, you are immune to magic that allows other creatures to read your thoughts, determine whether you are lying, know your alignment, or know your creature type. Creatures can telepathically communicate with you only if you allow it.

You can take a Magic action to cause the ring to become imperceptible until you take another Magic action to make it perceptible, until you remove the ring, or until you die.

If you die while wearing the ring, your soul enters it, unless it already houses a soul. You can remain in the ring or depart for the afterlife. As long as your soul is in the ring, you can telepathically communicate with any creature wearing it. A wearer can’t prevent this telepathic communication.', FALSE, ARRAY['attuned', 'ring', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Jumping', 'Ring', 'Uncommon', 'No', 'Varies', 'While wearing this ring, you can cast Jump from it, but can target only yourself when you do so.', FALSE, ARRAY['attuned', 'ring', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Swimming', 'Ring', 'Uncommon', 'No', 'Varies', 'You have a Swim Speed of 40 feet while wearing this ring.', FALSE, ARRAY['ring', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Warmth', 'Ring', 'Uncommon', 'No', 'Varies', 'If you take Cold damage while wearing this ring, the ring reduces the damage you take by 2d8.

In addition, while wearing this ring, you and everything you wear and carry are unharmed by temperatures of 0 degrees Fahrenheit or lower.', FALSE, ARRAY['attuned', 'ring', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Robe of Useful Items', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This robe has cloth patches of various shapes and colors covering it. While wearing the robe, you can take a Magic action to detach one of the patches, causing it to become the object or creature it represents. Once the last patch is removed, the robe becomes an ordinary garment.

The robe has two of each of the following patches:

In addition, the robe has 4d4 other patches. The DM chooses the patches or determines them randomly by rolling on the following table.', FALSE, ARRAY['consumable', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Water Walking', 'Ring', 'Uncommon', 'No', 'Varies', 'While wearing this ring, you cast Water Walk from it, targeting only yourself.', FALSE, ARRAY['ring', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rod of the Pact Keeper', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Rod, Uncommon (+1), Rare (+2), or Very Rare (+3) (Requires Attunement by a Warlock)

While holding this rod, you gain a bonus to spell attack rolls and to the saving throw DCs of your Warlock spells. The bonus is determined by the rod’s rarity.

In addition, you can regain one spell slot as a Magic action while holding the rod. You can’t use this property again until you finish a Long Rest.', FALSE, ARRAY['attuned', 'rare', 'rod', 'uncommon', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rope of Climbing', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This 60-foot length of rope can hold up to 3,000 pounds. While holding one end of the rope, you can take a Magic action to command the other end of the rope to animate and move toward a destination you choose, up to the rope’s length away from you. That end moves 10 feet on your turn when you first command it and 10 feet at the start of each of your subsequent turns until reaching its destination or until you tell it to stop. You can also tell the rope to fasten itself securely to an object or to unfasten itself, to knot or unknot itself, or to coil itself for carrying.

If you tell the rope to knot, large knots appear at 1-foot intervals along the rope. While knotted, the rope shortens to a 50-foot length and grants Advantage on ability checks made to climb using the rope.

The rope has AC 20, HP 20, and Immunity to Poison and Psychic damage. It regains 1 Hit Point every 5 minutes as long as it has at least 1 Hit Point. If the rope drops to 0 Hit Points, it is destroyed.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sending Stones', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'Sending Stones come in pairs, with each stone carved to match the other so the pairing is easily recognized. While you touch one stone, you can cast Sending from it. The target is the bearer of the other stone. If no creature bears the other stone, you know that fact as soon as you use the stone, and you don’t cast the spell.

Once Sending is cast using either stone, the stones can’t be used again until the next dawn. If one of the stones in a pair is destroyed, the other one becomes nonmagical.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Saddle of the Cavalier', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This saddle confers the following benefits while you are seated in it and astride a mount.

Protected Mount. Attack rolls against the mount have Disadvantage.

Secure Rider. You can’t be dismounted against your will. This property is suppressed while you have the Incapacitated condition.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sentinel Shield', 'Armor (Shield)', 'Uncommon', 'No', 'Varies', 'While holding this Shield, you have Advantage on Initiative rolls and Wisdom (Perception) checks. The Shield is emblazoned with a symbol of an eye.', FALSE, ARRAY['armor', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Shield, +1, +2, or +3', 'Armor (Shield)', 'Uncommon', 'No', 'Varies', 'While holding this Shield, you have a bonus to Armor Class determined by the Shield’s rarity, in addition to the Shield’s normal bonus to AC.', FALSE, ARRAY['armor', 'rare', 'uncommon', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Slippers of Spider Climbing', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While you wear these light shoes, you can move up, down, and across vertical surfaces and along ceilings, while leaving your hands free. You have a Climb Speed equal to your Speed. However, the slippers don’t allow you to move this way on a slippery surface, such as one covered by ice or oil.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Spiked Shield', 'Armor (shield)', 'Uncommon', 'Required', 'Varies', 'Crude metal spikes adorn this magic Shield. It has the following properties that you can use while holding it.

Shield Bash. When you take the Attack action, you can make one of the attack rolls using the Shield against a target within 5 feet of yourself. Apply your Proficiency Bonus and Strength modifier to the attack roll. On a hit, the Shield deals Piercing damage equal to 2d6 plus your Strength modifier.

Spike Salvo. As a Magic action, you can cause spikes to erupt from the Shield in a 30-foot Cone. Each creature in the Cone makes a DC 13 Dexterity saving throw, taking 3d6 Piercing damage on a failed save or half as much damage on a successful one. Once this property is used, it can''t be used again until the next dawn.', FALSE, ARRAY['armor', 'attuned', 'uncommon', 'wtthc']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Spell-Refueling Ring', 'Ring', 'Uncommon', 'No', 'Varies', 'While wearing this ring, you can recover one expended spell slot as a Bonus Action. The recovered slot can be of level 3 or lower. Once used, the ring can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'efota', 'ring', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of the Adder', 'Staff', 'Uncommon', 'No', 'Varies', 'As a Bonus Action, you can turn the head of this staff into that of an animate, venomous snake for 1 minute or revert the staff to its inanimate form.

When you take the Attack action, you can make one of the attack rolls using the animated snake head, which has a reach of 5 feet. Apply your Proficiency Bonus and Wisdom modifier to the attack roll. On a hit, the target takes 1d6 Piercing damage and 3d6 Poison damage.

The snake head can be attacked while it is animate. It has AC 15, HP 20, and Immunity to Poison and Psychic damage. If the head drops to 0 Hit Points, the staff is destroyed. As long as it’s not destroyed, the staff regains all lost Hit Points when it reverts to its inanimate form.', FALSE, ARRAY['attuned', 'staff', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of the Python', 'Staff', 'Uncommon', 'No', 'Varies', 'As a Magic action, you can throw this staff so that it lands in an unoccupied space within 10 feet of you, causing the staff to become a Giant Constrictor Snake in that space. The snake is under your control and shares your Initiative count, taking its turn immediately after yours.

On your turn, you can mentally command the snake (no action required) if it is within 60 feet of you and you don’t have the Incapacitated condition. You decide what action the snake takes and where it moves during its turn, or you can issue it a general command, such as to attack your enemies or guard a location. Absent commands from you, the snake defends itself.

As a Bonus Action, you can command the snake to revert to staff form in its current space, and you can’t use the staff’s property again for 1 hour. If the snake is reduced to 0 Hit Points, it dies and reverts to its staff form; the staff then shatters and is destroyed. If the snake reverts to staff form before losing all its Hit Points, it regains all of them.', FALSE, ARRAY['attuned', 'staff', 'uncommon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Stone of Good Luck (Luckstone)', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While this polished agate is on your person, you gain a +1 bonus to ability checks and saving throws.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sword of Vengeance', 'Weapon (Glaive', 'Uncommon', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon.

Curse. This weapon is cursed and possessed by a vengeful spirit. Becoming attuned to it extends the curse to you. As long as you remain cursed, you are unwilling to part with the weapon, keeping it on your person at all times. While attuned to this weapon, you have Disadvantage on attack rolls made with weapons other than this one.

In addition, while the weapon is on your person, you must succeed on a DC 15 Wisdom saving throw whenever you take damage from another creature in combat. On a failed save, you must attack the creature that damaged you until you drop to 0 Hit Points or it does or until you can’t reach the creature to make a melee attack against it.

You can break the curse in the usual ways. Alternatively, casting Banishment on the weapon forces the vengeful spirit to leave it. The weapon then becomes a +1 Weapon with no other properties.', FALSE, ARRAY['attuned', 'cursed', 'uncommon', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Thayan Spell Tattoo', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'This magical tattoo contains the essence of a level 1–3 spell chosen by the tattoo’s creator. While the tattoo is on your body, you always have the associated spell prepared, and you can cast the spell using any spell slots you have of the appropriate level. If you have the Spellcasting or Pact Magic feature, the spell uses your spellcasting ability; otherwise, if the spell requires a saving throw or an attack roll, the spell save DC is 13 and the attack bonus is +5. If your Attunement to the tattoo ends, the tattoo vanishes.

You can also cast the spell once without a spell slot and spell components. Once the spell is cast in this way, the tattoo vanishes.

The Thayan art of magical tattooing is highly guarded by its practitioners, and thus, Thayan Spell Tattoos can’t be crafted like other magic items. To learn how to ink Thayan Spell Tattoos, you must have a Renown Score of 50+ with the Red Wizards.

To ink a Thayan Spell Tattoo, you must have proficiency in the Arcana skill and with Calligrapher’s Tools and have the spell prepared each day of the inking. You must also have at hand any Material components required by the spell; if the spell consumes its Material components, they are consumed when you complete the tattoo. Inking a Thayan Spell Tattoo takes the same amount of time and money as scribing a Spell Scroll of an equivalent level.', FALSE, ARRAY['attuned', 'consumable', 'frhof', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Trident of Fish Command', 'Weapon (Trident)', 'Uncommon', 'No', 'Varies', 'This magic weapon has 3 charges, and it regains 1d3 expended charges daily at dawn. While you carry it, you can expend 1 charge to cast Dominate Beast (save DC 15) from it on a Beast that has a Swim Speed.', FALSE, ARRAY['attuned', 'uncommon', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Magic Detection', 'Wand', 'Uncommon', 'No', 'Varies', 'This wand has 3 charges. While holding it, you can expend 1 charge to cast Detect Magic from it. The wand regains 1d3 expended charges daily at dawn.', FALSE, ARRAY['uncommon', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Magic Missiles', 'Wand', 'Uncommon', 'No', 'Varies', 'This wand has 7 charges. While holding it, you can expend no more than 3 charges to cast Magic Missile from it. For 1 charge, you cast the level 1 version of the spell. You can increase the spell’s level by 1 for each additional charge you expend.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', FALSE, ARRAY['uncommon', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Secrets', 'Wand', 'Uncommon', 'No', 'Varies', 'This wand has 3 charges and regains 1d3 expended charges daily at dawn. While holding it, you can take a Magic action to expend 1 charge, and if a secret door or trap is within 60 feet of you, the wand pulses and points at the one nearest to you.', FALSE, ARRAY['uncommon', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of the War Mage, +1, +2 or +3', 'Wand', 'Uncommon', 'No', 'Varies', 'While holding this wand, you gain a bonus to spell attack rolls determined by the wand’s rarity. In addition, you ignore Half Cover when making a spell attack roll.', FALSE, ARRAY['attuned', 'rare', 'uncommon', 'very-rare', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Weapon of Warning', 'Weapon (Any Simple or Martial)', 'Uncommon', 'No', 'Varies', 'As long as this weapon is within your reach and you are attuned to it, you and allies within 30 feet of you gain the following benefits.

Alarm. The weapon magically awakens each subject who is sleeping naturally when combat begins. This benefit doesn''t wake a subject from magically induced sleep.

Supernatural Readiness. Each subject has Advantage on its Initiative rolls.', FALSE, ARRAY['attuned', 'uncommon', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Weapon, +1, +2 or +3', 'Weapon (Any Simple or Martial)', 'Uncommon', 'No', 'Varies', 'You have a bonus to attack rolls and damage rolls made with this magic weapon. The bonus is determined by the weapon’s rarity.', FALSE, ARRAY['rare', 'uncommon', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Web', 'Wand', 'Uncommon', 'No', 'Varies', 'This wand has 7 charges. While holding it, you can expend 1 charge to cast Web (save DC 13) from it.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', FALSE, ARRAY['attuned', 'uncommon', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wind Fan', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While holding this fan, you can cast Gust of Wind (save DC 13) from it. Each subsequent time the fan is used before the next dawn, it has a cumulative 20 percent chance of not working; if the fan fails to work, it tears into useless, nonmagical tatters.', FALSE, ARRAY['uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wraps of Unarmed Power', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing these wraps, you have a bonus to attack rolls and damage rolls made with your Unarmed Strikes. The bonus is determined by the wraps'' rarity, and those strikes deal your choice of Force damage or their normal damage type.', FALSE, ARRAY['rare', 'uncommon', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Winged Boots', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'These boots have 4 charges and regain 1d4 expended charges daily at dawn. While wearing the boots, you can take a Magic action to expend 1 charge, gaining a Fly Speed of 30 feet for 1 hour. If you are flying when the duration expires, you descend at a rate of 30 feet per round until you land.', FALSE, ARRAY['attuned', 'uncommon', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Amulet of Health', 'Wondrous Item', 'Rare', 'No', 'Varies', 'Your Constitution is 19 while you wear this amulet. It has no effect on you if your Constitution is 19 or higher without it.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Amulet of Retributive Healing', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This amulet has 3 charges and regains 1d4 charges daily at dawn. When you restore Hit Points to one other creature, you can expend 1 charge to regain the same amount of Hit Points.', FALSE, ARRAY['attuned', 'drops', 'drops0626', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Armor, +1, +2, or +3', 'Armor (Any Light', 'Rare', 'No', 'Varies', 'You have a bonus to Armor Class while wearing this armor. The bonus is determined by its rarity.', FALSE, ARRAY['armor', 'legendary', 'rare', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Armor of Resistance', 'Armor (Any Light', 'Rare', 'No', 'Varies', 'You have Resistance to one type of damage while you wear this armor. The DM chooses the type or determines it randomly by rolling on the following table.', FALSE, ARRAY['armor', 'attuned', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Armor of Vulnerability', 'Armor (Any Light', 'Rare', 'No', 'Varies', 'While wearing this armor, you have Resistance to one of the following damage types: Bludgeoning, Piercing, or Slashing. The DM chooses the type or determines it randomly.

Curse. This armor is cursed, a fact that is revealed only when the Identify spell is cast on the armor or you attune to it. Attuning to the armor curses you until you are targeted by a Remove Curse spell or similar magic; removing the armor fails to end the curse. While cursed, you have Vulnerability to two of the three damage types associated with the armor (not the one to which it grants Resistance).', FALSE, ARRAY['armor', 'attuned', 'cursed', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Arrow-Catching Shield', 'Wondrous Item', 'Rare', 'No', 'Varies', 'You gain a +2 bonus to Armor Class against ranged attack rolls while you wield this Shield. This bonus is in addition to the Shield’s normal bonus to AC.

Whenever an attacker makes a ranged attack roll against a target within 5 feet of you, you can take a Reaction to become the target of the attack instead.', FALSE, ARRAY['armor', 'attuned', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bag of Beans', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This heavy cloth bag contains 3d4 dry beans when found. The bag weighs half a pound regardless of how many beans it contains and becomes a nonmagical item when it no longer contains any beans.

If you dump one or more beans out of the bag, they explode in a 10-foot-radius Sphere centered on them. All the dumped beans are destroyed in the explosion, and each creature in the Sphere, including you, makes a DC 15 Dexterity saving throw, taking 5d4 Force damage on a failed save or half as much damage on a successful one.

If you remove a bean from the bag, plant it in dirt or sand, and then water it, the bean disappears as it produces an effect 1 minute later from the ground where it was planted. The DM can choose an effect from the following table or determine it randomly.', FALSE, ARRAY['consumable', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Belt of Dwarvenkind', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While wearing this belt, you gain the following benefits:

Dwarvish. You know Dwarvish.

Friend of Dwarvenkind. You have Advantage on Charisma (Persuasion) checks made to interact with dwarves and duergar.

Toughness. Your Constitution increases by 2, to a maximum of 20.

In addition, while attuned to the belt, you have a 50 percent chance each day at dawn of growing a full beard if you can grow one, or a thicker beard if you already have one.

If you aren’t a dwarf or duergar, you gain the following additional benefits while wearing the belt:

Darkvision. You have Darkvision with a range of 60 feet.

Resilience. You have Resistance to Poison damage. You also have Advantage on saving throws you make to avoid or end the Poisoned condition.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bead of Force', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This small black sphere measures 3/4 of an inch in diameter and weighs an ounce. Typically, 1d4 + 4 Beads of Force are found together.

You can take a Magic action to throw the bead up to 60 feet. The bead explodes in a 10-foot-radius Sphere on impact and is destroyed. Each creature in the Sphere must succeed on a DC 15 Dexterity saving throw or take 5d4 Force damage. A sphere of transparent force then encloses the area for 1 minute. Any creature that failed the save and is completely within the area is trapped inside this sphere. Creatures that succeeded on the save or are partially within the area are pushed away from the center of the sphere until they are no longer inside it. Only breathable air can pass through the sphere’s wall. No attack or other effect can pass through.

An enclosed creature can take a Utilize action to push against the sphere’s wall, moving the sphere up to half the creature’s Speed. The sphere can be picked up, and its magic causes it to weigh only 1 pound, regardless of the weight of creatures inside.', FALSE, ARRAY['consumable', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Belt of Giant Strength', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While wearing this belt, your Strength changes to a score granted by the belt. The type of giant determines the score (see the table below). The item has no effect on you if your Strength without the belt is equal to or greater than the belt’s score.', FALSE, ARRAY['attuned', 'legendary', 'rare', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Berserker Axe', 'Weapon (Battleaxe', 'Rare', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon. In addition, while you are attuned to this weapon, your Hit Point maximum increases by 1 for each level you have attained.

Curse. This weapon is cursed, and becoming attuned to it extends the curse to you. As long as you remain cursed, you are unwilling to part with the weapon, keeping it within reach at all times. You also have Disadvantage on attack rolls with weapons other than this one.

Whenever another creature damages you while the weapon is in your possession, you must succeed on a DC 15 Wisdom saving throw or go berserk. This berserk state ends when you start your turn and there are no creatures within 60 feet of you that you can see or hear.

While berserk, you regard the creature nearest to you that you can see or hear as your enemy. If there are multiple possible creatures, choose one at random. On each of your turns, you must move as close to the creature as possible and take the Attack action, targeting the creature. If you’re unable to get close enough to the creature to attack it with the weapon, your turn ends after you’ve used up all your available movement. If the creature dies or can no longer be seen or heard by you, the next nearest creature that you can see or hear becomes your new target.', FALSE, ARRAY['attuned', 'cursed', 'rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Boots of Levitation', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While you wear these boots, you can cast Levitate on yourself.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Boots of Speed', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While you wear these boots, you can take a Bonus Action to click the boots’ heels together. If you do, the boots double your Speed, and any creature that makes an Opportunity Attack against you has Disadvantage on the attack roll. If you click your heels together again, you end the effect.

When you’ve used the boots’ property for a total of 10 minutes, the magic ceases to function for you until you finish a Long Rest.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bowl of Commanding Water Elementals', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While this bowl is filled with water and you are within 5 feet of it, you can take a Magic action to summon a Water Elemental. The elemental appears in an unoccupied space as close to the bowl as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The bowl can’t be used this way again until the next dawn.

The bowl is about 1 foot in diameter and half as deep. It holds about 3 gallons.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bracers of Defense', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While wearing these bracers, you gain a +2 bonus to Armor Class if you are wearing no armor and using no Shield.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Brooch of the Elements', 'Wondrous Item', 'Rare', 'No', 'Varies', 'The central jewel of this butterfly-shaped brooch swirls with multicolored iridescence.

The brooch has 3 charges and regains all expended charges daily at dawn. As a Reaction when a creature you can see within 60 feet of you hits a target with an attack roll and deals damage, you can expend 1 charge and change one damage type the attack deals to one of the following damage types: Acid, Cold, Fire, Lightning, Poison, or Thunder.', FALSE, ARRAY['attuned', 'nf', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Brazier of Commanding Fire Elementals', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While you are within 5 feet of this brazier, you can take a Magic action to summon a Fire Elemental. The elemental appears in an unoccupied space as close to the brazier as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The brazier can’t be used this way again until the next dawn.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cape of the Mountebank', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This cape smells faintly of brimstone. While wearing it, you can use it to cast Dimension Door as a Magic action. This property can’t be used again until the next dawn.

When you teleport with that spell, you leave behind a cloud of smoke. The space you left is Lightly Obscured by that smoke until the end of your next turn.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Censer of Controlling Air Elementals', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While gently swinging this censer, you can take a Magic action to summon an Air Elemental. The elemental appears in an unoccupied space as close to the censer as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The censer can’t be used this way again until the next dawn.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of Displacement', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While you wear this cloak, it magically projects an illusion that makes you appear to be standing in a place near your actual location, causing any creature to have Disadvantage on attack rolls against you. If you take damage, the property ceases to function until the start of your next turn. This property is suppressed while your Speed is 0.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Chime of Opening', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This hollow metal tube measures about 1 foot long and weighs 1 pound. As a Magic action, you can strike the chime to cast Knock. The spell’s customary knocking sound is replaced by the clear, ringing tone of the chime, which is audible out to 300 feet.

The chime can be used 10 times. After the tenth time, it cracks and becomes useless.', FALSE, ARRAY['consumable', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of the Bat', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While wearing this cloak, you have Advantage on Dexterity (Stealth) checks. In an area of Dim Light or Darkness, you can grip the edges of the cloak and use it to gain a Fly Speed of 40 feet. If you ever fail to grip the cloak’s edges while flying in this way, or if you are no longer in Dim Light or Darkness, you lose this Fly Speed.

While wearing the cloak in an area of Dim Light or Darkness, you can cast Polymorph on yourself, shape-shifting into a Bat. While in that form, you retain your Intelligence, Wisdom, and Charisma scores. The cloak can’t be used this way again until the next dawn.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cube of Force', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This cube is about an inch across. Each face has a distinct marking on it. You can press one of those faces, expend the number of charges required for it, and thereby cast the spell associated with it (save DC 17), as shown in the Cube of Force Faces table.

The cube starts with 10 charges, and it regains 1d6 expended charges daily at dawn.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cube of Summoning', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This Tiny cube looks like a jack-in-the-box. When you wind its crank as a Magic action, a merry tune emits from the box, the lid pops open, a creature appears in the nearest unoccupied space, and the lid closes. The lid can’t otherwise be opened.

Roll on the Cube of Summoning table to determine which spell the cube casts to summon the creature. The spell is cast at level 5 (save DC 17, +9 attack bonus) and doesn’t require Concentration, but you otherwise function as the spell’s caster.

Once the cube summons a creature, the cube can’t do so again until the next dawn.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dagger of Venom', 'Weapon (Dagger)', 'Rare', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon.

You can take a Bonus Action to magically coat the blade with poison. The poison remains for 1 minute or until an attack using this weapon hits a creature. That creature must succeed on a DC 15 Constitution saving throw or take 2d10 Poison damage and have the Poisoned condition for 1 minute. The weapon can’t be used this way again until the next dawn.', FALSE, ARRAY['rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Daern''s Instant Fortress', 'Wondrous Item', 'Rare', 'No', 'Varies', 'As a Magic action, you can place this 1-inch adamantine statuette on the ground and, using a command word, cause it to grow rapidly into a square adamantine tower. Repeating the command word causes the tower to revert to statuette form, which works only if the tower is empty. Each creature in the area where the tower appears is pushed to an unoccupied space outside but next to the tower. Objects in the area that aren’t being worn or carried are also pushed clear of the tower.

The tower is 20 feet on a side and 30 feet high, with arrow slits on all sides and a battlement atop it. Its interior is divided into two floors, with a ladder, staircase, or ramp (your choice) connecting them. This ladder, staircase, or ramp ends at a trapdoor leading to the roof. When created, the tower has a single door at ground level on the side facing you. The door opens only at your command, which you can issue as a Bonus Action. It is immune to the Knock spell and similar magic.

Magic prevents the tower from being tipped over. The roof, the door, and the walls each have AC 20; HP 100; Immunity to Bludgeoning, Piercing, and Slashing damage except that which is dealt by siege equipment; and Resistance to all other damage. Shrinking the tower back down to statuette form doesn’t repair damage to the tower. Only a Wish spell can repair the tower (this use of the spell counts as replicating a spell of level 8 or lower). Each casting of Wish causes the tower to regain all its Hit Points.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dazzling Weapon', 'Weapon (Any Simple or Martial)', 'Rare', 'No', 'Varies', 'This magic weapon grants a +1 bonus to attack and damage rolls made with it. While holding it, you can take a Bonus Action to cause it to shed Bright Light in a 30-foot radius and Dim Light for an additional 30 feet. You can extinguish the light as a Bonus Action.

The weapon has 4 charges. You can take a Reaction immediately after being hit by an attack roll to expend 1 of the weapon’s charges and force the attacker to make a DC 15 Constitution saving throw. On a failed save, the attacker has the Blinded condition until the end of its next turn. The weapon regains 1d4 expended charges daily at dawn.', FALSE, ARRAY['attuned', 'efota', 'rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dimensional Shackles', 'Wondrous Item', 'Rare', 'No', 'Varies', 'You can take a Utilize action to place these shackles on a creature that has the Incapacitated condition. The shackles adjust to fit a creature of Small to Large size. The shackles prevent a creature bound by them from using any method of extradimensional movement, including teleportation or travel to a different plane of existence. They don’t prevent the creature from passing through an interdimensional portal.

You and any creature you designate when you use the shackles can take a Utilize action to remove them. Once every 30 days, the bound creature can make a DC 30 Strength (Athletics) check. On a successful check, the creature breaks free and destroys the shackles.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dragon Slayer', 'Weapon (Any Simple or Martial)', 'Rare', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon.

The weapon deals an extra 3d6 damage of the weapon’s type if the target is a Dragon.', FALSE, ARRAY['rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Elixir of Health', 'Potion', 'Rare', 'No', 'Varies', 'When you drink this potion, you are cured of all magical contagions. In addition, the following conditions end on you: Blinded, Deafened, Paralyzed, and Poisoned.

The clear, red liquid has tiny bubbles of light in it.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Elven Chain', 'Armor (Chain Mail or Chain Shirt)', 'Rare', 'No', 'Varies', 'You gain a +1 bonus to Armor Class while you wear this armor. You are considered trained with this armor even if you lack training with Medium or Heavy armor.', FALSE, ARRAY['armor', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Flame Tongue', 'Weapon (Any Melee Weapon)', 'Rare', 'No', 'Varies', 'While holding this magic weapon, you can take a Bonus Action and use a command word to cause flames to engulf the damage-dealing part of the weapon. These flames shed Bright Light in a 40-foot radius and Dim Light for an additional 40 feet. While the weapon is ablaze, it deals an extra 2d6 Fire damage on a hit. The flames last until you take a Bonus Action to issue the command again or until you drop, stow, or sheathe the weapon.', FALSE, ARRAY['attuned', 'rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Folding Boat', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This object appears as a wooden box that measures 12 inches long, 6 inches wide, and 6 inches deep. It weighs 4 pounds and floats. It can be opened to store items inside. This item also has three command words, each requiring a Magic action to use:

First Command Word. The box unfolds into a Rowboat.

Second Command Word. The box unfolds into a Keelboat.

Third Command Word. The Folding Boat folds back into a box if no creatures are aboard. Any objects in the vessel that can’t fit inside the box remain outside the box as it folds. Any objects in the vessel that can fit inside the box do so.

When the box becomes a vessel, its weight becomes that of a normal vessel its size, and anything that was stored in the box remains in the boat.

Statistics for the Rowboat and Keelboat appear in the Player’s Handbook. If either vessel is reduced to 0 Hit Points, the Folding Boat is destroyed.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Fork of Eddy Summoning', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This Tiny tuning fork crackles with harmless, multicolored magical energy. As a Magic action, you can tap the fork against any object to summon an Eldritch Eddy (see Netheril''s Fall). The eddy appears in an unoccupied space as close to you as possible. The eddy is Friendly to you and your allies, and it obeys your commands. If you fail to command it, the eddy defends itself against attackers but takes no other actions. It takes its turn immediately after you on your Initiative count. The eddy disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The fork can’t be used this way again until the next dawn.', FALSE, ARRAY['nf', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Gem of Seeing', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This gem has 3 charges. As a Magic action, you can expend 1 charge. For the next 10 minutes, you have Truesight out to 120 feet when you peer through the gem.

The gem regains 1d3 expended charges daily at dawn.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Glamoured Studded Leather', 'Armor (Studded Leather Armor)', 'Rare', 'No', 'Varies', 'While wearing this armor, you gain a +1 bonus to Armor Class. You can also take a Bonus Action to cause the armor to assume the appearance of a normal set of clothing or some other kind of armor. You decide what it looks like—including color, style, and accessories—but the armor retains its normal bulk and weight. The illusory appearance lasts until you use this property again or doff the armor.', FALSE, ARRAY['armor', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Giant Slayer', 'Weapon (Any Simple or Martial)', 'Rare', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon.

When you hit a Giant with this weapon, the Giant takes an extra 2d6 damage of the weapon’s type and must succeed on a DC 15 Strength saving throw or have the Prone condition.', FALSE, ARRAY['rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Heward''s Handy Haversack', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This backpack has a central pouch and two side pouches, each of which is an extradimensional space. Each side pouch can hold up to 200 pounds of material, not exceeding a volume of 25 cubic feet. The central pouch can hold up to 500 pounds of material, not exceeding a volume of 64 cubic feet. The haversack always weighs 5 pounds, regardless of its contents.

Retrieving an item from the haversack requires a Utilize action or a Bonus Action (your choice). When you reach into the haversack for a specific item, the item is always magically on top.

If any of its pouches is overloaded, pierced, or torn, the haversack ruptures and is destroyed. If the haversack is destroyed, its contents are lost forever, although an Artifact always turns up again somewhere. If the haversack is turned inside out, its contents spill forth unharmed, and the haversack must be put right before it can be used again.

Each pouch of the haversack holds enough air for 10 minutes of breathing, divided by the number of breathing creatures inside.

Placing the haversack inside an extradimensional space created by a Bag of Holding, Portable Hole, or similar item instantly destroys both items and opens a gate to the Astral Plane. The gate originates where the one item was placed inside the other. Any creature within 10 feet of the gate and not behind Total Cover is sucked through it and deposited in a random location on the Astral Plane. The gate then closes. The gate is one-way only and can’t be reopened.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Horn of Blasting', 'Wondrous Item', 'Rare', 'No', 'Varies', 'You can take a Magic action to blow the horn, which emits a thunderous blast in a 30-foot Cone that is audible out to 600 feet. Each creature in the Cone makes a DC 15 Constitution saving throw. On a failed save, a creature takes 5d8 Thunder damage and has the Deafened condition for 1 minute. On a successful save, a creature takes half as much damage only. Glass or crystal objects in the Cone that aren’t being worn or carried take 10d8 Thunder damage.

Each use of the horn’s magic has a 20 percent chance of causing the horn to explode. The explosion deals 10d6 Force damage to the user and destroys the horn.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Helm of Teleportation', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This helm has 3 charges. While wearing it, you can expend 1 charge to cast Teleport from it. The helm regains 1d3 expended charges daily at dawn.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ioun Stone', 'Wondrous Item', 'Rare', 'No', 'Varies', 'Roughly marble sized, Ioun Stones are named after Ioun, a god of knowledge and prophecy revered on some worlds. Many types of Ioun Stones exist, each type a distinct combination of shape and color.

When you take a Magic action to toss an Ioun Stone into the air, the stone orbits your head at a distance of 1d3 feet, conferring its benefit to you while doing so. You can have up to three Ioun Stones orbiting your head at the same time.

Each Ioun Stone orbiting your head is considered to be an object you are wearing. The orbiting stone avoids contact with other creatures and objects, adjusting its orbit to avoid collisions and thwarting all attempts by other creatures to attack or snatch it.

As a Utilize action, you can seize and stow any number of Ioun Stones orbiting your head. If your Attunement to an Ioun Stone ends while it’s orbiting your head, the stone falls as though you had dropped it.

The type of stone determines its rarity and effects.

Absorption (Very Rare) While this pale lavender ellipsoid orbits your head, you can take a Reaction to cancel a spell of level 4 or lower cast by a creature you can see. A canceled spell has no effect, and any resources used to cast it are wasted. Once the stone has canceled 20 levels of spells, it burns out, turns dull gray, and loses its magic.

Agility (Very Rare) Your Dexterity increases by 2, to a maximum of 20, while this deep-red sphere orbits your head.

Awareness (Rare) While this dark-blue rhomboid orbits your head, you have Advantage on Initiative rolls and Wisdom (Perception) checks.

Fortitude (Very Rare) Your Constitution increases by 2, to a maximum of 20, while this pink rhomboid orbits your head.

Greater Absorption (Legendary) While this marbled lavender and green ellipsoid orbits your head, you can take a Reaction to cancel a spell of level 8 or lower cast by a creature you can see. A canceled spell has no effect, and any resources used to cast it are wasted. Once the stone has canceled 20 levels of spells, it burns out, turns dull gray, and loses its magic.

Insight (Very Rare) Your Wisdom increases by 2, to a maximum of 20, while this incandescent blue sphere orbits your head.

Intellect (Very Rare) Your Intelligence increases by 2, to a maximum of 20, while this marbled scarlet and blue sphere orbits your head.

Leadership (Very Rare) Your Charisma increases by 2, to a maximum of 20, while this marbled pink and green sphere orbits your head.

Mastery (Legendary) Your Proficiency Bonus increases by 1 while this pale green prism orbits your head.

Protection (Rare) You gain a +1 bonus to Armor Class while this dusty-rose prism orbits your head.

Regeneration (Legendary) You regain 15 Hit Points at the end of each hour this pearly white spindle orbits your head if you have at least 1 Hit Point.

Reserve (Rare) This vibrant purple prism stores spells cast into it, holding them until you use them. The stone can store up to 4 levels of spells at a time. When found, it contains 1d4 levels of stored spells chosen by the DM.

Any creature can cast a spell of level 1 through 4 into the stone by touching it as the spell is cast. The spell has no effect, other than to be stored in the stone. If the stone can’t hold the spell, the spell is expended without effect. The level of the slot used to cast the spell determines how much space it uses.

While this stone orbits your head, you can cast any spell stored in it. The spell uses the slot level, spell save DC, spell attack bonus, and spellcasting ability of the original caster but is otherwise treated as if you cast the spell. The spell cast from the stone is no longer stored in it, freeing up space.

Strength (Very Rare) Your Strength increases by 2, to a maximum of 20, while this pale blue rhomboid orbits your head.

Sustenance (Rare) You don’t need to eat or drink while this clear spindle orbits your head.', FALSE, ARRAY['attuned', 'consumable', 'legendary', 'rare', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Horseshoes of Speed', 'Wondrous Item', 'Rare', 'No', 'Varies', 'These horseshoes come in a set of four. As a Magic action, you can touch one of the horseshoes to the hoof of a horse or similar creature, whereupon the horseshoe affixes itself to the hoof. Removing a horseshoe also takes a Magic action.

While all four horseshoes are attached to the same creature, its Speed is increased by 30 feet.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Iron Bands of Bilarro', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This rusty iron sphere measures 3 inches in diameter and weighs 1 pound. You can take a Magic action to throw the sphere at a Huge or smaller creature you can see within 60 feet of yourself. As the sphere moves through the air, it opens into a tangle of metal bands.

Make a ranged attack roll with an attack bonus equal to your Dexterity modifier plus your Proficiency Bonus. On a hit, the target has the Restrained condition until you take a Bonus Action to issue a command that releases it. Doing so or missing with the attack causes the bands to contract and become a sphere once more.

A creature that can touch the bands, including the one Restrained, can take an action to make a DC 20 Strength (Athletics) check to break the iron bands. On a successful check, the item is destroyed, and the Restrained creature is freed. On a failed check, any further attempts made by that creature automatically fail until 24 hours have elapsed.

Once the bands are used, they can’t be used again until the next dawn.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mace of Smiting', 'Weapon (Mace)', 'Rare', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon. The bonus increases to +3 when you use the weapon to attack a Construct.

When you roll a 20 on an attack roll made with this weapon, the target takes an extra 7 Bludgeoning damage, or 14 Bludgeoning damage if it’s a Construct. If a Construct has 25 Hit Points or fewer after taking this damage, it is destroyed.', FALSE, ARRAY['rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mace of Disruption', 'Weapon (Mace)', 'Rare', 'No', 'Varies', 'When you hit a Fiend or an Undead with this magic weapon, that creature takes an extra 2d6 Radiant damage. If the target has 25 Hit Points or fewer after taking this damage, it must succeed on a DC 15 Wisdom saving throw or be destroyed. On a successful save, the creature has the Frightened condition until the end of your next turn.

Light. While you hold this weapon, it sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet.', FALSE, ARRAY['attuned', 'rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mace of Terror', 'Weapon (Mace)', 'Rare', 'No', 'Varies', 'This magic weapon has 3 charges and regains 1d3 expended charges daily at dawn. While holding the weapon, you can take a Magic action and expend 1 charge to release a wave of terror from it. Each creature of your choice within 30 feet of you must succeed on a DC 15 Wisdom saving throw or have the Frightened condition for 1 minute. While Frightened in this way, a creature must spend its turns trying to move as far away from you as it can, and it can’t make Opportunity Attacks. For its action, it can use only the Dash action or try to escape from an effect that prevents it from moving. If it has nowhere it can move, the creature can take the Dodge action. At the end of each of its turns, a creature repeats the save, ending the effect on itself on a success.', FALSE, ARRAY['attuned', 'rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Magen Handbell', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While holding this brass handbell, you can take a Magic action to ring it and summon a Terran Magen (see Netheril''s Fall). The magen appears in an unoccupied space you choose within 30 feet of yourself, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The magen disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The bell can’t be used this way again for 1d6 days.

Berserk Magen. Whenever the magen summoned by this item starts its turn Bloodied, roll 1d6. On a 6, the magen goes berserk.

While berserk, the magen no longer obeys your commands, and you can’t dismiss it as a Bonus Action. On each of its turns, the berserk magen attacks the nearest creature it can see. If no creature is near enough for the magen to move to and attack, the magen attacks an object. The magen remains berserk until it disappears, or until a creature holding the handbell takes an Influence action and succeeds on a DC 15 Charisma (Persuasion) check to regain control of the magen.', FALSE, ARRAY['nf', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mantle of Spell Resistance', 'Wondrous Item', 'Rare', 'No', 'Varies', 'You have Advantage on saving throws against spells while you wear this cloak.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Necklace of Prayer Beads', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This necklace has 1d4 + 2 magic beads made from aquamarine, black pearl, or topaz. It also has many nonmagical beads made from stones such as amber, bloodstone, citrine, coral, jade, pearl, or quartz. If a magic bead is removed from the necklace, that bead loses its magic.

Six types of magic beads exist. The DM decides the type of each bead on the necklace or determines it randomly by rolling on the table below. A necklace can have more than one bead of the same type. To use one, you must be wearing the necklace. Each bead contains a spell that you can cast from it as a Bonus Action (using your spell save DC if a save is necessary). Once a magic bead’s spell is cast, that bead can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'consumable', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Portable Hole', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This fine black cloth, soft as silk, is folded up to the dimensions of a handkerchief. It unfolds into a circular sheet 6 feet in diameter.

You can take a Magic action to unfold a Portable Hole and place it on or against a solid surface, whereupon the Portable Hole creates an extradimensional hole 10 feet deep. The cylindrical space within the hole exists on a different plane of existence, so it can’t be used to create open passages. Any creature inside an open Portable Hole can exit the hole by climbing out of it.

You can take a Magic action to close a Portable Hole by taking hold of the edges of the cloth and folding it up. Folding the cloth closes the hole, and any creatures or objects within remain in the extradimensional space. No matter what’s in it, the hole weighs next to nothing.

If the hole is folded up, a creature within the hole’s extradimensional space can take an action to make a DC 10 Strength (Athletics) check. On a successful check, the creature forces its way out and appears within 5 feet of the Portable Hole. A closed Portable Hole holds enough air for 1 hour of breathing, divided by the number of breathing creatures inside.

Placing a Portable Hole inside an extradimensional space created by a Bag of Holding, Heward’s Handy Haversack, or similar item instantly destroys both items and opens a gate to the Astral Plane. The gate originates where the one item was placed inside the other. Any creature within 10 feet of the gate and not behind Total Cover is sucked through it and deposited in a random location on the Astral Plane. The gate then closes. The gate is one-way only and can’t be reopened.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Periapt of Proof against Poison', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This delicate silver chain has a brilliant-cut black gem pendant. While you wear it, you have Immunity to the Poisoned condition and Poison damage.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Oil of Etherealness', 'Potion', 'Rare', 'No', 'Varies', 'One vial of this oil can cover one Medium or smaller creature, along with the equipment it’s wearing and carrying (one additional vial is required for each size category above Medium). Applying the oil takes 10 minutes. The affected creature then gains the effect of the Etherealness spell for 1 hour.

Beads of this cloudy, gray oil form on the outside of its container and quickly evaporate.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Diminution', 'Potion', 'Rare', 'No', 'Varies', 'When you drink this potion, you gain the “reduce” effect of the Enlarge/Reduce spell for 1d4 hours (no Concentration required).

The red in the potion’s liquid continuously contracts to a tiny bead and then expands to color the clear liquid around it. Shaking the bottle fails to interrupt this process.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Clairvoyance', 'Potion', 'Rare', 'No', 'Varies', 'When you drink this potion, you gain the effect of the Clairvoyance spell (no Concentration required).

An eyeball bobs in this potion’s yellowish liquid but vanishes when the potion is opened.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Heroism', 'Potion', 'Rare', 'No', 'Varies', 'When you drink this potion, you gain 10 Temporary Hit Points that last for 1 hour. For the same duration, you are under the effect of the Bless spell (no Concentration required).

This potion’s blue liquid bubbles and steams as if boiling.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Gaseous Form', 'Potion', 'Rare', 'No', 'Varies', 'When you drink this potion, you gain the effect of the Gaseous Form spell for 1 hour (no Concentration required) or until you end the effect as a Bonus Action.

This potion’s container seems to hold fog that moves and pours like water.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Invisibility', 'Potion', 'Rare', 'No', 'Varies', 'This potion’s container looks empty but feels as though it holds liquid. When you drink the potion, you have the Invisible condition for 1 hour. The effect ends early if you make an attack roll, deal damage, or cast a spell.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Mind Reading', 'Potion', 'Rare', 'No', 'Varies', 'When you drink this potion, you gain the effect of the Detect Thoughts spell (save DC 13) for 10 minutes (no Concentration required).

This potion’s dense, purple liquid has an ovoid cloud of pink floating in it.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Invulnerability', 'Potion', 'Rare', 'No', 'Varies', 'For 1 minute after you drink this potion, you have Resistance to all damage.

This potion’s syrupy liquid looks like liquefied iron.', FALSE, ARRAY['consumable', 'potion', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Animal Influence', 'Ring', 'Rare', 'No', 'Varies', 'This ring has 3 charges, and it regains 1d3 expended charges daily at dawn. While wearing the ring, you can expend 1 charge to cast one of the following spells (save DC 13) from it:', FALSE, ARRAY['rare', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Free Action', 'Ring', 'Rare', 'No', 'Varies', 'While you wear this ring, Difficult Terrain doesn’t cost you extra movement. In addition, magic can neither reduce any of your Speeds nor cause you to have the Paralyzed or Restrained condition.', FALSE, ARRAY['attuned', 'rare', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Evasion', 'Ring', 'Rare', 'No', 'Varies', 'This ring has 3 charges, and it regains 1d3 expended charges daily at dawn. When you fail a Dexterity saving throw while wearing the ring, you can take a Reaction to expend 1 charge to succeed on that save instead.', FALSE, ARRAY['attuned', 'rare', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Protection', 'Ring', 'Rare', 'No', 'Varies', 'You gain a +1 bonus to Armor Class and saving throws while wearing this ring.', FALSE, ARRAY['attuned', 'rare', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Spell Storing', 'Ring', 'Rare', 'No', 'Varies', 'This ring stores spells cast into it, holding them until the attuned wearer uses them. The ring can store up to 5 levels worth of spells at a time. When found, it contains 1d6 − 1 levels of stored spells chosen by the DM.

Any creature can cast a spell of level 1 through 5 into the ring by touching the ring as the spell is cast. The spell has no effect other than to be stored in the ring. If the ring can’t hold the spell, the spell is expended without effect. The level of the slot used to cast the spell determines how much space it uses.

While wearing this ring, you can cast any spell stored in it. The spell uses the slot level, spell save DC, spell attack bonus, and spellcasting ability of the original caster but is otherwise treated as if you cast the spell. The spell cast from the ring is no longer stored in it, freeing up space.', FALSE, ARRAY['attuned', 'rare', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Resistance', 'Ring', 'Rare', 'No', 'Varies', 'You have Resistance to one damage type while wearing this ring. The gemstone in the ring indicates the type, which the DM chooses or determines randomly by rolling on the following table.', FALSE, ARRAY['rare', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of the Ram', 'Ring', 'Rare', 'No', 'Varies', 'This ring has 3 charges and regains 1d3 expended charges daily at dawn. While wearing the ring, you can take a Magic action to expend 1 to 3 charges to make a ranged spell attack against one creature you can see within 60 feet of yourself. The ring produces a spectral ram’s head and makes its attack roll with a +7 bonus. On a hit, for each charge you spend, the target takes 2d10 Force damage and is pushed 5 feet away from you.

Alternatively, you can expend 1 to 3 of the ring’s charges as a Magic action to try to break a nonmagical object you can see within 60 feet of yourself that isn’t being worn or carried. The ring makes a Strength check with a +5 bonus for each charge you spend.', FALSE, ARRAY['attuned', 'rare', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of X-ray Vision', 'Ring', 'Rare', 'No', 'Varies', 'While wearing this ring, you can take a Magic action to gain X-ray vision with a range of 30 feet for 1 minute. To you, solid objects within that radius appear transparent and don’t prevent light from passing through them. The vision can penetrate 1 foot of stone, 1 inch of common metal, or up to 3 feet of wood or dirt. Thicker substances or a thin sheet of lead block the vision.

Whenever you use the ring again before taking a Long Rest, you must succeed on a DC 15 Constitution saving throw or gain 1 Exhaustion level.', FALSE, ARRAY['attuned', 'rare', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Robe of Eyes', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This robe is adorned with eyelike patterns. While you wear the robe, you gain the following benefits:

All-Around Vision. The robe gives you Advantage on Wisdom (Perception) checks that rely on sight.

Special Senses. You have Darkvision and Truesight, both with a range of 120 feet.

Drawbacks. A Light spell cast on the robe or a Daylight spell cast within 5 feet of the robe gives you the Blinded condition for 1 minute. At the end of each of your turns, you make a Constitution saving throw (DC 11 for Light or DC 15 for Daylight), ending the condition on yourself on a success.', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rod of Rulership', 'Wondrous Item', 'Rare', 'No', 'Varies', 'Rod, Rare (Requires Attunement)

You can take a Magic action to present the rod and command obedience from each creature of your choice that you can see within 120 feet of yourself. Each target must succeed on a DC 15 Wisdom saving throw or have the Charmed condition for 8 hours. While Charmed in this way, the creature regards you as its trusted leader. If harmed by you or your allies or commanded to do something contrary to its nature, a target ceases to be Charmed in this way. Once used, this property can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'rare', 'rod']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rope of Entanglement', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This rope is 30 feet long. While holding one end of the rope, you can take a Magic action to command the other end to dart forward and entangle one creature you can see within 20 feet of yourself. The target must succeed on a DC 15 Dexterity saving throw or have the Restrained condition. You can release the target by letting go of your end of the rope (causing the rope to coil up in the target’s space) or by using a Bonus Action to repeat the command (causing the rope to coil up in your hand).

A target Restrained by the rope can take an action to make its choice of a DC 15 Strength (Athletics) or Dexterity (Acrobatics) check. On a successful check, the target is no longer Restrained by the rope. If you’re still holding onto the rope when a target escapes from it, you can take a Reaction to command the rope to coil up in your hand; otherwise, the rope coils up in the target’s space.

The rope has AC 20, HP 20, and Immunity to Poison and Psychic damage. It regains 1 Hit Point every 5 minutes as long as it has at least 1 Hit Point. If the rope drops to 0 Hit Points, it is destroyed.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Salubrious Armor', 'Armor (Plate Armor or Scale Mail)', 'Rare', 'No', 'Varies', 'Whenever you regain Hit Points while wearing this armor, it takes on a reddish tint and you gain a +1 bonus to Armor Class until the end of your next turn.', FALSE, ARRAY['armor', 'attuned', 'drops', 'drops0626', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Scroll of Protection', 'Each Scroll of Protection works against creatures of a specific creature type chosen by the DM or determined by rolling on the following table.', 'Rare', 'No', 'Varies', 'Using a Magic action to read the scroll creates a 5-foot Emanation originating from you. For 5 minutes, creatures of the specified type can’t enter or affect anything in the area. However, if you move in such a way that a creature of the specified type would be inside the area, the effect ends.

As a Magic action, a creature within 5 feet of the Emanation can attempt to overcome it, which forces the creature to make a DC 15 Charisma saving throw. On a successful save, the creature ceases to be affected by the Emanation.', FALSE, ARRAY['consumable', 'rare', 'scroll']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Shield of Missile Attraction', 'Armor (Shield)', 'Rare', 'No', 'Varies', 'While holding this Shield, you have Resistance to damage from attacks made with Ranged weapons.

Curse. This Shield is cursed. Attuning to it curses you until you are targeted by a Remove Curse spell or similar magic. Removing the Shield fails to end the curse on you. Whenever an attack with a Ranged weapon targets a creature within 10 feet of you, the curse causes you to become the target instead.', FALSE, ARRAY['armor', 'attuned', 'cursed', 'rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Healing', 'Staff', 'Rare', 'No', 'Varies', 'This staff has 10 charges. While holding the staff, you can cast one of the spells on the following table from it, using your spellcasting ability modifier. The table indicates how many charges you must expend to cast the spell.

Regaining Charges. The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff vanishes in a flash of light, lost forever.', FALSE, ARRAY['attuned', 'rare', 'staff']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Charming', 'Staff', 'Rare', 'No', 'Varies', 'This staff has 10 charges. While holding the staff, you can use any of its properties:

Cast Spell. You can expend 1 of the staff’s charges to cast Charm Person, Command, or Comprehend Languages from it using your spell save DC.

Reflect Enchantment. If you succeed on a saving throw against an Enchantment spell that targets only you, you can take a Reaction to expend 1 charge from the staff and turn the spell back on its caster as if you had cast the spell.

Resist Enchantment. If you fail a saving throw against an Enchantment spell that targets only you, you can turn your failed save into a successful one. You can’t use this property of the staff again until the next dawn.

Regaining Charges. The staff regains 1d8 + 2 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff crumbles to dust and is destroyed.', FALSE, ARRAY['attuned', 'rare', 'staff']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of the Woodlands', 'Staff', 'Rare', 'No', 'Varies', 'This staff has 6 charges and can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. While holding it, you have a +2 bonus to spell attack rolls.

Spells. While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

Tree Form. You can take a Magic action to plant one end of the staff in earth in an unoccupied space and expend 1 charge to transform the staff into a healthy tree. The tree is 60 feet tall and has a 5-foot-diameter trunk, and its branches at the top spread out in a 20-foot radius. The tree appears ordinary but radiates a faint aura of Transmutation magic that can be discerned with the Detect Magic spell. While touching the tree and using a Magic action, you return the staff to its normal form. Any creature in the tree falls when the tree reverts to a staff.

Regaining Charges. The staff regains 1d6 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff loses its properties and becomes a nonmagical Quarterstaff.', FALSE, ARRAY['attuned', 'rare', 'staff']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Swarming Insects', 'Staff', 'Rare', 'No', 'Varies', 'This staff has 10 charges.

Insect Cloud. While holding the staff, you can take a Magic action and expend 1 charge to cause a swarm of harmless flying insects to fill a 30-foot Emanation originating from you. The insects remain for 10 minutes, making the area Heavily Obscured for creatures other than you. A strong wind (like that created by Gust of Wind) disperses the swarm and ends the effect.

Spells. While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC and spell attack modifier. The table indicates how many charges you must expend to cast the spell.

Regaining Charges. The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, a swarm of insects consumes and destroys the staff, then disperses.', FALSE, ARRAY['attuned', 'rare', 'staff']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Withering', 'Staff', 'Rare', 'No', 'Varies', 'This staff has 3 charges and regains 1d3 expended charges daily at dawn.

The staff can be wielded as a magic Quarterstaff. On a hit, it deals damage as a normal Quarterstaff, and you can expend 1 charge to deal an extra 2d10 Necrotic damage to the target and force it to make a DC 15 Constitution saving throw. On a failed save, the target has Disadvantage for 1 hour on any ability check or saving throw that uses Strength or Constitution.', FALSE, ARRAY['attuned', 'rare', 'staff']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sun Blade', 'Weapon (Longsword)', 'Rare', 'No', 'Varies', 'This item appears to be a sword hilt.

Blade of Radiance. While grasping the hilt, you can take a Bonus Action to cause a blade of pure radiance to spring into existence or make the blade disappear. While the blade exists, this magic weapon functions as a Longsword with the Finesse property. If you are proficient with Longswords or Shortswords, you are proficient with the Sun Blade.

You gain a +2 bonus to attack rolls and damage rolls made with this weapon, which deals Radiant damage instead of Slashing damage. When you hit an Undead with it, that target takes an extra 1d8 Radiant damage.

Sunlight. The sword’s luminous blade emits Bright Light in a 15-foot radius and Dim Light for an additional 15 feet. The light is sunlight. While the blade persists, you can take a Magic action to expand or reduce its radius of Bright Light and Dim Light by 5 feet each, to a maximum of 30 feet each or a minimum of 10 feet each.', FALSE, ARRAY['attuned', 'rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Stone of Controlling Earth Elementals', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While touching this 5-pound stone to the ground, you can take a Magic action to summon an Earth Elemental. The elemental appears in an unoccupied space you choose within 30 feet of yourself, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The stone can’t be used this way again until the next dawn.', FALSE, ARRAY['rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sword of Life Stealing', 'Weapon (Glaive', 'Rare', 'No', 'Varies', 'When you attack a creature with this magic weapon and roll a 20 on the d20 for the attack roll, that target takes an extra 15 Necrotic damage if it isn’t a Construct or an Undead, and you gain Temporary Hit Points equal to the amount of Necrotic damage taken.', FALSE, ARRAY['attuned', 'rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sword of Wounding', 'Weapon (Glaive', 'Rare', 'No', 'Varies', 'When you hit a creature with an attack using this magic weapon, the target takes an extra 2d6 Necrotic damage and must succeed on a DC 15 Constitution saving throw or be unable to regain Hit Points for 1 hour. The target repeats the save at the end of each of its turns, ending the effect on itself on a success.', FALSE, ARRAY['attuned', 'rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Vicious Weapon', 'Weapon (Any Simple or Martial)', 'Rare', 'No', 'Varies', 'This magic weapon deals an extra 2d6 damage to any creature it hits. This extra damage is of the same type as the weapon’s normal damage.', FALSE, ARRAY['rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Tentacle Rod', 'Wondrous Item', 'Rare', 'No', 'Varies', 'Rod, Rare (Requires Attunement)

This rod ends in three rubbery tentacles. While holding the rod, you can take a Magic action to direct the tentacles to stretch outward, each one attacking a creature you can see within 15 feet of yourself. For each tentacle, make a melee attack roll with a +9 bonus. A tentacle deals 1d6 Psychic damage on a hit. If you hit the same target with all three tentacles, the target must succeed on a DC 15 Dexterity saving throw or have the Restrained condition until you have the Incapacitated condition, until you take a Bonus Action to release the target, or until the target is no longer within 15 feet of you. While Restrained in this way, the target takes 3d6 Psychic damage at the start of each of its turns. At the end of each of its turns, the target repeats the save, ending the effect on itself on a success.', FALSE, ARRAY['attuned', 'rare', 'rod']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Binding', 'Wand', 'Rare', 'No', 'Varies', 'This wand has 7 charges.

Spells. While holding the wand, you can cast one of the spells (save DC 17) on the following table from it. The table indicates how many charges you must expend to cast the spell.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', FALSE, ARRAY['attuned', 'rare', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Enemy Detection', 'Wand', 'Rare', 'No', 'Varies', 'This wand has 7 charges. While holding it, you can take a Magic action to expend 1 charge. For 1 minute, you know the direction of the nearest creature Hostile to you within 60 feet, but not its distance from you. The wand can sense the presence of Hostile creatures that are Invisible, ethereal, disguised, or hidden, as well as those in plain sight. The effect ends if you stop holding the wand.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', FALSE, ARRAY['attuned', 'rare', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Fear', 'Wand', 'Rare', 'No', 'Varies', 'This wand has 7 charges.

Spells. While holding the wand, you can cast one of the spells (save DC 15) on the following table from it. The table indicates how many charges you must expend to cast the spell.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', FALSE, ARRAY['attuned', 'rare', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Lightning Bolts', 'Wand', 'Rare', 'No', 'Varies', 'This wand has 7 charges. While holding it, you can expend no more than 3 charges to cast Lightning Bolt (save DC 15) from it. For 1 charge, you cast the level 3 version of the spell. You can increase the spell’s level by 1 for each additional charge you expend.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', FALSE, ARRAY['attuned', 'rare', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Paralysis', 'Wand', 'Rare', 'No', 'Varies', 'This wand has 7 charges. While holding it, you can take a Magic action to expend 1 charge to cause a thin blue ray to streak from the tip toward a creature you can see within 60 feet of yourself. The target must succeed on a DC 15 Constitution saving throw or have the Paralyzed condition for 1 minute. At the end of each of the target’s turns, it repeats the save, ending the effect on itself on a success.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', FALSE, ARRAY['attuned', 'rare', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Wonder', 'Wand', 'Rare', 'No', 'Varies', 'This wand has 7 charges. While holding it, you can take a Magic action to expend 1 charge while choosing a point within 120 feet of yourself. That location becomes the point of origin of a spell or other magical effect determined by rolling on the Wand of Wonder Effects table. Spells cast from the wand have a save DC of 15. If a spell’s maximum range is normally less than 120 feet, it becomes 120 feet when cast from the wand. If an effect has multiple possible subjects, the DM determines randomly which among them are affected.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll 1d20. On a 1, the wand crumbles into dust and is destroyed.', FALSE, ARRAY['attuned', 'rare', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Windskiff', 'Wondrous Item', 'Rare', 'No', 'Varies', 'This small piece of jewelry has 3 charges and regains all expended charges daily at dawn. While you are holding it, you can take a Magic action to expend 1 charge, which causes the jewelry to transform into a sail-powered personal vehicle. The vehicle is roughly the size and shape of a household door with a 10-foot-tall sail extending from one side. After 1 hour or until you use the item’s command word (no action required), the transformation ends and the Windskiff reverts to its jewelry form.

In vehicle form, a Windskiff is a Medium object with the following statistics: AC 12, HP 30, and Speed 40 ft. The Windskiff hovers a few inches above whatever surface it’s on and can glide; it moves 5 feet horizontally for every 1 foot it descends in the air. A Windskiff and its riders take no damage from falling.', FALSE, ARRAY['frhof', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wings of Flying', 'Wondrous Item', 'Rare', 'No', 'Varies', 'While wearing this cloak, you can take a Magic action to turn the cloak into a pair of wings on your back. The wings last for 1 hour or until you end the effect early as a Magic action. The wings give you a Fly Speed of 60 feet. If you are aloft when the wings disappear, you fall. When the wings disappear, you can''t use them again for 1d12 hours', FALSE, ARRAY['attuned', 'rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ammunition of Slaying', 'Weapon (Any Ammunition)', 'Very Rare', 'No', 'Varies', 'This magic ammunition is meant to slay creatures of a particular type, which the DM chooses or determines randomly by rolling on the table below. If a creature of that type takes damage from the ammunition, the creature makes a DC 17 Constitution saving throw, taking an extra 6d10 Force damage on a failed save or half as much extra damage on a successful one.

After dealing its extra damage to a creature, the ammunition becomes nonmagical.', FALSE, ARRAY['consumable', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Amulet of the Planes', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'While wearing this amulet, you can take a Magic action to name a location that you are familiar with on another plane of existence. Then make a DC 15 Intelligence (Arcana) check. On a successful check, you cast Plane Shift. On a failed check, you and each creature and object within 15 feet of you travel to a random destination determined by rolling 1d100 and consulting the following table.', FALSE, ARRAY['attuned', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Bag of Devouring', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This bag resembles a Bag of Holding but is a feeding orifice for a gigantic extradimensional creature. Turning the bag inside out closes the orifice.

The extradimensional creature attached to the bag can sense whatever is placed inside the bag. Animal or vegetable matter placed wholly in the bag is devoured and lost forever. When part of a living creature is placed in the bag, as happens when someone reaches inside it, there is a 50 percent chance that the creature is pulled inside the bag. A creature inside the bag can take an action to try to escape, doing so with a successful DC 15 Strength (Athletics) check. Another creature can take an action to reach into the bag to pull a creature out, doing so with a successful DC 20 Strength (Athletics) check, provided the puller isn’t pulled inside the bag first. Any creature that starts its turn inside the bag is devoured, its body destroyed.

Inanimate objects can be stored in the bag, which can hold a cubic foot of such material. However, once each day, the bag swallows any objects inside it and spits them out into another plane of existence. The DM determines the time and plane.

If the bag is pierced or torn, it is destroyed, and anything contained within it is transported to a random location on the Astral Plane.', FALSE, ARRAY['very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Animated Shield', 'Armor (Shield)', 'Very Rare', 'No', 'Varies', 'While holding this Shield, you can take a Bonus Action to cause it to animate. The Shield leaps into the air and hovers in your space to protect you as if you were wielding it, leaving your hands free. The Shield remains animate for 1 minute, until you take a Bonus Action to end this effect, or until you die or have the Incapacitated condition, at which point the Shield falls to the ground or into your hand if you have one free.', FALSE, ARRAY['armor', 'attuned', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Candle of Invocation', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This candle’s magic is activated when the candle is lit, which requires a Magic action. After burning for 4 hours, the candle is destroyed. You can snuff it out early for use at a later time. Deduct the time it burned in increments of 1 minute from its total burn time.

While lit, the candle sheds Dim Light in a 30-foot radius. While you are within that light, you have Advantage on D20 Tests. In addition, a Cleric or Druid in the light can cast level 1 spells they have prepared without expending spell slots.

Alternatively, when you light the candle for the first time, you can cast Gate with it. Doing so destroys the candle. The portal created by the spell links to a particular Outer Plane chosen by the DM or determined by rolling on the following table.', FALSE, ARRAY['attuned', 'consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cauldron of Rebirth', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This Tiny pot bears relief scenes of heroes on its cast-iron sides.

You can use the cauldron as a Spellcasting Focus for your spells, and it functions as a suitable component for the Scrying spell.

Brew Potion. When you finish a Long Rest, you can use the cauldron to create a Potion of Healing (greater), which takes 1 minute. The potion lasts for 24 hours, then loses its magic if not consumed.

Raise Dead. As a Magic action, you can cause the cauldron to grow large enough for a Medium creature to crouch within. You can revert the cauldron to its normal size as a Magic action, harmlessly shunting anything that can’t fit inside to the nearest unoccupied space.

If you place the corpse of a Humanoid into the cauldron and cover the corpse with 200 pounds of salt (which costs 10 GP) for at least 8 hours, the salt is consumed and the creature returns to life as if by Raise Dead at the next dawn. Once used, this property can’t be used again for 7 days.', FALSE, ARRAY['attuned', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Carpet of Flying', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'You can make this carpet hover and fly by taking a Magic action and using the carpet’s command word. It moves according to your directions if you are within 30 feet of it.

Four sizes of Carpet of Flying exist. The DM chooses the size of a given carpet or determines it randomly by rolling on the following table. A carpet can carry up to twice the weight shown on the table, but its Fly Speed is halved if it carries more than its normal capacity.', FALSE, ARRAY['very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dancing Sword', 'Weapon (Greatsword', 'Very Rare', 'No', 'Varies', 'You can take a Bonus Action to toss this magic weapon into the air. When you do so, the weapon begins to hover, flies up to 30 feet, and attacks one creature of your choice within 5 feet of itself. The weapon uses your attack roll and adds your ability modifier to damage rolls.

While the weapon hovers, you can take a Bonus Action to cause it to fly up to 30 feet to another spot within 30 feet of you. As part of the same Bonus Action, you can cause the weapon to attack one creature within 5 feet of the weapon.

After the hovering weapon attacks for the fourth time, it flies back to you and tries to return to your hand. If you have no hand free, the weapon falls to the ground in your space. If the weapon has no unobstructed path to you, it moves as close to you as it can and then falls to the ground. It also ceases to hover if you grasp it or are more than 30 feet away from it.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of Arachnida', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This fine garment is made of black silk interwoven with faint, silvery threads. While wearing it, you gain the following benefits.

Poison Resistance. You have Resistance to Poison damage.

Spider Climb. You have a Climb Speed equal to your Speed and can move up, down, and across vertical surfaces and along ceilings, while leaving your hands free.

Spider Walk. You can’t be caught in webs of any sort and can move through webs as if they were Difficult Terrain.

Web. You can cast Web (save DC 13). The web created by the spell fills twice its normal area. Once used, this property can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Demon Armor', 'Armor (Any Light', 'Very Rare', 'No', 'Varies', 'While wearing this armor, you gain a +1 bonus to Armor Class, and you know Abyssal. In addition, the armor’s clawed gauntlets allow your Unarmed Strikes to deal 1d8 Slashing damage instead of the usual Bludgeoning damage, and you gain a +1 bonus to the attack and damage rolls of your Unarmed Strikes.

Curse. Once you don this cursed armor, you can’t doff it unless you are targeted by a Remove Curse spell or similar magic. While wearing the armor, you have Disadvantage on attack rolls against demons and on saving throws against their spells and special abilities.', FALSE, ARRAY['armor', 'attuned', 'cursed', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dragon Scale Mail', 'Armor (Scale Mail)', 'Very Rare', 'No', 'Varies', 'Dragon Scale Mail is made of the scales of one kind of dragon. Sometimes dragons collect their cast-off scales and gift them. Other times, hunters carefully preserve the hide of a dead dragon. In either case, Dragon Scale Mail is highly valued.

While wearing this armor, you gain a +1 bonus to Armor Class, you have Advantage on saving throws against the breath weapons of Dragons, and you have Resistance to one damage type determined by the kind of dragon that provided the scales (see the accompanying table).

Additionally, you can focus your senses as a Magic action to discern the distance and direction to the closest dragon within 30 miles of yourself that is of the same type as the armor. This action can’t be used again until the next dawn.', FALSE, ARRAY['armor', 'attuned', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dwarven Plate', 'Armor (Half Plate or Plate Armor)', 'Very Rare', 'No', 'Varies', 'While wearing this armor, you gain a +2 bonus to Armor Class. In addition, if an effect moves you against your will along the ground, you can take a Reaction to reduce the distance you are moved by up to 10 feet.', FALSE, ARRAY['armor', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Dwarven Thrower', 'Weapon (Warhammer)', 'Very Rare', 'No', 'Varies', 'You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. It has the Thrown property with a normal range of 20 feet and a long range of 60 feet. When you hit with a ranged attack using this weapon, it deals an extra 1d8 Force damage, or an extra 2d8 Force damage if the target is a Giant. Immediately after hitting or missing, the weapon flies back to your hand.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Efreeti Bottle', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'When you take a Magic action to remove the stopper of this painted brass bottle, a cloud of thick smoke flows out of it. At the end of your turn, the smoke disappears with a flash of harmless fire, and an Efreeti appears in an unoccupied space within 30 feet of you.

The first time the bottle is opened, the DM rolls on the following table to determine what happens.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Energy Bow', 'Weapon (Longbow or Shortbow)', 'Very Rare', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon, which has no string. Each time you pull your arm back in a firing motion, a magical arrow made of golden energy appears nocked and ready to fire. An arrow produced by this weapon deals Force damage instead of Piercing damage on a hit, and it disappears after it hits or misses its target. Until it disappears, the arrow emits Bright Light in a 20-foot radius and Dim Light for an additional 20 feet.

This weapon has the following additional properties.

Arrow of Restraint. Whenever you use this weapon to make a ranged attack against a creature, you can try to restrain the target instead of dealing damage to it. If the arrow hits, the target must succeed on a DC 15 Strength saving throw or have the Restrained condition for 1 minute. As an action, a creature Restrained by an arrow can make a DC 20 Strength (Athletics) check to try to break the restraint, ending the effect on itself on a successful check.

Arrow of Transport. As a Magic action, you can fire one energy arrow from this weapon at a target you can see within 60 feet of yourself. The target can be either a willing Medium or smaller creature or an object that isn’t being worn or carried, provided the object is small enough to fit inside a 5-foot Cube. The arrow teleports the target to an unoccupied space you can see within 10 feet of you.

Energy Ladder. As a Magic action, you can loose a flurry of energy arrows from this weapon at a wall up to 60 feet away from yourself. The arrows become glowing rungs that stick out of the wall, forming a magical ladder up to 60 feet long on the wall. This ladder lasts for 1 minute before disappearing.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Frost Brand', 'Weapon (Glaive', 'Very Rare', 'No', 'Varies', 'When you hit with an attack roll using this magic weapon, the target takes an extra 1d6 Cold damage. In addition, while you hold the weapon, you have Resistance to Fire damage.

In freezing temperatures, the weapon sheds Bright Light in a 10-foot radius and Dim Light for an additional 10 feet.

When you draw this weapon, you can extinguish all nonmagical flames within 30 feet of yourself. Once used, this property can’t be used again for 1 hour.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Executioner''s Axe', 'Weapon (Battleaxe', 'Very Rare', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon.

Any Humanoid you hit with the weapon takes an extra 2d6 Slashing damage, and you gain Temporary Hit Points equal to the extra damage dealt.', FALSE, ARRAY['very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Hat of Many Spells', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This pointed hat has the following properties.

Spellcasting Focus. While holding the hat, you can use it as a Spellcasting Focus for your Wizard spells. Any spell you cast using the hat gains a special Somatic component: you must reach into the hat and “pull” the spell out of it.

Unknown Spell. While holding the hat, you can try to cast a level 1+ spell you don’t know. The spell must be on the Wizard spell list, it must be of a level you can cast, and it can’t have Material components costing more than 1,000 GP. Once you decide on the spell, you must expend a spell slot of the spell’s level. Then, to determine whether you cast the spell, make an Intelligence (Arcana) check (DC 10 plus the spell’s level). On a successful check, you cast the spell using its normal casting time, and you can’t use this property again until you finish a Short or Long Rest. On a failed check, you fail to cast the spell and a random effect occurs instead, determined by rolling on the following table.

Any spell you cast from the hat uses your spell save DC and spell attack bonus.', FALSE, ARRAY['attuned', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Helm of Brilliance', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This helm is set with 1d10 diamonds, 2d10 rubies, 3d10 fire opals, and 4d10 opals. Any gem pried from the helm crumbles to dust. When all the gems are removed or destroyed, the helm loses its magic.

You gain the following benefits while wearing the helm.

Diamond Light. As long as it has at least one diamond, the helm emits a 30-foot Emanation. When at least one Undead is within that area, the Emanation is filled with Dim Light. Any Undead that starts its turn in that area takes 1d6 Radiant damage.

Fire Opal Flames. As long as the helm has at least one fire opal, you can take a Magic action to cause one weapon you are holding to burst into flames. The flames emit Bright Light in a 10-foot radius and Dim Light for an additional 10 feet. The flames are harmless to you and the weapon. When you hit with an attack using the blazing weapon, the target takes an extra 1d6 Fire damage. The flames last until you take a Bonus Action to extinguish them or until you drop or stow the weapon.

Ruby Resistance. As long as the helm has at least one ruby, you have Resistance to Fire damage.

Spells. You can cast one of the following spells (save DC 18), using one of the helm’s gems of the specified type as a component: Daylight (opal), Fireball (fire opal), Prismatic Spray (diamond), or Wall of Fire (ruby). The gem is destroyed when the spell is cast and disappears from the helm.

Taking Fire Damage. Roll 1d20 if you are wearing the helm and take Fire damage as a result of failing a saving throw against a spell. On a roll of 1, the helm emits beams of light from its remaining gems and is then destroyed. Each creature within a 60-foot Emanation originating from you must succeed on a DC 17 Dexterity saving throw or be struck by a beam, taking Radiant damage equal to the number of gems in the helm.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Horseshoes of a Zephyr', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'These horseshoes come in a set of four. As a Magic action, you can touch one of the horseshoes to the hoof of a horse or similar creature, whereupon the horseshoe affixes itself to the hoof. Removing a horseshoe also takes a Magic action.

While all four shoes are affixed to the hooves of a horse or similar creature, they allow the creature to move normally while floating 4 inches above a surface. This effect means the creature can cross or stand above nonsolid or unstable surfaces, such as water or lava. The creature leaves no tracks and ignores Difficult Terrain. In addition, the creature can travel for up to 12 hours a day without gaining Exhaustion levels from extended travel.', FALSE, ARRAY['very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Lute of Thunderous Thumping', 'Weapon (Club)', 'Very Rare', 'No', 'Varies', 'This reinforced lute can be wielded as a magic Club that deals an extra 2d8 Thunder damage on a hit.

Sing and Swing. If you’re a Bard, you can use your Charisma modifier instead of your Strength modifier when making a melee attack roll with the lute, provided you sing or hum while making the attack.', FALSE, ARRAY['very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Manual of Bodily Health', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This book contains health and nutrition tips, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book’s contents and practicing its guidelines, your Constitution increases by 2, to a maximum of 30. The manual then loses its magic but regains it in a century.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Manual of Golems', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This tome contains information and incantations necessary to make a particular type of golem. The DM chooses the type or determines it randomly by rolling on the accompanying table. To decipher and use the manual, you must be a spellcaster with at least two level 5 spell slots. A creature that can’t use a Manual of Golems and attempts to read it takes 6d6 Psychic damage.

To create a golem, you must spend the time shown on the table, working without interruption with the manual at hand and resting no more than 8 hours per day. You must also pay the specified cost to purchase supplies.

Once you finish creating the golem, the book is consumed in eldritch flames. The golem becomes animate when the ashes of the manual are sprinkled on it. See the Monster Manual for the golem’s stat block. The golem is under your control, and it understands and obeys your commands.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Manual of Gainful Exercise', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This book describes fitness exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book’s contents and practicing its guidelines, your Strength increases by 2, to a maximum of 30. The manual then loses its magic but regains it in a century.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Manual of Quickness of Action', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This book contains coordination and balance exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book’s contents and practicing its guidelines, your Dexterity increases by 2, to a maximum of 30. The manual then loses its magic but regains it in a century.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mirror of Life Trapping', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'When this 4-foot-tall, 2-foot-wide mirror is viewed indirectly, its surface shows faint images of creatures. The mirror weighs 50 pounds, and it has AC 11, HP 10, Immunity to Poison and Psychic damage, and Vulnerability to Bludgeoning damage. It shatters and is destroyed when reduced to 0 Hit Points.

If the mirror is hanging on a vertical surface and you are within 5 feet of it, you can take a Magic action and use a command word to activate it. It remains activated until you take a Magic action and repeat the command word to deactivate it.

Any creature other than you that sees its reflection in the activated mirror while within 30 feet of the mirror must succeed on a DC 15 Charisma saving throw or be trapped, along with anything it is wearing or carrying, in one of the mirror’s twelve extradimensional cells. A creature that knows the mirror’s nature makes the save with Advantage, and Constructs succeed on the save automatically.

An extradimensional cell is an infinite expanse filled with thick fog that reduces visibility to 10 feet. Creatures trapped in the mirror’s cells don’t age, and they don’t need to eat, drink, or sleep. A creature trapped within a cell can escape using magic that permits planar travel. Otherwise, the creature is confined to the cell until freed.

If the mirror traps a creature but its twelve extradimensional cells are already occupied, the mirror frees one trapped creature at random to accommodate the new prisoner. A freed creature appears in an unoccupied space within sight of the mirror but facing away from it. If the mirror is shattered, all creatures it contains are freed and appear in unoccupied spaces near it.

While within 5 feet of the mirror, you can take a Magic action to name one creature trapped in it or call out a particular cell by number. The creature named or contained in the named cell appears as an image on the mirror’s surface. You and the creature can then communicate.

In a similar way, you can take a Magic action and use a second command word to free one creature trapped in the mirror. The freed creature appears, along with its possessions, in the unoccupied space nearest to the mirror and facing away from it.

Placing the mirror inside an extradimensional space created by a Bag of Holding, Portable Hole, or similar item instantly destroys both items and opens a gate to the Astral Plane. The gate originates where the one item was placed inside the other. Any creature within 10 feet of the gate and not behind Total Cover is sucked through it to a random location on the Astral Plane. The gate then closes. The gate is one-way only and can’t be reopened.', FALSE, ARRAY['very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Niko''s Mace', 'Weapon (Mace)', 'Very Rare', 'No', 'Varies', 'This Mace has 6 charges and regains 1d6 expended charges daily at dawn. While holding the Mace, you can expend 1 of its charges to cast Summon Celestial (+9 to hit with spell attacks).', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Nolzur''s Marvelous Pigments', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This fine wooden box contains 1d4 pots of pigment and a brush (weighing 1 pound in total).

Using the brush and expending 1 pot of pigment, you can paint any number of three-dimensional objects and terrain features (such as walls, doors, trees, flowers, weapons, webs, and pits), provided these elements are all confined to a 20-foot Cube. The effort takes 10 minutes (regardless of the number of elements you create), during which time you must remain in the Cube, and requires Concentration. If your Concentration is broken or you leave the Cube before the work is done, all the painted elements vanish, and the pot of pigment is wasted.

When the work is done, all the painted objects and terrain features become real. Thus, painting a door on a wall creates an actual door, which can be opened to whatever is beyond. Painting a pit creates a real pit, the entire depth of which must lie within the 20-foot Cube.

No object created by a pot of pigment can have a value greater than 25 GP, and the total value of all objects created by a pot of pigment can’t exceed 500 GP. If you paint objects of greater value (such as a large pile of gold), they look authentic, but close inspection reveals they’re made from paste, cookies, or some other worthless material.

If you paint a form of energy such as fire or lightning, the energy dissipates as soon as you complete the painting, doing no harm.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Nine Lives Stealer', 'Weapon (Any Simple or Martial)', 'Very Rare', 'No', 'Varies', 'You gain a +2 bonus to attack rolls and damage rolls made with this magic weapon.

Life Stealing. The weapon has 1d8 + 1 charges. When you attack a creature that has fewer than 100 Hit Points with this weapon and roll a 20 on the d20 for the attack roll, the creature must succeed on a DC 15 Constitution saving throw or be slain instantly as the sword tears its life force from its body. Constructs and Undead succeed on the save automatically. The weapon loses 1 charge if the creature is slain. When the weapon has no charges remaining, it loses this property.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Oathbow', 'Weapon (Longbow or Shortbow)', 'Very Rare', 'No', 'Varies', 'When you nock an arrow on this bow, it whispers in Elvish, “Swift defeat to my enemies.” When you use this weapon to make a ranged attack, you can utter or sign the following command words: “Swift death to you who have wronged me.” The target of your attack becomes your sworn enemy until it dies or until dawn 7 days later. You can have only one such sworn enemy at a time. When your sworn enemy dies, you can choose a new one after the next dawn.

When you make a ranged attack roll with this weapon against your sworn enemy, you have Advantage on the roll. In addition, your target gains no benefit from Half Cover or Three-Quarters Cover, and you suffer no Disadvantage due to long range. If the attack hits, your sworn enemy takes an extra 3d6 Piercing damage.

While your sworn enemy lives, you have Disadvantage on attack rolls with all other weapons.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Oil of Sharpness', 'Potion', 'Very Rare', 'No', 'Varies', 'One vial of this oil can coat one Melee weapon or twenty pieces of ammunition, but only ammunition and Melee weapons that are nonmagical and deal Slashing or Piercing damage are affected. Applying the oil takes 1 minute, after which the oil magically seeps into whatever it coats, turning the coated weapon into a +3 Weapon or the coated ammunition into +3 Ammunition.

This clear, gelatinous oil sparkles with tiny, ultrathin silver shards.', FALSE, ARRAY['consumable', 'potion', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Longevity', 'When you drink this potion', 'Very Rare', 'No', 'Varies', 'Suspended in this amber liquid is a tiny heart that, against all reason, is still beating. These ingredients vanish when the potion is opened.', FALSE, ARRAY['consumable', 'potion', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Flying', 'Potion', 'Very Rare', 'No', 'Varies', 'When you drink this potion, you gain a Fly Speed equal to your Speed for 1 hour and can hover. If you’re in the air when the potion wears off, you fall unless you have some other means of staying aloft.

This potion’s clear liquid floats at the top of its container and has cloudy white impurities drifting in it.', FALSE, ARRAY['consumable', 'potion', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Greater Invisibility', 'Potion', 'Very Rare', 'No', 'Varies', 'This potion’s container looks empty but feels as though it holds liquid. When you drink the potion, you have the Invisible condition for 1 hour.', FALSE, ARRAY['consumable', 'potion', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Speed', 'Potion', 'Very Rare', 'No', 'Varies', 'When you drink this potion, you gain the effect of the Haste spell for 1 minute (no Concentration required) without suffering the wave of lethargy that typically occurs when the effect ends.

This potion’s yellow fluid is streaked with black and swirls on its own.', FALSE, ARRAY['consumable', 'potion', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Potion of Vitality', 'Potion', 'Very Rare', 'No', 'Varies', 'When you drink this potion, it removes any Exhaustion levels you have and ends the Poisoned condition on you. For the next 24 hours, you regain the maximum number of Hit Points for any Hit Point Die you spend.

This potion’s crimson liquid regularly pulses with dull light, calling to mind a heartbeat.', FALSE, ARRAY['consumable', 'potion', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Quarterstaff of the Acrobat', 'Weapon (Quarterstaff)', 'Very Rare', 'No', 'Varies', 'You have a +2 bonus to attack rolls and damage rolls made with this magic weapon.

While holding this weapon, you can cause it to emit green Dim Light out to 10 feet, either as a Bonus Action or after you roll Initiative, or you can extinguish the light as a Bonus Action.

While holding this weapon, you can take a Bonus Action to alter its form, turning it into a 6-inch rod (for ease of storage) or a 10-foot pole, or reverting it a Quarterstaff; the weapon will elongate only as far as the surrounding space allows.

In certain forms, the weapon has the following additional properties.

Acrobatic Assist (Quarterstaff and 10-Foot Pole Forms Only). While holding this weapon, you have Advantage on Dexterity (Acrobatics) checks.

Attack Deflection (Quarterstaff Form Only). When you are hit by an attack while holding the weapon, you can take a Reaction to twirl the weapon around you, gaining a +5 bonus to your Armor Class against the triggering attack, potentially causing the attack to miss you. You can’t use this property again until you finish a Short or Long Rest.

Ranged Weapon (Quarterstaff Form Only). This weapon has the Thrown property with a normal range of 30 feet and a long range of 120 feet. Immediately after you make a ranged attack with the weapon, it flies back to your hand.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Shooting Stars', 'Ring', 'Very Rare', 'No', 'Varies', 'You can cast Dancing Lights or Light from the ring.

The ring has 6 charges and regains 1d6 expended charges daily at dawn. You can expend its charges to use the properties below.

Faerie Fire. You can expend 1 charge to cast Faerie Fire from the ring.

Lightning Spheres. You can expend 2 charges as a Magic action to create up to four 3-foot-diameter spheres of lightning.

Each sphere appears in an unoccupied space you can see within 120 feet of yourself. The spheres last as long as you maintain Concentration, up to 1 minute. Each sphere sheds Dim Light in a 30-foot radius.

As a Bonus Action, you can move each sphere up to 30 feet, but no farther than 120 feet away from yourself. The first time the sphere comes within 5 feet of a creature other than you that isn’t behind Total Cover, the sphere discharges lightning at that creature and disappears. That creature makes a DC 15 Dexterity saving throw. On a failed save, the creature takes Lightning damage based on the number of spheres you created, as shown in the following table. On a successful save, the creature takes half as much damage.

Shooting Stars. You can expend 1 to 3 charges as a Magic action. For every charge you expend, you launch a glowing mote of light from the ring at a point you can see within 60 feet of yourself. Each creature in a 15-foot Cube originating from that point is showered in sparks and makes a DC 15 Dexterity saving throw, taking 5d4 Radiant damage on a failed save or half as much damage on a successful one.', FALSE, ARRAY['attuned', 'ring', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Regeneration', 'Ring', 'Very Rare', 'No', 'Varies', 'While wearing this ring, you regain 1d6 Hit Points every 10 minutes if you have at least 1 Hit Point. If you lose a body part, the ring causes the missing part to regrow and return to full functionality after 1d6 + 1 days if you have at least 1 Hit Point the whole time.', FALSE, ARRAY['attuned', 'ring', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Telekinesis', 'Ring', 'Very Rare', 'No', 'Varies', 'While wearing this ring, you can cast Telekinesis from it.', FALSE, ARRAY['attuned', 'ring', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Robe of Scintillating Colors', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This robe has 3 charges, and it regains 1d3 expended charges daily at dawn. While you wear it, you can take a Magic action and expend 1 charge to cause the garment to display a shifting pattern of dazzling hues until the end of your next turn. During this time, the robe sheds Bright Light in a 30-foot radius and Dim Light for an additional 30 feet, and creatures that can see you have Disadvantage on attack rolls against you. Any creature in the Bright Light that can see you when the robe’s power is activated must succeed on a DC 15 Wisdom saving throw or have the Stunned condition until the effect ends.', FALSE, ARRAY['attuned', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Robe of Stars', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This black or dark-blue robe is embroidered with small white or silver stars. You gain a +1 bonus to saving throws while you wear it.

Six stars, located on the robe’s upper-front portion, are particularly large. While wearing this robe, you can take a Magic action to remove one of the stars and expend it to cast the level 5 version of Magic Missile. Daily at dusk, 1d6 removed stars reappear on the robe.

While you wear the robe, you can take a Magic action to enter the Astral Plane along with everything you are wearing and carrying. You remain there until you take a Magic action to return to the plane you were on. You reappear in the last space you occupied or, if that space is occupied, the nearest unoccupied space.', FALSE, ARRAY['attuned', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rod of Security', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'Rod, Very Rare

While holding this rod, you can take a Magic action to activate it. The rod then instantly transports you and up to 199 other willing creatures you can see to a demiplane. You choose the form the demiplane takes. It could be a tranquil garden, a cheery tavern, an immense palace, a tropical island, a fantastic carnival, or whatever else you can imagine. Regardless of its nature, the demiplane contains enough water and food to sustain its visitors, and the demiplane’s environment can’t harm its occupants. Everything else that can be interacted with there can exist only there. For example, a flower picked from a garden there disappears if it is taken outside the demiplane.

For each hour spent in the demiplane, a visitor regains Hit Points as if it had spent 1 Hit Point Die. Also, creatures don’t age while there, although time passes normally. Visitors can remain there for up to 200 days divided by the number of creatures present (round down).

When the time runs out or you take a Magic action to end the effect, all visitors reappear in the location they occupied when you activated the rod or an unoccupied space nearest that location. Once used, this property can’t be used again until 10 days have passed.', FALSE, ARRAY['rod', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rod of Absorption', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'Rod, Very Rare (Requires Attunement)

While holding this rod, you can take a Reaction to absorb a spell that is targeting only you and doesn’t create an area of effect. The absorbed spell’s effect is canceled, and the spell’s energy—not the spell itself—is stored in the rod. The energy has the same level as the spell when it was cast. A canceled spell dissipates with no effect, and any resources used to cast it are wasted. The rod can absorb and store up to 50 levels of energy over the course of its existence. Once the rod absorbs 50 levels of energy, it can’t absorb more. If you are targeted by a spell that the rod can’t store, the rod has no effect on that spell.

When you become attuned to the rod, you know how many levels of energy the rod has absorbed over the course of its existence and how many levels of spell energy it currently has stored.

If you are a spellcaster holding the rod, you can convert energy stored in it into spell slots to cast spells you have prepared or know. You can create spell slots only of a level equal to or lower than your own spell slots, up to a maximum of level 5. You use the stored levels in place of your slots but otherwise cast the spell as normal. For example, you can use 3 levels stored in the rod as a level 3 spell slot.

A newly found rod typically has 1d10 levels of spell energy stored in it. A rod that can no longer absorb spell energy and has no energy remaining becomes nonmagical.', FALSE, ARRAY['attuned', 'consumable', 'rod', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rod of Alertness', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'Rod, Very Rare (Requires Attunement)

This rod has the following properties.

Alertness. While holding the rod, you have Advantage on Wisdom (Perception) checks and on Initiative rolls.

Spells. While holding the rod, you can cast the following spells from it:

Protective Aura. As a Magic action, you can plant the haft end of the rod in the ground, whereupon the rod’s head sheds Bright Light in a 60-foot radius and Dim Light for an additional 60 feet. While in that Bright Light, you and your allies gain a +1 bonus to Armor Class and saving throws and can sense the location of any Invisible creature that is also in the Bright Light.

The rod’s head stops glowing and the effect ends after 10 minutes or when a creature takes a Magic action to pull the rod from the ground. Once used, this property can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'rod', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Scimitar of Speed', 'Weapon (Scimitar)', 'Very Rare', 'No', 'Varies', 'You gain a +2 bonus to attack rolls and damage rolls made with this magic weapon. In addition, you can make one attack with it as a Bonus Action on each of your turns.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Shield of the Cavalier', 'Armor (Shield)', 'Very Rare', 'No', 'Varies', 'While holding this Shield, you have a +2 bonus to Armor Class. This bonus is in addition to the Shield’s normal bonus to AC.

The Shield has the following additional properties that you can use while holding it.

Forceful Bash. When you take the Attack, you can make one of the attack rolls using the Shield against a target within 5 feet of yourself. Apply your Proficiency Bonus and Strength modifier to the attack roll. On a hit, the Shield deals Force damage to the target equal to 2d6 + 2 plus your Strength modifier, and if the target is a creature, you can push it up to 10 feet directly away from yourself. If the creature is your size or smaller, you can also knock it down, giving it the Prone condition.

Protective Field. As a Reaction, when you or an ally you can see within 5 feet of you is targeted by an attack or makes a saving throw against an area of effect, you can use the Shield to create an immobile 5-foot Emanation originating from you. When the Emanation appears, any creatures or objects not fully contained within it are pushed into the nearest unoccupied spaces outside it. The attack or area of effect that triggered the Reaction has no effect on creatures and objects inside the Emanation, which lasts as long as you maintain Concentration, up to 1 minute. Nothing can pass into or out of the Emanation. A creature or object inside the Emanation can’t be damaged by attacks or effects originating from outside, nor can a creature inside the Emanation damage anything outside it. Once this property is used, it can’t be used again until the next dawn.', FALSE, ARRAY['armor', 'attuned', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Spellguard Shield', 'Armor (Shield)', 'Very Rare', 'No', 'Varies', 'While holding this Shield, you have Advantage on saving throws against spells and other magical effects, and spell attack rolls have Disadvantage against you.', FALSE, ARRAY['armor', 'attuned', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Spirit Board', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This ornate wooden board has the letters of the Common alphabet printed on one side, alongside the words “Yes” and “No” and symbols representing “Weal” and “Woe.” The board comes with a heart-shaped, wooden planchette. This planchette must be resting on the lettered side of the board for the board’s magic to function.

This board has 3 charges and regains 1 expended charge daily at dawn. While touching the planchette, you can take 1 minute to cast one of the spells on the table below. The table indicates how many charges you must expend to cast the spell. As you cast the spell, you call on the spirits of the dead to guide the planchette across the board’s surface, answering your questions by pointing to the letters or words on the board.', FALSE, ARRAY['very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Fire', 'Staff', 'Very Rare', 'No', 'Varies', 'You have Resistance to Fire damage while you hold this staff.

Spells. The staff has 10 charges. While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

Regaining Charges. The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff crumbles into cinders and is destroyed.', FALSE, ARRAY['attuned', 'staff', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Power', 'Staff', 'Very Rare', 'No', 'Varies', 'This staff has 20 charges and can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. While holding it, you gain a +2 bonus to Armor Class, saving throws, and spell attack rolls.

Spells. While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

Regaining Charges. The staff regains 2d8 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff retains its +2 bonus to attack rolls and damage rolls but loses all other properties. On a 20, the staff regains 1d8 + 2 charges.

Retributive Strike. You can take a Magic action to break the staff over your knee or against a solid surface. The staff is destroyed and releases its magic in an explosion that fills a 30-foot Emanation originating from itself. You have a 50 percent chance to instantly travel to a random plane of existence, avoiding the explosion. If you fail to avoid the effect, you take Force damage equal to 16 times the number of charges in the staff. Each other creature in the area makes a DC 17 Dexterity saving throw. On a failed save, a creature takes Force damage equal to 4 times the number of charges in the staff. On a successful save, a creature takes half as much damage.', FALSE, ARRAY['attuned', 'staff', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Striking', 'Staff', 'Very Rare', 'No', 'Varies', 'This staff can be wielded as a magic Quarterstaff that grants a +3 bonus to attack rolls and damage rolls made with it.

The staff has 10 charges. When you hit with a melee attack using it, you can expend up to 3 charges. For each charge you expend, the target takes an extra 1d6 Force damage.

Regaining Charges. The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff becomes a nonmagical Quarterstaff.', FALSE, ARRAY['attuned', 'staff', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Thunder and Lightning', 'Staff', 'Very Rare', 'No', 'Varies', 'This staff can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. It also has the following additional properties. Once one of these properties is used, it can’t be used again until the next dawn.

Lightning. When you hit with a melee attack using the staff, you can cause the target to take an extra 2d6 Lightning damage (no action required).

Thunder. When you hit with a melee attack using the staff, you can cause the staff to emit a crack of thunder audible out to 300 feet (no action required). The target you hit must succeed on a DC 17 Constitution saving throw or have the Stunned condition until the end of your next turn.

Thunder and Lightning. Immediately after you hit with a melee attack using the staff, you can take a Bonus Action to use the Lightning and Thunder properties (see above) at the same time. Doing so doesn’t expend the daily use of those properties, only the use of this one.

Lightning Strike. You can take a Magic action to cause a bolt of lightning to leap from the staff’s tip in a Line that is 5 feet wide and 120 feet long. Each creature in that Line makes a DC 17 Dexterity saving throw, taking 9d6 Lightning damage on a failed save or half as much damage on a successful one.

Thunderclap. You can take a Magic action to cause the staff to produce a thunderclap audible out to 600 feet. Every creature within a 60-foot Emanation originating from you makes a DC 17 Constitution saving throw. On a failed save, a creature takes 2d6 Thunder damage and has the Deafened condition for 1 minute. On a successful save, a creature takes half as much damage only.', FALSE, ARRAY['attuned', 'staff', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of Frost', 'Staff', 'Very Rare', 'No', 'Varies', 'You have Resistance to Cold damage while you hold this staff.

Spells. The staff has 10 charges. While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

Regaining Charges. The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff turns to water and is destroyed.', FALSE, ARRAY['attuned', 'staff', 'very-rare']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sword of Sharpness', 'Weapon (Glaive', 'Very Rare', 'No', 'Varies', 'When you attack an object with this magic weapon and hit, maximize your weapon damage dice against the target.

When you attack a creature with this weapon and roll a 20 on the d20 for the attack roll, that target takes an extra 14 Slashing damage and gains 1 Exhaustion level.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Thunderous Greatclub', 'Weapon (Greatclub)', 'Very Rare', 'No', 'Varies', 'While you are attuned to this magic weapon, your Strength is 20 unless your Strength is already equal to or greater than that score. The weapon deals an extra 1d8 Thunder damage to any creature it hits and an extra 3d8 Thunder damage to objects it hits that aren’t being worn or carried.

The weapon has the following additional properties.

Clap of Thunder. As a Magic action, you can strike the weapon against a hard surface to create a loud clap of thunder audible out to 300 feet. You also create a 30-foot Cone of thunderous energy. Each creature in the Cone must succeed on a DC 15 Strength saving throw or have the Prone condition. Nonmagical objects in the Cone that aren’t being worn or carried take 3d8 Thunder damage.

Earthquake. As a Magic action, you can strike the weapon against the ground to create an intense seismic disturbance in a 50-foot-radius circle centered on the point of impact. Structures in contact with the ground in that area take 50 Bludgeoning damage, and each creature on the ground in that area must succeed on a DC 20 Dexterity saving throw or have the Prone condition. If that creature is also concentrating, it must succeed on a DC 20 Constitution saving throw or its Concentration is broken. In addition, you can cause a 30-foot-deep, 10-foot-wide fissure to open up on the ground anywhere in the area. Any creature on a spot where the fissure opens must make a DC 20 Dexterity saving throw, falling into the fissure on a failed save or moving with the fissure’s edge on a successful one. Any structure on a spot where the fissure opens collapses into the fissure. Once you use this property, it can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'very-rare', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Tome of Clear Thought', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This book contains memory and logic exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book’s contents and practicing its guidelines, your Intelligence increases by 2, to a maximum of 30. The manual then loses its magic but regains it in a century.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Tome of Understanding', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This book contains intuition and insight exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book’s contents and practicing its guidelines, your Wisdom increases by 2, to a maximum of 30. The manual then loses its magic, but regains it in a century.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Tome of Leadership and Influence', 'Wondrous Item', 'Very Rare', 'No', 'Varies', 'This book contains guidelines for influencing and charming others, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book’s contents and practicing its guidelines, your Charisma increases by 2, to a maximum of 30. The manual then loses its magic but regains it in a century.', FALSE, ARRAY['consumable', 'very-rare', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Polymorph', 'Wand', 'Very Rare', 'No', 'Varies', 'This wand has 7 charges. While holding it, you can expend 1 charge to cast Polymorph (save DC 15) from it.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', FALSE, ARRAY['attuned', 'very-rare', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Armor of Invulnerability', 'Armor (Plate Armor)', 'Legendary', 'No', 'Varies', 'You have Resistance to Bludgeoning, Piercing, and Slashing damage while you wear this armor.

Metal Shell. You can take a Magic action to give yourself Immunity to Bludgeoning, Piercing, and Slashing damage for 10 minutes or until you are no longer wearing the armor. Once this property is used, it can’t be used again until the next dawn.', FALSE, ARRAY['armor', 'attuned', 'legendary']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cloak of Invisibility', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This cloak has 3 charges and regains 1d3 expended charges daily at dawn. While wearing the cloak, you can take a Magic action to pull its hood over your head and expend 1 charge to give yourself the Invisible condition for 1 hour. The effect ends early if you pull the hood down (no action required) or cease wearing the hood.', FALSE, ARRAY['attuned', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Apparatus of Kwalish', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This item first appears to be a sealed iron barrel weighing 500 pounds. The barrel has a hidden catch, which can be found with a successful DC 20 Intelligence (Investigation) check. Releasing the catch unlocks a hatch at one end of the barrel, allowing two Medium or smaller creatures to crawl inside. Ten levers are set in a row at the far end, each in a neutral position, able to move up or down. When certain levers are used, the apparatus transforms to resemble a giant lobster.

The Apparatus of Kwalish is a Large object with the following statistics: AC 20; HP 200; Speed 30 ft., Swim 30 ft. (or 0 ft. for both if the legs aren’t extended); Immunity to Poison and Psychic damage.

To be used as a vehicle, the apparatus requires one pilot. While the apparatus’s hatch is closed, the compartment is airtight and watertight. The compartment holds enough air for 10 hours of breathing, divided by the number of breathing creatures inside.

The apparatus floats on water. It can also go underwater to a depth of 900 feet. Below that, the vehicle takes 2d6 Bludgeoning damage each minute from pressure.

A creature in the compartment can take a Utilize action to move as many as two of the apparatus’s levers up or down. After each use, a lever goes back to its neutral position. Each lever, from left to right, functions as shown in the Apparatus of Kwalish Levers table.', FALSE, ARRAY['legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Cubic Gate', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This cube is 3 inches across and radiates palpable magical energy. The six sides of the cube are each keyed to a different plane of existence, one of which is the Material Plane. The other sides are linked to planes determined by the DM.

The cube has 3 charges and regains 1d3 expended charges daily at dawn. As a Magic action, you can expend 1 of the cube’s charges to cast one of the following spells using the cube.

Gate. Pressing one side of the cube, you cast Gate, opening a portal to the plane of existence keyed to that side.

Plane Shift. Pressing one side of the cube twice, you cast Plane Shift, transporting the targets to the plane of existence keyed to that side.', FALSE, ARRAY['legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Deck of Many Things', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'Usually found in a box or pouch, this deck contains a number of cards made of ivory or vellum. Most (75 percent) of these decks have thirteen cards, but some have twenty-two. Use the appropriate column of the Deck of Many Things table when randomly determining cards drawn from the deck.

Before you draw a card, you must declare how many cards you intend to draw and then draw them randomly. Any cards drawn in excess of this number have no effect. Otherwise, as soon as you draw a card from the deck, its magic takes effect. You must draw each card no more than 1 hour after the previous draw. If you fail to draw the chosen number, the remaining number of cards fly from the deck on their own and take effect all at once.

Once a card is drawn, it disappears. Unless the card is the Fool or Jester, the card reappears in the deck, making it possible to draw the same card twice. (Once the Fool or Jester has left the deck, reroll on the table if that card comes up again.)

Each card’s effect is described below.

Balance You can increase one of your ability scores by 2, to a maximum of 22, provided you also decrease another one of your ability scores by 2. You can’t decrease an ability that has a score of 5 or lower. Alternatively, you can choose not to adjust your ability scores, in which case this card has no effect.

Comet The next time you enter combat against one or more Hostile creatures, you can select one of them as your foe when you roll Initiative. If you reduce your foe to 0 Hit Points during that combat, you have Advantage on Death Saving Throws for 1 year. If someone else reduces your chosen foe to 0 Hit Points or you don’t choose a foe, this card has no effect.

Donjon You disappear and become entombed in a state of suspended animation in an extradimensional sphere. Everything you’re wearing and carrying disappears with you except for Artifacts, which stay behind in the space you occupied when you disappeared. You remain imprisoned until you are found and removed from the sphere. You can’t be located by any Divination magic, but a Wish spell can reveal the location of your prison. You draw no more cards.

Euryale The card’s medusa-like visage curses you. You take a −2 penalty to saving throws while cursed in this way. Only a god or the magic of the Fates card can end this curse.

Fates Reality’s fabric unravels and spins anew, allowing you to avoid or erase one event as if it never happened. You can use the card’s magic as soon as you draw the card or at any other time before you die.

Flames A powerful devil becomes your enemy. The devil seeks your ruin and torments you, savoring your suffering before attempting to slay you. This enmity lasts until either you or the devil dies.

Fool You have Disadvantage on D20 Tests for the next 72 hours. Draw another card; this draw doesn’t count as one of your declared draws.

Gem Twenty-five pieces of jewelry worth 2,000 GP each or fifty gems worth 1,000 GP each appear at your feet.

Jester You have Advantage on D20 Tests for the next 72 hours, or you can draw two additional cards beyond your declared draws.

Key A Rare or rarer magic weapon with which you are proficient appears on your person. The DM chooses the weapon.

Knight You gain the service of a Knight, who magically appears in an unoccupied space you choose within 30 feet of yourself. The knight has the same alignment as you and serves you loyally until death, believing the two of you have been drawn together by fate. Work with your DM to create a name and backstory for this NPC. The DM can use a different stat block to represent the knight, as desired.

Moon You gain the ability to cast Wish 1d3 times.

Puzzle Permanently reduce your Intelligence or Wisdom by 1d4 + 1 (to a minimum score of 1). You can draw one additional card beyond your declared draws.

Rogue An NPC of the DM’s choice becomes Hostile toward you. You don’t know the identity of this NPC until they or someone else reveals it. Nothing less than a Wish spell or divine intervention can end the NPC’s hostility toward you.

Ruin All forms of wealth that you carry or own, other than magic items, are lost to you. Portable property vanishes. Businesses, buildings, and land you own are lost in a way that alters reality the least. If you have a Bastion, it is destroyed by some calamity beyond your control. Any documentation that proves you should own something lost to this card also disappears.

Sage At any time you choose within one year of drawing this card, you can ask a question in meditation and mentally receive a truthful answer to that question.

Skull An Avatar of Death (see the accompanying stat block) appears in an unoccupied space as close to you as possible. The avatar targets only you with its attacks, appearing as a ghostly skeleton clad in a tattered black robe and carrying a spectral scythe. The avatar disappears when it drops to 0 Hit Points or you die. If an ally of yours deals damage to the avatar, that ally summons another Avatar of Death. The new avatar appears in an unoccupied space as close to that ally as possible and targets only that ally with its attacks. You and your allies can each summon only one avatar as a consequence of this draw. A creature slain by an avatar can’t be restored to life.

Star Increase one of your ability scores by 2, to a maximum of 24.

Sun A magic item (chosen by the DM) appears on your person. In addition, you gain 10 Temporary Hit Points daily at dawn until you die.

Talons Every magic item you wear or carry disintegrates. Artifacts in your possession vanish instead.

Throne You gain proficiency and Expertise in your choice of History, Insight, Intimidation, or Persuasion. In addition, you gain rightful ownership of a small keep somewhere in the world. However, the keep is currently home to one or more monsters, which must be cleared out before you can claim the keep as yours.

Void Your soul is drawn from your body and contained in an object in a place of the DM’s choice. One or more powerful beings guard the place. While your soul is trapped in this way, your body is inert, ceases aging, and requires no food, air, or water. A Wish spell can’t return your soul to your body, but the spell reveals the location of the object that holds your soul. You draw no more cards.', FALSE, ARRAY['legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Efreeti Chain', 'Armor (Chain Mail or Chain Shirt)', 'Legendary', 'No', 'Varies', 'While wearing this armor, you gain a +3 bonus to Armor Class, you have Immunity to Fire damage, and you know Primordial. In addition, you can stand on and move across molten rock as if it were solid ground.', FALSE, ARRAY['armor', 'attuned', 'legendary']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Holy Avenger', 'Weapon (Any Simple or Martial)', 'Legendary', 'No', 'Varies', 'You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. When you hit a Fiend or an Undead with it, that creature takes an extra 2d10 Radiant damage.

While you hold the drawn weapon, it creates a 10-foot Emanation originating from you. You and all creatures Friendly to you in the Emanation have Advantage on saving throws against spells and other magical effects. If you have 17 or more levels in the Paladin class, the size of the Emanation increases to 30 feet.', FALSE, ARRAY['attuned', 'legendary', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Hammer of Thunderbolts', 'Weapon (Maul or Warhammer)', 'Legendary', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon.

The weapon has 5 charges. You can expend 1 charge and make a ranged attack with the weapon, hurling it as if it had the Thrown property with a normal range of 20 feet and a long range of 60 feet. If the attack hits, the weapon unleashes a thunderclap audible out to 300 feet. The target and every creature within 30 feet of it other than you must succeed on a DC 17 Constitution saving throw or have the Stunned condition until the end of your next turn. Immediately after hitting or missing, the weapon flies back to your hand. The weapon regains 1d4 + 1 expended charges daily at dawn.

Giant’s Bane. While you are attuned to the weapon and wearing either a Belt of Giant Strength or Gauntlets of Ogre Power to which you are also attuned, you gain the following benefits:

Giants’ Bane. When you roll a 20 on the d20 for an attack roll made with this weapon against a Giant, the creature must succeed on a DC 17 Constitution saving throw or die.

Might of Giants. The Strength score bestowed by your Belt of Giant Strength or Gauntlets of Ogre Power increases by 4, to a maximum of 30.', FALSE, ARRAY['attuned', 'legendary', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Defender', 'Weapon (Any Melee Weapon)', 'Legendary', 'No', 'Varies', 'You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon.

The first time you attack with the weapon on each of your turns, you can transfer some or all of the weapon’s bonus to your Armor Class. For example, you could reduce the bonus to your attack rolls and damage rolls to +1 and gain a +2 bonus to Armor Class. The adjusted bonuses remain in effect until the start of your next turn, although you must hold the weapon to gain a bonus to AC from it.', FALSE, ARRAY['attuned', 'legendary', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Iron Flask', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'While holding this brass-stoppered iron flask, you can take a Magic action to target a creature that you can see within 60 feet of yourself. If the flask is empty and the target is native to a plane of existence other than the one you’re on, the target must succeed on a DC 17 Wisdom saving throw or be trapped in the flask. If the target has been trapped by the flask before, it has Advantage on the save. Once trapped, a creature remains in the flask until released. The flask can hold only one creature at a time. A creature trapped in the flask doesn’t age and doesn’t need to breathe, eat, or drink.

You can take a Magic action to remove the flask’s stopper and release the creature in the flask. The creature then obeys your commands for 1 hour, understanding those commands even if it doesn’t know the language in which the commands are given. If you issue no commands or give the creature a command that is likely to result in its death or imprisonment, it defends itself but otherwise takes no actions. At the end of the duration, the creature acts in accordance with its normal disposition and alignment.

An Identify spell reveals if the flask contains a creature, but the only way to determine the type of creature is to open the flask. A newly discovered Iron Flask might already contain a creature chosen by the DM or determined randomly by rolling on the following table (see the Monster Manual for the creature’s stat block).', FALSE, ARRAY['legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Plate Armor of Etherealness', 'Armor (Half Plate Armor or Plate Armor)', 'Legendary', 'No', 'Varies', 'While you’re wearing this armor, you can take a Magic action and use a command word to gain the effect of the Etherealness spell. The spell ends immediately if you remove the armor or take a Magic action to repeat the command word. This property of the armor can’t be used again until the next dawn.', FALSE, ARRAY['armor', 'attuned', 'legendary']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Moonblade', 'Weapon (Greatsword', 'Legendary', 'No', 'Varies', 'Of all the magic items created by elves, one of the most prized and jealously guarded is a Moonblade. In ancient times, nearly all elven noble houses claimed one such weapon. Over the centuries, some of these weapons have faded from the world, their magic lost as family lines have become extinct. Others have vanished with their bearers during great quests. Thus, only a few of these weapons remain.

Every Moonblade longs for a bearer whose disposition and goals are compatible with its own. If you try to attune to a Moonblade that doesn’t want you as its bearer, the weapon not only rejects you but also places a curse on you, causing you to make D20 Tests with Disadvantage for 24 hours or until the curse is ended by a Remove Curse spell or similar magic. If you’re accepted by the weapon and try to attune to it, you become attuned to it instantly, and a new rune appears on it. You remain attuned to the weapon until you die or the weapon is destroyed. A Moonblade functions like a nonmagical weapon of its kind for anyone other than its chosen bearer.

A Moonblade has one rune on it for each bearer it has willingly served (typically 1d6 + 1). The first rune grants a +1 bonus to attack rolls and damage rolls made with this magic weapon. Each rune beyond the first grants the Moonblade an additional property. The DM chooses each property or determines it randomly by rolling on the Moonblade Properties table.

Minor Property. In addition to its aforementioned properties, each Moonblade has a minor property determined by rolling on the Magic Item’s Minor Property table

Sentience. A Moonblade is a sentient weapon with an Intelligence of 12, a Wisdom of 10, and a Charisma of 12. It has hearing and Darkvision out to 120 feet. Its alignment matches that of its creator.

The weapon communicates by transmitting emotions, sending a tingling sensation through the wielder’s hand when it wants to communicate something it has sensed. It can communicate through visions or dreams when the wielder is either in a trance or asleep.

Personality. A Moonblade has a personality similar to that of its creator. Once a Moonblade has decided on an owner, it believes that only that person should wield it, even if the bearer’s alignment differs from that of the weapon’s or the bearer’s goals later clash with the weapon’s goals.', FALSE, ARRAY['attuned', 'legendary', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Luck Blade', 'Weapon (Glaive', 'Legendary', 'No', 'Varies', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon. While the weapon is on your person, you also gain a +1 bonus to saving throws.

Luck. If the weapon is on your person, you can call on its luck (no action required) to reroll one failed D20 Test if you don’t have the Incapacitated condition. You must use the second roll. Once used, this property can’t be used again until the next dawn.

Wish. The weapon has 1d3 charges. While holding it, you can expend 1 charge and cast Wish from it. Once used, this property can’t be used again until the next dawn. The weapon loses this property if it has no charges.', FALSE, ARRAY['attuned', 'legendary', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Djinni Summoning', 'Ring', 'Legendary', 'No', 'Varies', 'While wearing this ring, you can take a Magic action to summon a particular Djinni from the Elemental Plane of Air. The djinni appears in an unoccupied space you choose within 120 feet of yourself. It remains as long as you maintain Concentration, to a maximum of 1 hour, or until it drops to 0 Hit Points.

While summoned, the djinni is Friendly to you and your allies, and it obeys your commands. If you fail to command it, the djinni defends itself against attackers but takes no other actions.

After the djinni departs, it can’t be summoned again for 24 hours, and the ring becomes nonmagical if the djinni dies.

Rings of Djinni Summoning are often created by the djinn they summon and given to mortals as gifts of friendship or tokens of esteem.', FALSE, ARRAY['attuned', 'legendary', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Elemental Command', 'Each Ring of Elemental Command is linked to one of the four Elemental Planes. The DM chooses or randomly determines the linked plane. For example', 'Legendary', 'No', 'Varies', 'Every Ring of Elemental Command has the following two properties:

Elemental Bane. While wearing the ring, you have Advantage on attack rolls against Elementals and they have Disadvantage on attack rolls against you.

Elemental Compulsion. While wearing the ring, you can take a Magic action to try to compel an Elemental you see within 60 feet of yourself. The Elemental makes a DC 18 Wisdom saving throw. On a failed save, the Elemental has the Charmed condition until the start your next turn, and you determine what it does with its move and action on its next turn.

Elemental Focus. While wearing the ring, you benefit from additional properties corresponding to the ring’s linked Elemental Plane:

Air. You know Auran, you have Resistance to Lightning damage, and you have a Fly Speed equal to your Speed and can hover.

Earth. You know Terran, and you have Resistance to Acid damage. Terrain composed of rubble, rocks, or dirt isn’t Difficult Terrain for you. In addition, you can move through solid earth or rock as if those areas were Difficult Terrain without disturbing the matter through which you pass. If you end your turn in solid earth or rock, you are shunted out to the nearest unoccupied space you last occupied.

Fire. You know Ignan, and you have Immunity to Fire damage.

Water. You know Aquan, you gain a Swim Speed of 60 feet, and you can breathe underwater.

Spellcasting. The ring has 5 charges and regains 1d4 + 1 expended charges daily at dawn. While wearing the ring, you can cast a spell from it. Choose the spell from the list of available spells based on the Elemental Plane the ring is linked to, as shown in the following table. The table indicates how many charges you must expend to cast the spell, which has a save DC of 18.', FALSE, ARRAY['attuned', 'legendary', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Invisibility', 'Ring', 'Legendary', 'No', 'Varies', 'While wearing this ring, you can take a Magic action to give yourself the Invisible condition. You remain Invisible until the ring is removed or until you take a Bonus Action to become visible again.', FALSE, ARRAY['attuned', 'legendary', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Spell Turning', 'Ring', 'Legendary', 'No', 'Varies', 'While wearing this ring, you have Advantage on saving throws against spells. If you succeed on the save for a spell of level 7 or lower, the spell has no effect on you. If that spell targeted only you and didn’t create an area of effect, you can take a Reaction to deflect the spell back at the spell’s caster; the caster must make a saving throw against the spell using their own spell save DC.', FALSE, ARRAY['attuned', 'legendary', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ring of Three Wishes', 'Ring', 'Legendary', 'No', 'Varies', 'While wearing this ring, you can expend 1 of its 3 charges to cast Wish from it. The ring becomes nonmagical when you use the last charge.', FALSE, ARRAY['consumable', 'legendary', 'ring']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Robe of the Archmagi', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This elegant garment is made from exquisite cloth and adorned with runes.

You gain these benefits while wearing the robe.

Armor. If you aren’t wearing armor, your base Armor Class is 15 plus your Dexterity modifier.

Magic Resistance. You have Advantage on saving throws against spells and other magical effects.

War Mage. Your spell save DC and spell attack bonus each increase by 2.', FALSE, ARRAY['attuned', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rod of Lordly Might', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'Rod, Legendary (Requires Attunement)

This rod has a flanged head, and it functions as a magic Mace that grants a +3 bonus to attack rolls and damage rolls made with it. The rod has properties associated with six different buttons that are set in a row along the haft. It has three other properties as well, detailed below.

Buttons. You can press one of the following buttons as a Bonus Action; a button’s effect lasts until you push a different button or until you push the same button again, which causes the rod to revert to its normal form:

Button 1. A fiery blade sprouts from the end opposite the rod’s flanged head. The flames shed Bright Light in a 40-foot radius and Dim Light for an additional 40 feet, and the blade functions as a magic Longsword or Shortsword (your choice) that deals an extra 2d6 Fire damage on a hit.

Button 2. The rod’s flanged head folds down and two crescent-shaped blades spring out, transforming the rod into a magic Battleaxe that grants a +3 bonus to attack rolls and damage rolls made with it.

Button 3. The rod’s flanged head folds down, a spear point springs from the rod’s tip, and the rod’s handle lengthens into a 6-foot haft, transforming the rod into a magic Spear that grants a +3 bonus to attack rolls and damage rolls made with it.

Button 4. The rod transforms into a climbing pole up to 50 feet long (you specify the length), though the rod’s buttons remain within your reach. In surfaces as hard as granite, a spike at the bottom and three hooks at the top anchor the pole. Horizontal bars 3 inches long fold out from the sides, 1 foot apart, forming a ladder. The pole can bear up to 4,000 pounds. More weight or lack of solid anchoring causes the rod to revert to its normal form.

Button 5. The rod transforms into a handheld battering ram and grants its user a +10 bonus to Strength (Athletics) checks made to break through doors, barricades, and other barriers.

Button 6. The rod assumes or remains in its normal form and indicates magnetic north. (Nothing happens if this function of the rod is used in a location that has no magnetic north.) The rod also gives you knowledge of your approximate depth beneath the ground or your height above it.

Drain Life. When you hit a creature with a melee attack using the rod, you can force the target to make a DC 17 Constitution saving throw. On a failed save, the target takes an extra 4d6 Necrotic damage, and you regain a number of Hit Points equal to half that Necrotic damage. Once used, this property can’t be used again until the next dawn.

Paralyze. When you hit a creature with a melee attack using the rod, you can force the target to make a DC 17 Constitution saving throw. On a failed save, the target has the Paralyzed condition for 1 minute. The target repeats the save at the end of each of its turns, ending the effect on a success. Once used, this property can’t be used again until the next dawn.

Terrify. While holding the rod, you can take a Magic action to force each creature you can see within 30 feet of yourself to make a DC 17 Wisdom saving throw. On a failed save, a target has the Frightened condition for 1 minute. A Frightened target repeats the save at the end of each of its turns, ending the effect on itself on a success. Once used, this property can’t be used again until the next dawn.', FALSE, ARRAY['attuned', 'legendary', 'rod']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Scroll of Titan Summoning', 'Scroll', 'Legendary', 'No', 'Varies', 'When you take a Magic action to read this scroll, a particular titan named in the scroll appears in an unoccupied space on the ground or in water that you can see within 1 mile of yourself. The DM picks a suitable titan or determines it randomly by rolling on the table below (see the Monster Manual for the creature’s stat block).

The titan is Hostile toward all other creatures and disappears when it drops to 0 Hit Points. If the titan is summoned into a space that isn’t large enough to contain it, the summoning fails, and the scroll is wasted.', FALSE, ARRAY['consumable', 'legendary', 'scroll']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Rod of Resurrection', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'Rod, Legendary (Requires Attunement)

The rod has 5 charges. While you hold it, you can cast one of the following spells from it: Heal (expends 1 charge) or Resurrection (expends 5 charges).

The rod regains 1 expended charge daily at dawn. If you expend the last charge, roll 1d20. On a 1, the rod disappears in a harmless burst of radiance.', FALSE, ARRAY['attuned', 'legendary', 'rod']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Scarab of Protection', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This beetle-shaped medallion provides three benefits while it is on your person.

Defense. You gain a +1 bonus to Armor Class.

Preservation. The scarab has 12 charges. If you fail a saving throw against a Necromancy spell or a harmful effect originating from an Undead, you can take a Reaction to expend 1 charge and turn the failed save into a successful one. The scarab crumbles into powder and is destroyed when its last charge is expended.

Spell Resistance. You have Advantage on saving throws against spells.', FALSE, ARRAY['attuned', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sovereign Glue', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This viscous, milky-white substance can form a permanent adhesive bond between any two objects. It must be stored in a jar or flask that has been coated inside with Oil of Slipperiness. When found, a container contains 1d6 + 1 ounces.

One ounce of the glue can cover a 1-foot square surface. Applying an ounce of Sovereign Glue takes a Utilize action, and the applied glue takes 1 minute to set. Once it has done so, the bond it creates can be broken only by the application of Universal Solvent or Oil of Etherealness, or with a Wish spell.', FALSE, ARRAY['consumable', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sphere of Annihilation', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This 2-foot-diameter black sphere is a hole in the multiverse, hovering in space and stabilized by a magical field surrounding it.

The sphere obliterates all matter it passes through and all matter that passes through it. Artifacts are the exception. Unless an Artifact is susceptible to damage from a Sphere of Annihilation, it passes through the sphere unscathed. Anything else that touches the sphere but isn’t wholly engulfed and obliterated by it takes 8d10 Force damage.

Controlling the Sphere. A Sphere of Annihilation is stationary until someone takes control of it. If you are within 60 feet of a sphere, you can take a Magic action to make a DC 25 Intelligence (Arcana) check. On a successful check, you control the sphere until the start of your next turn, and if it was under another creature’s control, that creature loses control of the sphere. On a failed check, the sphere moves 10 feet toward you in a straight line.

While in control of the sphere, you can take a Bonus Action to cause it to move in one direction of your choice, up to a number of feet equal to 5 times your Intelligence modifier (minimum 5 feet). Any creature whose space the sphere enters must succeed on a DC 19 Dexterity saving throw or be touched by it, taking 8d10 Force damage. A creature reduced to 0 Hit Points by this damage is obliterated, leaving its possessions behind but no other physical remains.

Sphere Interactions. If the sphere comes into contact with a planar portal (such as that created by the Gate spell) or an extradimensional space (such as that within a Portable Hole), the DM determines randomly what happens using the following table.', FALSE, ARRAY['legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Staff of the Magi', 'Staff', 'Legendary', 'No', 'Varies', 'This staff has 50 charges and can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. While you hold it, you gain a +2 bonus to spell attack rolls.

Spell Absorption. While holding the staff, you have Advantage on saving throws against spells. In addition, you can take a Reaction when another creature casts a spell that targets only you. If you do, the staff absorbs the magic of the spell, canceling its effect and gaining a number of charges equal to the absorbed spell’s level. However, if doing so brings the staff’s total number of charges above 50, the staff explodes as if you activated its Retributive Strike (see below).

Spells. While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

Regaining Charges. The staff regains 4d6 + 2 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 20, the staff regains 1d12 + 1 charges.

Retributive Strike. You can take a Magic action to break the staff over your knee or against a solid surface. The staff is destroyed and releases its magic in an explosion that fills a 30-foot Emanation originating from itself. You have a 50 percent chance to instantly travel to a random plane of existence, avoiding the explosion. If you fail to avoid the effect, you take Force damage equal to 16 times the number of charges in the staff. Each other creature in the area makes a DC 17 Dexterity saving throw. On a failed save, a creature takes Force damage equal to 6 times the number of charges in the staff. On a successful save, a creature takes half as much damage.', FALSE, ARRAY['attuned', 'legendary', 'staff']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Talisman of Pure Good', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This talisman is a mighty symbol of goodness. A Fiend or an Undead that touches the talisman takes 8d6 Radiant damage and takes the damage again each time it ends its turn holding or carrying the talisman.

Holy Symbol. You can use the talisman as a Holy Symbol. You gain a +2 bonus to spell attack rolls while you wear or hold it.

Pure Rebuke. The talisman has 7 charges. While wearing or holding the talisman, you can take a Magic action to expend 1 charge and target one creature you can see on the ground within 120 feet of yourself. A flaming fissure opens under the target, and the target makes a DC 20 Dexterity saving throw. If the target is a Fiend or an Undead, it has Disadvantage on the save. On a failed save, the target falls into the fissure and is destroyed, leaving no remains. On a successful save, the target isn’t cast into the fissure but takes 4d6 Psychic damage from the ordeal. In either case, the fissure then closes, leaving no trace of its existence. When you expend the last charge, the talisman disperses into motes of golden light and is destroyed.', FALSE, ARRAY['attuned', 'consumable', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sword of Answering', 'Weapon (Longsword)', 'Legendary', 'No', 'Varies', 'You gain a +3 bonus to attack rolls and damage rolls made with this sword. In addition, while you hold the sword, you can take a Reaction to make one melee attack with it against any creature in your reach that deals damage to you. You have Advantage on the attack roll, and any damage dealt with this special attack ignores any Immunity or Resistance the target has to that damage.', FALSE, ARRAY['attuned', 'legendary', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Talisman of the Sphere', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'While holding or wearing this talisman, you have Advantage on any Intelligence (Arcana) check you make to control a Sphere of Annihilation. In addition, when you start your turn in control of a Sphere of Annihilation, you can take a Magic action to move it 10 feet plus a number of additional feet equal to 10 times your Intelligence modifier. This movement doesn’t have to be in a straight line.', FALSE, ARRAY['attuned', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Talisman of Ultimate Evil', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This item symbolizes unrepentant evil. A creature that isn’t a Fiend or an Undead that touches the talisman takes 8d6 Necrotic damage and takes the damage again each time it ends its turn holding or carrying the talisman.

Holy Symbol. You can use the talisman as a Holy Symbol. You gain a +2 bonus to spell attack rolls while you wear or hold it.

Ultimate End. The talisman has 6 charges. While wearing or holding the talisman, you can take a Magic action to expend 1 charge and target one creature you can see on the ground within 120 feet of yourself. A flaming fissure opens under the target, and the target makes a DC 20 Dexterity saving throw. If the target is a Celestial, it has Disadvantage on the save. On a failed save, the target falls into the fissure and is destroyed, leaving no remains. On a successful save, the target isn’t cast into the fissure but takes 4d6 Psychic damage from the ordeal. In either case, the fissure then closes, leaving no trace of its existence. When you expend the last charge, the talisman dissolves into foul-smelling slime and is destroyed.', FALSE, ARRAY['attuned', 'consumable', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Tome of the Dragon', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This heavy tome is bound in dragonhide and reinforced with thick bands of cold iron. The original copies were made by wyrmspeakers of the Cult of the Dragon and bear that cult’s symbol on their cover. The Tome of the Dragon contains the secret ritual to transform a dragon or a dead dragon’s body into a dracolich.

To decipher and use the Tome of the Dragon, you must be either a spellcaster with at least two level 5 spell slots or a Dragon. A single assistant (or more, at the DM’s discretion) can help you conduct the ritual, so long as that assistant also meets the requirements to use the tome.

To create a dracolich using a Tome of the Dragon, you must have continuous access to the body of an adult or ancient dragon (either living or dead), as well as 80,000 GP worth of supplies (which includes a gem that will serve as the anchor for the dracolich’s spirit). While you have the necessary materials, you must conduct a ritual that lasts 180 days divided by the number of creatures conducting the ritual. During the ritual, you and any assistants must work without interruption, resting no more than 8 hours per day. If you are a Dragon, the cost of supplies and the ritual’s duration are halved.

When the ritual is complete, the tome explodes with violet light, dealing 12d6 Necrotic damage to you and each assistant. If this damage reduces a creature to 0 Hit Points, the creature is killed and immediately reanimates as a Zombie under the DM''s control.

At the end of the ritual, the target transforms into a Dracolich. If the ritual’s target was a living dragon, that dragon dies instantly, and its spirit is transferred to the gem supplied for the ritual. If the target was a dead dragon’s body, the body reanimates, and the gem is inhabited by an evil dragon spirit from the Outer Planes. The dracolich is under no obligation toward its creators and acts according to its nature.', FALSE, ARRAY['fraif', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Tome of the Stilled Tongue', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This book has a desiccated tongue pinned to its front cover. Five of these tomes exist, and it’s unknown which one is the original. The tongue on the first Tome of the Stilled Tongue belonged to a treacherous former servant of the lich Vecna. The tongues pinned to the covers of the four copies came from other spellcasters who crossed Vecna. The first few pages of each tome are filled with indecipherable scrawls. The remaining pages are blank.

While attuned to this item, you can use it as a Spellbook and an Arcane Focus. In addition, while holding the tome, you can take a Bonus Action to cast a spell you have written in this tome, without expending a spell slot or using any Verbal or Somatic components. Once used, this property of the tome can’t be used again until the next dawn.

Only you can remove the tongue from the book’s cover. If you do so, all spells written in the book are permanently erased.

Vecna watches anyone using this tome and can write cryptic messages in it. These messages typically fade away after they are read.', FALSE, ARRAY['attuned', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Universal Solvent', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This tube holds milky liquid with a strong alcohol smell. When found, a tube contains 1d6 + 1 ounces.

You can take a Utilize action to pour 1 or more ounces of solvent from the tube onto a surface within reach. Each ounce instantly dissolves up to 1 square foot of adhesive it touches, including Sovereign Glue.', FALSE, ARRAY['consumable', 'legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Vorpal Sword', 'Weapon (Glaive', 'Legendary', 'No', 'Varies', 'You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. In addition, the weapon ignores Resistance to Slashing damage.

When you use this weapon to attack a creature that has at least one head and roll a 20 on the d20 for the attack roll, you cut off one of the creature’s heads. The creature dies if it can’t survive without the lost head. A creature is immune to this effect if it has Immunity to Slashing damage, if it doesn’t have or need a head, or if the DM decides that the creature is too big for its head to be cut off with this weapon. Such a creature instead takes an extra 30 Slashing damage from the hit. If the creature has Legendary Resistance, it can expend one daily use of that trait to avoid losing its head, taking the extra damage instead.', FALSE, ARRAY['attuned', 'legendary', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Well of Many Worlds', 'Wondrous Item', 'Legendary', 'No', 'Varies', 'This fine black cloth, soft as silk, is folded up to the dimensions of a handkerchief. It unfolds into a circular sheet 6 feet in diameter.

You can take a Magic action to unfold the Well of Many Worlds and place it on a solid surface, whereupon it forms a two-way, 6-foot-diameter, circular portal to another world or plane of existence. Each time the item opens a portal, the DM decides where it leads. The portal remains open until a creature within 5 feet of it takes a Magic action to close it by taking hold of the edges of the cloth and folding it up.

Once the Well of Many Worlds has opened a portal, it can’t do so again for 1d8 hours.', FALSE, ARRAY['legendary', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Axe of the Dwarvish Lords', 'Weapon (Battleaxe)', 'Artifact', 'No', 'Varies', 'A young dwarf prince set out to forge a weapon that would be regarded as a symbol of unity among his people. Venturing deep under the mountains, deeper than any dwarf had ever delved, the prince came to the blazing heart of a great volcano. With the aid of Moradin, a god of creation, he first crafted four mighty tools: the Starmetal Pick, the Earthheart Forge, the Anvil of Songs, and the Shaping Hammer. With these tools, he forged the Axe of the Dwarvish Lords.

Armed with the Artifact, the prince brought peace to the dwarf clans, ending grudges and answering slights. The clans became allies, and they threw back their enemies and enjoyed an era of prosperity. This young dwarf is remembered as the First King. When he became old, he passed the weapon, which had become his badge of office, to his heir. The rightful inheritors passed the axe on for many generations.

Later, in an era marked by treachery and wickedness, the axe was lost in a bloody civil war fomented by greed for its power and the status it bestowed. Centuries later, the dwarves still search for the axe, and many adventurers have made careers of chasing after rumors and plundering old vaults to find it.

Magic Weapon. The Axe of the Dwarvish Lords is a magic weapon that grants a +3 bonus to attack rolls and damage rolls made with it.

When you attack a creature with the axe and roll a 20 on the d20 for the attack roll, the axe deals an extra 20 Slashing damage.

The axe has the Thrown property with a normal range of 20 feet and a long range of 60 feet. When you hit with a ranged attack using this weapon, it deals an extra 1d8 Force damage, or an extra 2d8 Force damage if the target is a creature of the Giant type. Immediately after hitting or missing, the weapon flies back to your hand.

Blessings of Moradin. While attuned to the axe, you gain the following benefits:

Darkvision. You gain Darkvision with a range of 60 feet. If you already have Darkvision, its range increases by 60 feet.

Fortitude of Stone. Your Constitution increases by 2, to a maximum of 20.

Gifts of the Creator. You have proficiency with Brewer’s Supplies, Mason’s Tools, and Smith’s Tools.

One with the Forge. You have Immunity to Poison damage and Resistance to Fire damage.

Sunder. When you hit an object with the axe, the object takes the maximum amount of damage possible.

Conjure Earth Elemental. While holding the axe, you can take a Magic action to summon an Earth Elemental. It appears in an unoccupied space you choose within 30 feet of yourself, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 24 hours, when it dies, or when you dismiss it as a Bonus Action. You can’t use this property again until the next dawn.

Random Properties. The axe has the following random properties (see “Artifacts”):

Travel the Depths. You can take a Magic action to touch the axe to a fixed piece of dwarven stonework and cast Teleport from the axe. If your intended destination is underground, there is no chance of a mishap or arriving somewhere unexpected. You can’t use this property again until 3 days have passed.

Destroying the Axe. The only way to destroy the axe is to melt it down in the Earthheart Forge, where it was created. It must remain in the burning forge for 50 years before it finally succumbs to the fire and is consumed.', FALSE, ARRAY['artifact', 'attuned', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Blackrazor', 'Weapon (Greatsword)', 'Artifact', 'No', 'Varies', 'Hidden in the dungeon of White Plume Mountain, Blackrazor shines like a piece of night sky filled with stars. Its black scabbard is decorated with pieces of cut obsidian.

You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. If you hit an Undead with this weapon, you take 1d10 Necrotic damage, and the target regains 1d10 Hit Points. If this Necrotic damage reduces you to 0 Hit Points, Blackrazor devours your soul (see “Devour Soul” below).

While you hold this weapon, you have Immunity to the Charmed and Frightened conditions, and you have Blindsight with a range of 30 feet.

Devour Soul. Whenever you use Blackrazor to reduce a creature to 0 Hit Points, the sword slays the creature and devours its soul unless it is a Construct or an Undead. A creature whose soul has been devoured by Blackrazor can be restored to life only by a Wish spell.

When Blackrazor devours a soul that isn’t yours, you gain Temporary Hit Points equal to the slain creature’s Hit Point maximum.

Haste. Blackrazor can cast Haste on you, after which it can’t cast this spell again until the next dawn. Blackrazor decides when to cast the spell, which takes effect at the start of your turn. The spell lasts for 1 minute (no Concentration required) or until Blackrazor decides to end it, which it can do at the end of any of your turns.

Sentience. Blackrazor is a sentient Chaotic Neutral weapon with an Intelligence of 17, a Wisdom of 10, and a Charisma of 19. It has hearing and Darkvision out to 120 feet.

The weapon speaks Common and can communicate with its wielder telepathically. Its voice is deep and echoing. While you are attuned to it, Blackrazor also understands every language you know.

Personality. Blackrazor speaks with an imperious tone, as though accustomed to being obeyed.

The sword’s purpose is to consume souls. It doesn’t care whose souls it eats, including the wielder’s. The sword believes that all matter and energy sprang from a void of negative energy and will one day return to it. Blackrazor is meant to hurry that process along.

Despite its nihilism, Blackrazor feels a strange kinship to Wave and Whelm, two other weapons locked away under White Plume Mountain. It wants the three weapons to be reunited and wielded together in combat, even though it violently disagrees with Whelm and finds Wave tedious.

Blackrazor’s hunger for souls must be regularly fed. If the sword goes 3 days or more without consuming a soul, a conflict between it and its wielder occurs at the next sunset.

Destroying Blackrazor. Blackrazor can be destroyed by crushing it in the great gears of Mechanus. Primus, the creator of the modrons, also knows a series of musical tones that Blackrazor can’t stand to hear, causing the sword to shatter.', FALSE, ARRAY['artifact', 'attuned', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Book of Exalted Deeds', 'Wondrous Item', 'Artifact', 'No', 'Varies', 'The definitive treatise on all that is good in the multiverse, the Book of Exalted Deeds figures prominently in many religions. Rather than being a scripture devoted to a particular faith, the book’s authors filled the pages with their own visions of true virtue, providing guidance for defeating evil.

The Book of Exalted Deeds rarely lingers in one place. As soon as the book is read, it vanishes to some other corner of the multiverse where its moral guidance can bring hope to an endangered world. Although attempts have been made to copy the work, efforts to do so fail to capture its magical nature or translate the benefits it offers to those pure of heart and firm of purpose.

A heavy clasp, wrought to look like angel wings, keeps the book’s contents secure. Only a creature that is attuned to the book can release the clasp that holds it shut. Once the book is opened, the attuned creature must spend 80 hours reading and studying the book to digest its contents and gain its benefits.

Other creatures that peruse the book’s open pages can read the text but glean no deeper meaning and reap no benefits. A Fiend, an Undead, or a servant of a god from the Lower Planes that tries to read from the book takes 24d6 Radiant damage. This damage ignores Resistance and Immunity, and it can’t be reduced or avoided by any means. A creature reduced to 0 Hit Points by this damage disappears in a flash and is destroyed, leaving its possessions behind. The book then vanishes, and the creature’s Attunement to it ends.

Benefits granted by the Book of Exalted Deeds last only as long as you strive to do good. If you fail to perform at least one act of kindness or generosity within the span of 10 days, or if you willingly perform an evil act, you lose all the benefits granted by the book.

Celestial Calm. While attuned to the book, you have Immunity to the Charmed and Frightened conditions and Resistance to Psychic damage. These benefits become permanent after you spend the requisite amount of time reading and studying the book.

Divine Wisdom. After you spend the requisite amount of time reading and studying the book, your Wisdom increases by 2, to a maximum of 24. You can’t gain this benefit from the book more than once.

Enlightened Magic. After you spend the requisite amount of time reading and studying the book, any spell slot you expend to cast a spell counts as a spell slot of one level higher.

Halo. After you spend the requisite amount of time reading and studying the book, you gain a protective halo. This halo sheds Bright Light in a 10-foot radius and Dim Light for an additional 10 feet. You can dismiss or manifest the halo as a Bonus Action. While present, the halo gives you Advantage on Charisma (Persuasion) checks. In addition, Fiends and Undead within the halo’s Bright Light make attack rolls against you with Disadvantage.

Random Properties. The Book of Exalted Deeds has the following random properties (see “Artifacts”):

Destroying the Book. The Book of Exalted Deeds can’t be destroyed. However, drowning the book in the River Styx removes all writing and imagery from its pages and renders the book powerless for 1d100 years.', FALSE, ARRAY['artifact', 'attuned', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Book of Vile Darkness', 'Wondrous Item', 'Artifact', 'No', 'Varies', 'The contents of this foul manuscript are the meat and drink of the wicked. It contains knowledge so horrid that to even glimpse the scrawled pages invites doom.

Most believe the lich-god Vecna authored the Book of Vile Darkness. He recorded in its pages every horrid idea, every corrupt thought, and every example of foul magic he came across or devised.

Other practitioners of evil have added their own input to the book’s catalog of vile knowledge. Their additions are clear, for the writers of later works stitched whatever they were writing into the tome or, in some cases, made notations and additions to existing text. There are places where pages are missing, torn, or covered so completely with ink, blood, and scratches that the original text can’t be divined.

Nature can’t abide the book’s presence. Ordinary plants wither in its presence, common animals are unwilling to approach it, and the book gradually destroys whatever it touches. Even stone cracks and turns to powder if the book rests on it long enough.

Whenever a creature that isn’t a Fiend or an Undead attunes to the Book of Vile Darkness, that creature makes a DC 17 Charisma saving throw. On a failed save, the creature is magically transformed into a Larva under the DM’s control. Only a Wish spell can reverse this vile transformation.

A creature attuned to the book must spend 80 hours reading and studying it to digest its contents and use its Adjusted Ability Scores, Tireless Form, Spells, Vile Lore, and Vile Speech properties.

The Book of Vile Darkness remains with you only as long as you strive to work evil in the world. If you fail to perform at least one evil act within the span of 10 days, or if you willingly perform a good act, the book disappears, your Attunement to it ends immediately, and you lose all benefits granted by it. If you die while attuned to the book, an entity of great evil claims your soul. You can’t be restored to life by any means while your soul remains imprisoned.

Adjusted Ability Scores. One ability score of your choice increases by 2, to a maximum of 24. Another ability score of your choice decreases by 2, to a minimum of 3. The book can’t adjust your ability scores again.

Tireless Form. While the book is on your person, you have Immunity to the Exhaustion condition.

Random Properties. The Book of Vile Darkness has the following random properties (see “Artifacts”):

Spells. While attuned to the book and holding it, you can cast the following spells (save DC 18) from it:

Once you use the book to cast a spell, you can’t cast that spell again from it until the next dawn.

Vile Lore. You can reference the Book of Vile Darkness whenever you make an Intelligence check to recall information about some aspect of evil, such as lore about demons. When you do so, you have Advantage on that check.

At the DM’s discretion, the book might reveal secrets no mortal should know, such as the true names of powerful Fiends, foul rites that allow one to transform into a death knight or lich, or long-lost spells crafted by beings so evil their names ought never to be spoken aloud.

Vile Speech. While the book is on your person, you can take a Magic action to recite words from its pages in a foul, dead language. Each time you do so, you take 1d12 Psychic damage, and each creature within 15 feet of you takes 3d6 Psychic damage unless the creature is a Fiend or an Undead.

Destroying the Book. The Book of Vile Darkness allows pages to be torn from it, but any evil lore contained on those pages finds its way back into the book eventually, usually when a new author adds pages to the tome.

If a solar tears the book in two, the book is destroyed for 1d100 years, after which it re-forms in some far corner of the multiverse.

A creature attuned to the book for 100 years can unearth a phrase hidden in the original text that, when translated to Celestial and spoken aloud, destroys both the speaker and the book in a flash of radiance. However, as long as evil exists in the multiverse, the book re-forms 1d10 × 100 years later.', FALSE, ARRAY['artifact', 'attuned', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Calimemnon Crystal', 'Wondrous Item', 'Artifact', 'No', 'Varies', 'This immaculately cut sixty-sided diamond fits in one hand, yet it contains an entire genie empire. The Calimemnon Crystal was made by high elf magic to imprison the notorious genie lords Calim and Memnon, who once ruled and warred over what is now Calimshan.

When viewed by a creature with Truesight, the normally beautiful diamond is a grotesque sight: trapped within the gemstone are more than a hundred genies, including the physical forms of Calim and Memnon. The genies scream and strain in agonized fury, pressing their belligerent faces against the walls of their crystalline prison.

Properties of the Crystal. While attuned to the crystal, you gain the following benefits:

Arcane Focus. You can use the Calimemnon Crystal as an Arcane Focus.

Flight. You have a Fly Speed of 30 feet and can hover.

Spells. You can cast these spells with the crystal (spell save DC 18): Create or Destroy Water, Enlarge/Reduce, Invisibility (targeting yourself only), and Major Image.

Aura of Cold. The temperature drops precipitously in a 20-foot Emanation originating from the crystal. Whenever the Emanation enters a creature’s space and whenever a creature enters the Emanation or ends its turn there, the creature takes 2d6 Cold damage. A creature takes this damage only once per turn. While attuned to the crystal, you are unaffected by the aura, and you can take a Magic action to disable or enable the aura.

Healing/Damage Rays. While holding the crystal, you can take a Magic action to fire six rays of volatile energy from the crystal at one or more creatures within 60 feet. You can aim the rays at one target or at several. For each ray, choose one of the following effects:

Damage Ray. The target makes a DC 18 Dexterity saving throw, taking 6d6 + 6 Radiant damage on a failed save or half as much damage on a successful one.

Healing Ray. The target regains 2d6 + 2 Hit Points.

This property can’t be used again until the next dawn.

Random Properties. The Artifact has the following random properties (see chapter 7 of the Dungeon Master’s Guide):

Destroying the Crystal. The Calimemnon Crystal is destroyed if the creature attuned to it casts the Wish spell and wishes the crystal destroyed. Nothing else can harm it. When the crystal is destroyed, all the genies in the crystal are released.', FALSE, ARRAY['artifact', 'attuned', 'fraif', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Crown Of Horns', 'Wondrous Item', 'Artifact', 'No', 'Varies', 'The Crown of Horns contains the essence and intelligence of Myrkul, one of the Dead Three. This ghastly crown is a pale silver circlet with four curved bones set around its rim. On the crown''s brow is set a black diamond whose depths swirl with weird, malignant energy.

Myrkul created the Crown of Horns at the height of his power. When Myrkul was slain by Mystra, he imbued the crown with his dying essence. Myrkul has since returned to become one of the Dead Three, and the Crown of Horns continues to further his gruesome will by seeking out mortal agents and gradually transforming them into powerful Undead scions. Should a wearer prove unworthy of this honor, the crown teleports away to find a new mortal to corrupt for its master.

Cursed. The crown is cursed. Attuning to the crown extends the curse to you. Only a Wish spell or the will of Myrkul can remove this curse. As long as you remain cursed, the following properties apply to you:

Bound. You are unwilling to part with the crown, wearing it at all times, and you can’t voluntarily end your Attunement to the crown.

Cruel. Your alignment becomes Neutral Evil.

Doomed. You slowly transform into a monstrous servant of Myrkul over the course of 365 days. During that time, the transformation is purely cosmetic; these cosmetic changes slowly fade if you end Attunement to the crown before completing the transformation. When the transformation is complete, you become a Lich under the DM’s control. Each time you use this Artifact’s Cone of Undeath or Myrkul’s Hand benefit, there is a 10 percent cumulative chance that you instantly complete this transformation.

Cone of Undeath. You can take a Magic action to unleash a wave of unholy light in a 60-foot Cone. Each creature in the Cone makes a DC 18 Constitution saving throw, taking 4d8 Necrotic damage on a failed save or half as much damage on a successful one. A Humanoid killed by Cone of Undeath rises at the start of your next turn as a Specter that follows your verbal orders.

Damage Immunity. You have Immunity to Necrotic damage.

Fear Aura. While wearing the crown, you emit an aura of terrifying energy in a 60-foot Emanation. A creature that enters this area for the first time on a turn or starts its turn there must succeed on a DC 16 Wisdom saving throw or have the Frightened condition. A Frightened target must use its movement on its turns to get as far away as possible from you, moving by the safest route.

If you damage a Frightened target or if a Frightened target ends its turn more than 120 feet away from you, the target can repeat the Wisdom save, ending the condition on itself on a success. A creature that succeeds on the save against this effect is immune to it for 1 minute, after which it can be affected again.

The aura is inactive while you have the Incapacitated condition. You can activate or deactivate the aura as a Bonus Action.

Myrkul’s Hand. While wearing the crown, you can cast the Power Word Kill spell (save DC 18) from it. A Humanoid killed by this spell rises at the start of your next turn as a Wraith that follows your verbal orders. Once you use the crown to cast this spell, you can’t cast it again from the crown until the next dawn.

Teleportation. While wearing the crown, you can cast the Teleport spell. The crown can also cast this spell of its own free will. Once the spell has been cast using the crown, it can’t be cast again until 7 days have passed.

Random Properties. The Artifact has the following random properties (see chapter 7 of the Dungeon Master’s Guide):

Sentience. The Crown of Horns is a sentient Neutral Evil Artifact with an Intelligence of 10, a Wisdom of 16, and a Charisma of 19. It has hearing and Darkvision out to 120 feet.

The crown communicates telepathically with its wearer and knows Common.

Personality. The crown contains the essence of Myrkul and exists to spread that god’s will, which is to slay the living, raise the dead, and sow fear across the Material Plane. The crown urges its wearer to spread dread and destruction wherever possible.

Destroying the Crown. The crown is destroyed if it is worn by Myrkul’s successor, Kelemvor, while he sits on the throne of Myrkul’s former realm, the Bone Castle.', FALSE, ARRAY['artifact', 'attuned', 'fraif', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Demonomicon of Iggwilv', 'Wondrous Item', 'Artifact', 'No', 'Varies', 'This treatise, composed by Iggwilv the archmage, documents the Abyss’s layers and inhabitants and is widely regarded as the most thorough and blasphemous tome of demonology in the multiverse. The tome recounts both the oldest and most current profanities of the Abyss and demons. Demons have attempted to censor the text, and while sections have been ripped from the book’s spine, the general chapters remain, ever revealing demonic secrets. Caged behind lines of script roils a secret piece of the Abyss itself, which keeps the book up-to-date, no matter how many pages are removed, and it longs to be more than mere reference material.

Abyssal Lore. You can reference the Demonomicon whenever you make an Intelligence check to discern information about demons or a Wisdom (Survival) check related to the Abyss. When you do so, you gain Advantage on the check.

Containment. The first ten pages of the Demonomicon are blank. As a Magic action while holding the book, you can target a Fiend that you can see that is trapped within the area of a Magic Circle spell. The Fiend must succeed on a DC 20 Charisma saving throw with Disadvantage or become trapped within one of the Demonomicon’s blank pages, which fills with writing detailing the trapped creature’s widely known name and depravities. Once used, this action can’t be used again until the next dawn.

When you finish a Long Rest, if you and the Demonomicon are on the same plane of existence, one trapped creature within the book can attempt to possess you. You make a DC 20 Charisma saving throw. On a failed save, you are possessed by the creature, which controls you like a puppet. As a Magic action, the possessing creature can release you and appear in the closest unoccupied space to you. On a successful save, the Fiend can’t try to possess you again for 7 days (but another Fiend trapped in the book can certainly try).

When the tome is discovered, it has 1d4 Fiends occupying its pages—typically an assortment of demons.

Ensnarement. While carrying the book, whenever you cast Magic Circle naming only Fiends or cast Planar Binding targeting a Fiend, the spell is cast at level 9, regardless of what level spell slot you used, if any. Additionally, the Fiend has Disadvantage on its saving throw against the spell.

Fiendish Scourging. While carrying the book, when you make a damage roll for a spell you cast against a Fiend, you use the maximum possible result instead of rolling.

Random Properties. The Artifact has the following random properties (see “Artifacts”):

Spells. The book has 8 charges and regains 1d8 expended charges daily at dawn. While holding the book, you can take a Magic action to cast one of the spells (save DC 20) on the following table. The table indicates how many charges you must expend to cast the spell.

Destroying the Demonomicon. To destroy the book, six different demon lords must each tear out a sixth of the book’s pages. If this occurs, the pages reappear after 24 hours. Before all those hours pass, anyone who opens the book’s remaining binding is transported to a nascent layer of the Abyss that lies hidden within the book. At the heart of this deadly, semisentient domain lies a long-lost Artifact, Fraz-Urb’luu’s Staff. If the staff is dragged from the pocket plane, the tome is reduced to a mundane and out-of-date copy of the Tome of Zyx, the work that served as the foundation of the Demonomicon of Iggwilv. The Tome of Zyx can be destroyed like any ordinary book. Once the staff emerges, the demon lord Fraz-Urb’luu knows instantly.', FALSE, ARRAY['artifact', 'attuned', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Ebonbane', 'Weapon (Longsword)', 'Artifact', 'No', 'Varies', 'The Darklord of the Domain of Dread known as the Shadowlands is Ebonbane, a sapient sword. Ebonbane uses its monster stat block while in Shadowborn Manor.

Bound to the Shadowlands. When you enter a space outside of the Shadowlands, your Attunement immediately ends and Ebonbane teleports to somewhere in Shadowborn Manor.

Insatiable Rage. The sword demands destruction. If the sword hasn’t slain a Celestial or a Humanoid for 3 days, you make a DC 17 Charisma saving throw at the next dawn. On a successful save, you take 8d8 Force damage. On a failed save, you are dominated by the sword, as if by the Dominate Monster spell, and the sword demands the blood of a Celestial or a Humanoid. The spell effect ends when the sword’s demand is met.

Magic Weapon. You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. When you hit a Celestial or a Humanoid with it, that attack also deals 3d6 Necrotic damage.

While you hold this weapon, you have Advantage on saving throws against spells and other magical effects.

Sentience. Ebonbane is a sentient Chaotic Evil weapon with an Intelligence of 17, a Wisdom of 14, and a Charisma of 19. It has hearing and Truesight out to 120 feet. The weapon speaks Common and can communicate with its wielder telepathically. While you are attuned to it, Ebonbane also understands every language you know.

Personality. Ebonbane was created to kill the paladin Kateri Shadowborn, and it still possesses a burning hatred for goodly knights. Ebonbane revels in seeing good defeated and hope vanquished. The sword bonds with any wielder that assists in its goals but always views it wielder as a lackey.

Destroying Ebonbane. The only way to destroy Ebonbane is to forge a weapon from the Four Keys and reduce Ebonbane to 0 Hit Points with it (see the Ebonbane stat block).', FALSE, ARRAY['artifact', 'attuned', 'rthw', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Eye and Hand of Vecna', 'Wondrous Item', 'Artifact', 'No', 'Varies', 'Vecna was a mighty wizard who, through magic and conquest, forged a terrible empire. For all his power, however, Vecna feared death and took steps to prevent his demise by becoming a lich.

A treacherous lieutenant named Kas brought Vecna’s rule to an end in a terrible battle. Of Vecna, all that remained were one hand and one eye, grisly Artifacts that still seek to work Vecna’s will in the world.

The Eye of Vecna and the Hand of Vecna are separate Artifacts that might be found together or separately. The eye looks like a bloodshot organ torn free from the socket. The hand is a shriveled left extremity.

Random Properties of the Eye and Hand. The Eye of Vecna and the Hand of Vecna each have the following random properties (see “Artifacts”):

Attuning to the Eye. To attune to the eye, you must press it into your empty socket. The eye grafts itself to your head and remains there until you die. If the eye is ever removed, you die.

Properties of the Eye. While you are attuned to the eye, your alignment is Neutral Evil, and you gain the following benefits:

Truesight. You have Truesight out to 240 feet.

Spellcasting. The eye has 8 charges and regains 1d4 + 4 expended charges daily at dawn. You can cast a spell on the Eye of Vecna Spells table from the eye (save DC 18). The table indicates how many charges you must expend to cast the spell. Each time you cast a spell from the eye, there is a 5 percent chance that Vecna tears your soul from your body, devours it, and then takes control of the body like a puppet. If that happens, you become an NPC under the DM’s control.

X-ray Vision. You can take a Magic action to gain X-ray vision with a range of 30 feet for 1 minute. To you, solid objects within that radius appear transparent and don’t prevent light from passing through themselves. The vision can penetrate 1 foot of stone, 1 inch of common metal, or up to 3 feet of wood or dirt. Thicker substances block the vision, as does a thin sheet of lead.

Attuning to the Hand. To attune to the hand, you must press it against the stump where your left hand was. The hand grafts itself to your arm and becomes a functioning appendage. If the hand is ever removed, you die.

Properties of the Hand. When you are attuned to the hand, your alignment is Neutral Evil, and you gain the following benefits:

Great Strength. Your Strength becomes 20 unless it is already 20 or higher.

Icy Touch. Any melee spell attack you make with the hand and any melee attack made with a weapon held by it deals an extra 2d8 Cold damage on a hit.

Spellcasting. The hand has 8 charges and regains 1d4 + 4 expended charges daily at dawn. You can cast a spell on the Hand of Vecna Spells table from the hand (save DC 18). The table indicates how many charges you must expend to cast the spell. Each time you cast a spell from it, the hand casts Suggestion on you (save DC 18; no Concentration required), demanding that you commit an evil act. The hand might have a specific act in mind or leave it up to you.

Properties of the Eye and Hand. While attuned to both the hand and eye, you gain the following additional benefits:

Danger Sense. You have Advantage on Initiative rolls.

Necrotic Reduction. As a Magic action, you can target one creature you can see within 5 feet of yourself. The target makes a DC 18 Constitution saving throw, taking 7d6 Necrotic damage on a failed save or half as much damage on a successful one. A creature reduced to 0 Hit Points by this damage is transformed into green slime (see chapter 3) that covers the ground in its space, each 5-foot square of slime representing a separate patch. Nonmagical objects worn or carried by the target that are made of metal or organic material are destroyed by the slime.

Poison Immunity. You have Immunity to Poison damage and the Poisoned condition.

Regeneration. If you start your turn with at least 1 Hit Point, you regain 1d10 Hit Points.

Wish. You can cast Wish. Once used, this property can’t be used again until 30 days have passed.

Destroying the Eye and Hand. If the Eye of Vecna and the Hand of Vecna are both attached to the same creature and that creature is slain by the Sword of Kas, both the eye and the hand burst into flame, turn to ash, and are destroyed. Any other attempt to destroy the eye or hand seems to work, but the Artifact reappears in one of Vecna’s many hidden vaults, where it waits to be rediscovered.', FALSE, ARRAY['artifact', 'attuned', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Orb of Damara', 'Wondrous Item', 'Artifact', 'No', 'Varies', 'A wizard named Damara created this orb while devising a way to become a dragon. Aided by a mysterious magician (actually an aspect of Tiamat in disguise), Damara eventually created an Artifact that would enable him to achieve his dream. Yet the potential power of his creation terrified Damara so much that he dared not use the orb. Instead, the wizard entombed himself with the Artifact to seal it away.

The Orb of Damara is about 6 inches in diameter and is made of a glassy, iridescent material that''s like obsidian but incredibly hard. If held to one’s own lips with the intention of consuming it, the orb shrinks to the size of a grape.

Properties of the Orb. While attuned to the orb, you gain the following benefits:

Dragon’s Breath. You can take a Magic action to exhale a 15-foot Cone. When you do, choose Acid, Cold, Fire, Lightning, or Poison. Each creature in the Cone makes a DC 18 Dexterity saving throw, taking 6d6 damage of the chosen type on a failed save or half as much damage on a successful one.

Fear Aura. You exude a terrifying aura in a 20-foot Emanation while you don’t have the Incapacitated condition. You can take a Magic action to disable or enable this aura. Any enemy that starts its turn in the aura must succeed on a DC 18 Wisdom saving throw or have the Frightened condition until the start of its next turn. A creature that succeeds on this save is immune to the aura’s effects for 24 hours.

Flight. You have a Fly Speed of 60 feet and can hover.

Random Properties. The Artifact has the following random properties (see chapter 7 of the Dungeon Master’s Guide):

Spellcasting. The orb has 6 charges and regains 1d4 + 2 expended charges daily at dawn. While attuned to the orb, you can cast one of the spells on the following table from it (+10 spell attack modifier, spell save DC 18). The table indicates how many charges you must expend to cast the spell.

Dragon Transformation. If you swallow the orb, you transform into an adult chromatic dragon under the DM’s control. The type of chromatic dragon depends on your alignment and personality and is left to the DM to decide. The transformation is permanent, but if the dragon is slain, its body reverts to its original form and the orb reappears outside its body.

Destroying the Orb. If an Ancient Gold Dragon willingly swallows the orb, the orb and the dragon are both destroyed.', FALSE, ARRAY['artifact', 'attuned', 'fraif', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Orb of Dragonkind', 'Wondrous Item', 'Artifact', 'No', 'Varies', 'Long ago, in the Dragonlance setting, elves and humans waged a terrible war against chromatic dragons. When the world seemed doomed, the wizards of the Towers of High Sorcery came together and forged five Orbs of Dragonkind to help defeat the dragons. One orb was taken to each of the five towers, and there they were used to speed the war toward a victorious end. The wizards used the orbs to lure dragons to them, then destroyed the dragons with powerful magic.

As the Towers of High Sorcery fell in later ages, the orbs were destroyed or faded into legend, and only three are thought to survive. Their magic has been warped over the centuries. Their primary purpose of calling dragons still functions, but they also allow some measure of control over dragons.

Each orb contains the essence of an evil dragon, a presence that resents any attempt to coax magic from it. Those who try to wield an orb’s magic but lack sufficient force of personality might find themselves under the orb’s control.

An orb is an etched crystal globe about 10 inches in diameter. When used, it grows to about 20 inches in diameter, and mist swirls inside it.

While attuned to an orb, you can take a Magic action to peer into the orb’s depths. You must then make a DC 15 Charisma saving throw. On a successful save, you control the orb for as long as you remain attuned to it. On a failed save, the orb imposes the Charmed condition on you for as long as you remain attuned to it.

While you are Charmed by the orb, you can’t voluntarily end your Attunement to it, and the orb casts Suggestion on you at will (save DC 18), urging you to work toward the evil ends it desires. The dragon essence within the orb might want many things: the annihilation of a particular society or organization, freedom from the orb, to spread suffering in the world, to advance the worship of Tiamat, or something else the DM decides.

Random Properties. An Orb of Dragonkind has the following random properties (see “Artifacts”):

Spells. The orb has 7 charges and regains 1d4 + 3 expended charges daily at dawn. If you control the orb, you can cast one of the spells on the following table from it. The table indicates how many charges you must expend to cast the spell.

Call Dragons. While you control the orb, you can take a Magic action to cause the orb to issue a telepathic call that extends in all directions for 40 miles. Chromatic dragons in range feel compelled to come to the orb as soon as possible by the most direct route. Dragon deities such as Tiamat are unaffected by this call. Chromatic dragons drawn to the orb might be Hostile toward you for compelling them against their will. Once you have used this property, it can’t be used again for 1 hour.

Destroying an Orb. An Orb of Dragonkind has AC 20 and is destroyed if it takes damage from a +3 Weapon or a Disintegrate spell. Nothing else can harm it.', FALSE, ARRAY['artifact', 'attuned', 'wondrous-item']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wand of Orcus', 'Wand', 'Artifact', 'No', 'Varies', 'Crafted and wielded by Orcus, this ghastly wand slips from the demon lord’s grasp from time to time. When it does, it magically appears wherever the demon lord senses an opportunity to achieve some fell goal.

The wand is topped with a skull that once belonged to a human hero slain by Orcus. The wand can magically change in size to better conform to the grip of its user. All Holy Water within 10 feet of the wand is destroyed.

Any creature besides Orcus that tries to attune to the wand makes a DC 17 Constitution saving throw. On a successful save, the creature takes 10d6 Necrotic damage. On a failed save, the creature dies and, if it is a Humanoid, turns into a Zombie.

Magic Weapon. You can wield the wand as a magic Mace that grants a +3 bonus to attack rolls and damage rolls made with it. The wand deals an extra 2d12 Necrotic damage on a hit.

Random Properties. The Wand of Orcus has the following random properties (see “Artifacts”):

The detrimental properties of the Wand of Orcus are suppressed while the wand is attuned to Orcus.

Protection. You gain a +3 bonus to Armor Class while holding the wand.

Spells. The wand has 7 charges and regains 1d4 + 3 expended charges daily at dawn. While holding the wand, you can cast one of the spells on the following table from it (save DC 18). The table indicates how many charges you must expend to cast the spell.

While attuned to the wand, Orcus or a follower blessed by him can cast each of the wand’s spells using 2 fewer charges (minimum of 0).

Call Undead. While holding the wand, you can take a Magic action to conjure 15 Skeletons and 15 Zombies. These Undead magically rise up from the ground or otherwise form in unoccupied spaces within 300 feet of you and obey your commands until they are destroyed or until the next dawn, when they collapse into inanimate piles of bones and rotting corpses. Once you use this property, you can’t use it again until the next dawn.

While holding the wand, Orcus can summon any kind of Undead, not just skeletons and zombies. These Undead don’t perish at dawn the following day, remaining until Orcus dismisses them.

Sentience. The Wand of Orcus is a sentient Chaotic Evil item with an Intelligence of 16, a Wisdom of 12, and a Charisma of 16. It has hearing and Darkvision out to 120 feet.

The wand communicates telepathically with its wielder and speaks Abyssal and Common.

Personality. The wand’s purpose is to help satisfy Orcus’s desire to slay everything in the multiverse. The wand is cruel, nihilistic, and bereft of humor.

To further Orcus’s goals, the wand feigns devotion to its current user and makes grandiose promises that it has no intention of fulfilling, such as vowing to help its user overthrow Orcus.

Destroying the Wand. Destroying the Wand of Orcus requires that it be taken to the Positive Plane by the ancient hero whose skull surmounts it. For this to happen, the long-lost hero must first be restored to life—no easy task, given the fact that Orcus has imprisoned the hero’s soul and keeps it hidden and well guarded.

Bathing the wand in positive energy (such as that which permeates the Positive Plane) causes it to crack and explode, but unless the above conditions are met, the wand instantly re-forms on Orcus’s layer of the Abyss.', FALSE, ARRAY['artifact', 'attuned', 'wand']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Sword of Kas', 'Weapon (Longsword)', 'Artifact', 'No', 'Varies', 'Kas was a powerful warrior who served Vecna and whose loyalty was rewarded with this sword. As Kas’s power grew, so did his hubris. The sword urged Kas to destroy Vecna and usurp his throne. Legend says Vecna’s destruction came at Kas’s hand, but Vecna also wrought his rebellious lieutenant’s doom, leaving only Kas’s sword behind.

Bloodthirst. The sword thirsts for blood. If the sword doesn’t taste blood on its blade within 1 minute of being drawn from its scabbard, its wielder makes a DC 15 Charisma saving throw. On a successful save, the wielder takes 3d6 Psychic damage. On a failed save, the wielder is dominated by the sword, as if by the Dominate Monster spell, and the sword demands blood. The spell effect ends when the sword’s demand is met.

Magic Weapon. You gain a +3 bonus to attack rolls and damage rolls made with the sword, which scores a Critical Hit on a roll of 19 or 20 on the d20 and deals an extra 2d10 Slashing damage to Undead.

Random Properties. The sword has the following random properties (see “Artifacts”):

Spells. While the sword is on your person, you can cast the following spells (save DC 18) from it:

Once you use the sword to cast a spell, you can’t cast that spell again from it until the next dawn.

Spirit of Kas. While the sword is on your person, you gain the following benefits:

Battle Hunger. You add 1d10 to your Initiative rolls.

Blade of Defense. When you take an action to attack with the sword, you can transfer some or all of its attack bonus to your Armor Class instead. The adjusted bonuses remain in effect until the start of your next turn.

Necrotic Resistance. You have Resistance to Necrotic damage.

Sentience. The Sword of Kas is a sentient Chaotic Evil weapon with an Intelligence of 15, a Wisdom of 13, and a Charisma of 16. It has hearing and Darkvision out to 120 feet.

The weapon communicates telepathically with its wielder and speaks Common.

Personality. The sword’s purpose is to bring ruin to Vecna. Killing Vecna’s worshipers, destroying the lich’s works, and foiling his machinations all help to fulfill this goal.

The Sword of Kas also seeks to destroy anyone corrupted by the Eye and Hand of Vecna.

Destroying the Sword. A creature attuned to both the Eye of Vecna and the Hand of Vecna can use the Wish property of those combined Artifacts to unmake the Sword of Kas, provided the sword is within 30 feet of the spell’s caster. Upon casting Wish, the creature makes a DC 18 Charisma saving throw. On a failed save, nothing happens, and the Wish spell is wasted. On a successful save, the Sword of Kas is destroyed.', FALSE, ARRAY['artifact', 'attuned', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Wave', 'Weapon (Trident)', 'Artifact', 'No', 'Varies', 'Held in the dungeon of White Plume Mountain, Wave is engraved with images of waves, shells, and sea creatures.

You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. When you roll a 20 on the d20 for an attack roll with this weapon, the target takes an extra 21 Necrotic damage.

While holding Wave, you gain the following benefits:

Combat Ready. You have Advantage on Initiative rolls.

Underwater Adaptation. A bubble of air forms around your head while you are underwater, allowing you to breathe normally in that environment.

Aquatic Command. Wave has 3 charges and regains 1d3 expended charges daily at dawn. While you carry it, you can expend 1 charge to cast Dominate Beast (save DC 20) from it on a Beast that has a Swim Speed.

Globe of Invulnerability. While holding Wave, you can cast the level 9 version of Globe of Invulnerability from it. Once used, this property can''t be used again until the next dawn.

Sentience. Wave is a sentient weapon of Neutral alignment, with an Intelligence of 14, a Wisdom of 10, and a Charisma of 18. It has hearing and Darkvision out to 120 feet.

The weapon communicates telepathically with its wielder and speaks Aquan.

Personality. Wave zealously encourages mortals to worship sea gods and has a habit of humming sea chanteys. Conflict arises if the wielder fails to further the weapon’s objectives in the world.

Destroying Wave. Wave can be destroyed only on the island of Thunderforge, where it was forged. The weapon must be melted down by a storm giant or someone imbued with a storm giant''s strength. Destroying Wave angers a god of the sea, who sends powerful agents to attack the island and punish the destroyers.', FALSE, ARRAY['artifact', 'attuned', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Whelm', 'Weapon (Warhammer)', 'Artifact', 'No', 'Varies', 'Whelm is a powerful weapon forged by dwarves and lost in the dungeon of White Plume Mountain.

You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon.

Hurl. Whelm has the Thrown property with a normal range of 60 feet and a long range of 180 feet. When you hit with a ranged attack roll using Whelm, the target takes an extra 1d8 Force damage, or an extra 4d8 Force damage if the target is a Construct, an Elemental, or a Giant. Immediately after hitting or missing, the weapon flies back to your hand.

Shock Wave. You can take a Magic action to strike the ground with Whelm and send a shock wave out from the point of impact. Each creature of your choice on the ground within 60 feet of that point must succeed on a DC 20 Constitution saving throw or have the Stunned condition for 1 minute. A creature repeats the save at the end of each of its turns, ending the effect on itself on a success. Once used, this property can’t be used again until the next dawn.

Supernatural Awareness. While you are holding the weapon, it alerts you to the location of any secret or concealed doors within 30 feet of you. In addition, you can cast Detect Evil and Good or Locate Object from the weapon. Once you cast either spell, you can''t cast it from the weapon again until the next dawn.

Sentience. Whelm is a sentient, Lawful Neutral weapon with an Intelligence of 15, a Wisdom of 12, and a Charisma of 15. It has hearing and Darkvision out to 120 feet.

The weapon communicates telepathically with its wielder and speaks Dwarvish, Giant, and Goblin.

Personality. Whelm has ties to the dwarf clan that created it, called the Dankil or the Mightyhammer clan. It longs to be returned to that clan. Whelm''s purpose is to protect dwarves. Conflict arises if the wielder doesn’t share this goal.

Destroying Whelm. Whelm can be dissolved in the acidic bile of a recently slain ancient black dragon. It can also be melted down in the forges of the Mightyhammer dwarf clan, but only by the rightful leader of that clan.', FALSE, ARRAY['artifact', 'attuned', 'weapon']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
